}

/**
 * Chart Wrapper Component
 * Wrapper for Chart.js with reactive updates and export functionality
 */
import { createEffect, createMemo, createSignal, ErrorBoundary, onCleanup } from 'solid-js'
import ChartContainer from './ChartContainer.module.css'
import ExportChartButton from './ExportChartButton'
import type * as ChartJS from 'chart.js/auto'

export interface ChartWrapperProps {
  type: 'line' | 'bar' | 'doughnut' | 'pie' | 'polarArea' | 'radar' | 'bubble' | 'scatter'
  data: ChartJS.ChartData
  options?: ChartJS.ChartOptions
  height?: number
  variant?: 'tall' | 'medium' | 'short'
  showExport?: boolean
  filename?: string
  onReady?: (chart: ChartJS.Chart) => void
}

export default function ChartWrapper(props: ChartWrapperProps) {
  const [chartInstance, setChartInstance] = createSignal<ChartJS.Chart | undefined>(undefined)

  let canvasRef: HTMLCanvasElement | null = null
  let cancelled = false

  // Watch for theme changes via MutationObserver
  const [isDark, setIsDark] = createSignal(
    document.documentElement.getAttribute('data-theme') === 'dark'
  )

  const themeObserver = new MutationObserver(() => {
    const dark = document.documentElement.getAttribute('data-theme') === 'dark'
    setIsDark(dark)
  })
  themeObserver.observe(document.documentElement, {
    attributes: true,
    attributeFilter: ['data-theme'],
  })

  onCleanup(() => {
    themeObserver.disconnect()
  })

  createEffect(() => {
    const dark = isDark()
    // Read props BEFORE async to track dependencies
    const chartType = props.type
    const chartData = props.data

    if (canvasRef === null) return

    import('chart.js/auto')
      .then(({ default: ChartJS }) => {
        if (cancelled) return

        // Destroy existing chart
        const existingChart = chartInstance()
        if (existingChart) {
          existingChart.destroy()
        }

        // Create new chart
        const ctx = canvasRef?.getContext('2d')
        if (!ctx) return

        const textColor = dark ? '#E5E7EB' : '#374151'
        const gridColor = dark ? 'rgba(255, 255, 255, 0.1)' : 'rgba(0, 0, 0, 0.1)'
        const tooltipBg = dark ? 'rgba(59, 130, 246, 0.2)' : 'rgba(59, 130, 246, 0.1)'
        const tooltipBorder = dark ? 'rgba(255, 255, 255, 0.1)' : 'rgba(0, 0, 0, 0.1)'
        const isPieOrDoughnut =
          chartType === 'doughnut' || chartType === 'pie' || chartType === 'polarArea'
        const options = props.options || {
          responsive: true,
          maintainAspectRatio: false,
          layout: isPieOrDoughnut
            ? {
                padding: {
                  left: 0,
                  right: 0,
                  top: 0,
                  bottom: 0,
                },
              }
            : undefined,
          plugins: {
            legend: {
              position: isPieOrDoughnut ? 'right' : 'top',
              align: isPieOrDoughnut ? 'center' : 'center',
              labels: {
                color: textColor,
                font: { size: 12 },
                padding: isPieOrDoughnut ? 20 : 15,
                usePointStyle: true,
                boxWidth: 12,
                boxHeight: 12,
              },
            },
            tooltip: {
              backgroundColor: tooltipBg,
              titleColor: textColor,
              bodyColor: textColor,
              borderColor: tooltipBorder,
              borderWidth: 1,
              padding: 10,
              cornerRadius: 8,
              displayColors: true,
              usePointStyle: true,
            },
          },
          scales:
            chartType === 'doughnut' || chartType === 'pie' || chartType === 'polarArea'
              ? {}
              : {
                  x: {
                    grid: {
                      color: gridColor,
                      drawBorder: false,
                    },
                    ticks: { color: textColor },
                  },
                  y: {
                    grid: {
                      color: gridColor,
                      drawBorder: false,
                    },
                    ticks: {
                      color: textColor,
                      callback: (value: number) => value.toLocaleString() as any,
                    },
                  },
                },
          animation: {
            duration: 750,
            easing: 'easeInOutQuad' as const,
          },
        }

        const newChart = new ChartJS(ctx, {
          type: chartType,
          data: chartData,
          options: options as any,
        })

        setChartInstance(newChart)
        props.onReady?.(newChart)
      })
      .catch((err: unknown) => {
        console.error('Failed to load Chart.js:', err)
      })
  })

  onCleanup(() => {
    cancelled = true
    const existingChart = chartInstance()
    if (existingChart) {
      existingChart.destroy()
    }
  })

  const heightClass = createMemo(() =>
    props.variant === 'tall'
      ? ChartContainer.chartTall
      : props.variant === 'medium'
        ? ChartContainer.chartMedium
        : props.variant === 'short'
          ? ChartContainer.chartShort
          : ''
  )

  const heightStyle = createMemo(() => (props.height ? `height: ${props.height}px` : undefined))

  return (
    <ErrorBoundary
      fallback={(_err) => (
        <div
          class={ChartContainer.chartContainer}
          classList={{ [heightClass()]: !!heightClass() }}
          style={{
            ...(heightStyle()
              ? {
                  height: `${(heightStyle() as string).replace('height: ', '').replace('px', '')}px`,
                }
              : {}),
            display: 'flex',
            'align-items': 'center',
            'justify-content': 'center',
            color: 'var(--text-secondary, #6b7280)',
            'font-size': '0.875rem',
          }}
        >
          Chart failed to load
        </div>
      )}
    >
      <div
        class={ChartContainer.chartContainer}
        classList={{ [heightClass()]: !!heightClass() }}
        style={heightStyle()}
      >
        {props.showExport && props.filename && (
          <ExportChartButton filename={props.filename} chart={chartInstance()} />
        )}
        <canvas ref={(canvas: HTMLCanvasElement) => (canvasRef = canvas)} />
      </div>
    </ErrorBoundary>
  )
}

import { createSignal, Show } from 'solid-js'
import styles from './ConfirmButton.module.css'
import type { JSX } from 'solid-js'

export interface ConfirmButtonProps {
  onConfirm: () => void | Promise<void>
  label?: JSX.Element
  confirmLabel?: string
  class?: string
}

export default function ConfirmButton(props: ConfirmButtonProps) {
  const [confirming, setConfirming] = createSignal(false)

  const handleConfirm = async () => {
    setConfirming(false)
    await props.onConfirm()
  }

  const handleCancel = () => setConfirming(false)

  return (
    <Show
      when={confirming()}
      fallback={
        <button
          class={props.class || styles.btn}
          onClick={() => setConfirming(true)}
          style={{ display: 'inline-flex', 'align-items': 'center', gap: '6px' }}
        >
          {props.label || 'Delete'}
        </button>
      }
    >
      <span class={styles.wrapper}>
        <span class={styles.confirmLabel}>{props.confirmLabel || 'Confirm?'}</span>
        <button class={styles.btnYes} onClick={handleConfirm}>
          Yes
        </button>
        <button class={styles.btnNo} onClick={handleCancel}>
          No
        </button>
      </span>
    </Show>
  )
}

/**
 * D3HeatmapChart Component
 * D3-based calendar heatmap for daily spending visualization
 * with HTML tooltip and click drill-down
 */
import { createEffect, onCleanup, onMount } from 'solid-js'
import type * as D3 from 'd3'

let d3Module: typeof D3 | null = null

async function getD3() {
  if (!d3Module) d3Module = await import('d3')
  return d3Module
}

interface Props {
  data: Map<string, number>
  year: number
  type: 'income' | 'expense'
  height?: number
  onDayClick?: (dateStr: string, amount: number) => void
}

export default function D3HeatmapChart(props: Props) {
  let containerRef: HTMLDivElement | undefined
  let tooltipEl: HTMLDivElement | undefined

  const formatCurrency = (amount: number): string => {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'EUR' }).format(amount)
  }

  const ensureTooltip = () => {
    if (!tooltipEl || !tooltipEl.parentNode) {
      tooltipEl = document.createElement('div')
      tooltipEl.id = 'heatmap-tooltip'
      tooltipEl.style.cssText =
        'position:fixed;display:none;background:var(--card-bg,#1f2937);color:var(--text,#e5e7eb);padding:6px 10px;border-radius:6px;font-size:12px;pointer-events:none;z-index:9999;box-shadow:0 2px 8px rgba(0,0,0,0.3);border:1px solid var(--border,#374151);white-space:nowrap;'
      document.body.appendChild(tooltipEl)
    }
  }

  const renderHeatmap = async () => {
    const container = containerRef
    if (!container) return

    const width = container.clientWidth || 800
    if (width <= 0) return
    const height = props.height || 160
    const margin = { top: 20, right: 20, bottom: 10, left: 40 }

    const d3 = await getD3()
    d3.select(container).selectAll('svg').remove()

    ensureTooltip()

    const svg = d3
      .select(container)
      .append('svg')
      .attr('width', width)
      .attr('height', height)
      .attr('viewBox', [0, 0, width, height])

    const cellSize = Math.max(10, Math.min(14, (width - margin.left - margin.right) / 53))

    const startDate = d3.timeYear.floor(new Date(props.year, 0, 1))
    const endDate = d3.timeYear.ceil(new Date(props.year, 11, 31))

    const day = d3.timeDays(startDate, endDate)

    const maxVal = d3.max(Array.from(props.data.values())) || 1

    const colorFn =
      props.type === 'expense'
        ? (d3.scaleSequentialPow([0, maxVal], d3.interpolateReds) as any).exponent(0.4)
        : (d3.scaleSequentialPow([0, maxVal], d3.interpolateGreens) as any).exponent(0.4)

    const getValue = (date: Date) => {
      const dateStr = d3.timeFormat('%Y-%m-%d')(date)
      return props.data.get(dateStr) || 0
    }

    const g = svg.append('g').attr('transform', `translate(${margin.left},${margin.top})`)

    // Month labels
    const monthLabels = d3.timeMonths(startDate, endDate)
    g.selectAll('.month-label')
      .data(monthLabels)
      .join('text')
      .attr('class', 'month-label')
      .attr('x', (d: Date) => {
        const firstDayOfMonth = d3.timeMonday.count(d3.timeYear(d), d)
        return firstDayOfMonth * cellSize
      })
      .attr('y', -5)
      .attr('font-size', '10px')
      .attr('fill', 'var(--text-secondary)')
      .text((d: Date) => d3.timeFormat('%b')(d))

    // Day labels
    const dayLabels = ['Mon', '', 'Wed', '', 'Fri', '', '']
    dayLabels.forEach((label, i) => {
      g.append('text')
        .attr('x', -8)
        .attr('y', i * cellSize + cellSize * 0.8)
        .attr('font-size', '9px')
        .attr('fill', 'var(--text-secondary)')
        .attr('text-anchor', 'end')
        .text(label)
    })

    // Cells with mouse events
    g.selectAll('.cell')
      .data(day)
      .join('rect')
      .attr('class', 'cell')
      .attr('width', cellSize - 1.5)
      .attr('height', cellSize - 1.5)
      .attr('x', (d: Date) => d3.timeWeek.count(d3.timeYear(d), d) * cellSize)
      .attr('y', (d: Date) => (d.getDay() === 0 ? 6 * cellSize : (d.getDay() - 1) * cellSize))
      .attr('rx', 2)
      .attr('fill', (d: Date) => {
        const val = getValue(d)
        return val > 0 ? colorFn(val) : '#ffffff'
      })
      .on('mouseover', (event: MouseEvent, d: Date) => {
        if (!tooltipEl) return
        const val = getValue(d)
        const dateLabel = d3.timeFormat('%b %d, %Y')(d)
        const amountLabel = formatCurrency(val)
        tooltipEl.innerHTML =
          val > 0 ? `${dateLabel}: ${amountLabel} ${props.type}` : `${dateLabel}: No ${props.type}`
        tooltipEl.style.display = 'block'
        tooltipEl.style.left = `${event.clientX + 12}px`
        tooltipEl.style.top = `${event.clientY - 40}px`
      })
      .on('mousemove', (event: MouseEvent) => {
        if (!tooltipEl) return
        tooltipEl.style.left = `${event.clientX + 12}px`
        tooltipEl.style.top = `${event.clientY - 40}px`
      })
      .on('mouseout', () => {
        if (!tooltipEl) return
        tooltipEl.style.display = 'none'
      })
      .on('click', (_event: MouseEvent, d: Date) => {
        const dateStr = d3.timeFormat('%Y-%m-%d')(d)
        const val = getValue(d)
        if (props.onDayClick) props.onDayClick(dateStr, val)
      })

    // Legend
    const legendX = margin.left
    const legendY = height - 16
    const legendWidth = 120
    const legendHeight = 10

    svg
      .append('g')
      .attr('transform', `translate(${legendX},${legendY})`)
      .selectAll('.legend-cell')
      .data([0, 0.25, 0.5, 0.75, 1])
      .join('rect')
      .attr('x', (_: number, i: number) => i * (legendWidth / 5))
      .attr('width', legendWidth / 5 - 1)
      .attr('height', legendHeight)
      .attr('fill', (t: number) => colorFn(t * maxVal))

    svg
      .append('g')
      .attr('transform', `translate(${legendX},${legendY})`)
      .append('text')
      .attr('x', legendWidth + 6)
      .attr('y', legendHeight - 1)
      .attr('font-size', '10px')
      .attr('fill', 'var(--text-secondary)')
      .text(d3.format(',.0f')(maxVal))
  }

  // Create tooltip element and render heatmap
  onMount(() => {
    ensureTooltip()
    renderHeatmap()
    const observer = new ResizeObserver(() => {
      renderHeatmap()
    })
    if (containerRef) observer.observe(containerRef)
    onCleanup(() => {
      observer.disconnect()
      if (tooltipEl && tooltipEl.parentNode) {
        tooltipEl.parentNode.removeChild(tooltipEl)
      }
    })
  })

  createEffect(() => {
    if (props.data && props.year && props.type) renderHeatmap()
  })

  return (
    <div
      ref={containerRef}
      style={{ width: '100%', 'overflow-x': 'auto', '-webkit-overflow-scrolling': 'touch' }}
    />
  )
}

/**
 * Budget Alerts Card Component
 * Shows budget alerts for the current period — fetches from API
 */
import { createResource, For } from 'solid-js'
import { apiGet, formatCurrency } from '../../core/api'
import { useAppState } from '../../core/appStore'
import styles from './BudgetAlertsCard.module.css'

interface BudgetAlert {
  categoryName: string
  categoryColor: string
  categoryIcon?: string
  budgetAmount: number
  spent: number
  remaining: number
  percentage: number
  status: 'over' | 'warning' | 'ok'
}

export default function BudgetAlertsCard() {
  const state = useAppState()
  const [alertsResource] = createResource(
    () => state.profileVersion,
    async () => {
      const data = (await apiGet<{ alerts: BudgetAlert[] }>(
        '/api/budgets/alerts?threshold=80'
      )) as any
      return data?.alerts && Array.isArray(data.alerts) ? data.alerts : []
    }
  )
  const loading = () => alertsResource.loading
  const alerts = () => alertsResource() ?? []

  const statusClass = (status: string) => {
    if (status === 'over') return styles.over
    if (status === 'warning') return styles.warning
    return styles.ok
  }

  return (
    <div class={styles.alertsContainer}>
      {loading() ? (
        <div class={styles.emptyMsg}>Loading...</div>
      ) : alerts().length === 0 ? (
        <div class={`${styles.alertItem} ${styles.ok}`}>
          <svg
            width="18"
            height="18"
            fill="none"
            stroke="currentColor"
            stroke-width="2"
            viewBox="0 0 24 24"
          >
            <path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
          <div class={styles.alertContent}>
            <div class={styles.alertTitle}>All budgets within limits</div>
            <div class={styles.alertDescription}>You're on track to meet all your budget goals</div>
          </div>
        </div>
      ) : (
        <For each={alerts().slice(0, 5)}>
          {(alert) => (
            <div class={`${styles.alertItem} ${statusClass(alert.status)}`}>
              <span
                class={styles.alertDot}
                style={{ 'background-color': `#${alert.categoryColor || 'ef4444'}` }}
              />
              <div class={styles.alertContent}>
                <div class={styles.alertTitle}>{alert.categoryName}</div>
                <div class={styles.alertDescription}>
                  {formatCurrency(alert.spent)} of {formatCurrency(alert.budgetAmount)} (
                  {alert.percentage}
                  %)
                </div>
              </div>
              <span class={`${styles.alertAmount} ${alert.status === 'over' ? styles.over : ''}`}>
                {alert.remaining < 0
                  ? `-${formatCurrency(Math.abs(alert.remaining))}`
                  : formatCurrency(alert.remaining)}
              </span>
            </div>
          )}
        </For>
      )}
    </div>
  )
}

/**
 * Period Navigator Component
 * Navigation for month/year selection in dashboard
 */
import { createMemo, createSignal, For, Show } from 'solid-js'
import styles from './PeriodNavigator.module.css'

export interface PeriodNavigatorProps {
  month: () => number
  year: () => number
  onMonthChange: (newMonth: number) => void
  onYearChange: (newYear: number) => void
  onPrev: () => void
  onNext: () => void
  minYear?: number
  maxYear?: number
  /** If provided, show only these exact years instead of a continuous range */
  years?: number[]
}

const MONTHS = [
  'January',
  'February',
  'March',
  'April',
  'May',
  'June',
  'July',
  'August',
  'September',
  'October',
  'November',
  'December',
]

export function PeriodNavigator(props: PeriodNavigatorProps) {
  const [showMonthPicker, setShowMonthPicker] = createSignal(false)
  const [showYearPicker, setShowYearPicker] = createSignal(false)
  const currentYear = createMemo(() => new Date().getFullYear())

  // Reactive: recomputes when parent signals (minYear, maxYear, years) change.
  // Plain const would be computed once on mount and never update — that's why
  // the year range appeared "hardcoded" even after profile switches.
  const years = createMemo(() => {
    if (props.years && props.years.length > 0) return props.years
    const startYear = props.minYear ?? currentYear() - 10
    const endYear = props.maxYear ?? currentYear() + 10
    return Array.from({ length: endYear - startYear + 1 }, (_, i) => startYear + i)
  })

  return (
    <div class={styles.periodNavigator}>
      <button
        class={styles.prevButton}
        onClick={props.onPrev}
        type="button"
        aria-label="Previous period"
      >
        <svg
          width="24"
          height="24"
          fill="none"
          stroke="currentColor"
          stroke-width="2"
          viewBox="0 0 24 24"
        >
          <path stroke-linecap="round" stroke-linejoin="round" d="M15 19l-7-7 7-7" />
        </svg>
      </button>

      <div class={styles.periodDisplay}>
        <div class={styles.dropdownWrapper}>
          <button
            class={styles.monthBtn}
            onClick={() => {
              setShowMonthPicker(!showMonthPicker())
              setShowYearPicker(false)
            }}
            type="button"
          >
            {MONTHS[props.month() - 1]}
            <svg width="10" height="6" viewBox="0 0 10 6" fill="currentColor">
              <path d="M5 6L0 0h10z" />
            </svg>
          </button>
          <Show when={showMonthPicker()}>
            <div class={styles.dropdown}>
              <For each={MONTHS}>
                {(name, i) => (
                  <button
                    class={styles.dropdownItem}
                    classList={{ [styles.selected]: i() + 1 === props.month() }}
                    onClick={() => {
                      props.onMonthChange(i() + 1)
                      setShowMonthPicker(false)
                    }}
                    type="button"
                  >
                    {name}
                  </button>
                )}
              </For>
            </div>
          </Show>
        </div>

        <div class={styles.dropdownWrapper}>
          <button
            class={styles.yearBtn}
            onClick={() => {
              setShowYearPicker(!showYearPicker())
              setShowMonthPicker(false)
            }}
            type="button"
          >
            {props.year()}
            <svg width="10" height="6" viewBox="0 0 10 6" fill="currentColor">
              <path d="M5 6L0 0h10z" />
            </svg>
          </button>
          <Show when={showYearPicker()}>
            <div class={styles.dropdown}>
              <For each={years()}>
                {(y) => (
                  <button
                    class={styles.dropdownItem}
                    classList={{ [styles.selected]: y === props.year() }}
                    onClick={() => {
                      props.onYearChange(y)
                      setShowYearPicker(false)
                    }}
                    type="button"
                  >
                    {y}
                  </button>
                )}
              </For>
            </div>
          </Show>
        </div>
      </div>

      <button
        class={styles.nextButton}
        onClick={props.onNext}
        type="button"
        aria-label="Next period"
      >
        <svg
          width="24"
          height="24"
          fill="none"
          stroke="currentColor"
          stroke-width="2"
          viewBox="0 0 24 24"
        >
          <path stroke-linecap="round" stroke-linejoin="round" d="M9 5l7 7-7 7" />
        </svg>
      </button>

      <Show when={showMonthPicker() || showYearPicker()}>
        <div
          class={styles.overlay}
          onClick={() => {
            setShowMonthPicker(false)
            setShowYearPicker(false)
          }}
        />
      </Show>
    </div>
  )
}

/**
 * Recurring Insights Card Component
 * Shows insights about recurring transactions
 */
import { createMemo, createSignal, For, onMount } from 'solid-js'
import { api } from '../../core/api'
import styles from './RecurringInsightsCard.module.css'

interface RecurringItem {
  id: number
  description: string
  amount: number
  type: string
  frequency: string
  next_date: string | null
  category_name: string | null
  category_color: string | null
}

export default function RecurringInsightsCard() {
  const [items, setItems] = createSignal<RecurringItem[]>([])
  const [loading, setLoading] = createSignal(true)

  onMount(async () => {
    try {
      const data = await api.getRecurring()
      setItems(Array.isArray(data) ? data : [])
    } catch {
      // items remain empty
    } finally {
      setLoading(false)
    }
  })

  const upcoming = createMemo(() =>
    items()
      .filter((i) => i.next_date)
      .sort((a, b) => a.next_date!.localeCompare(b.next_date!))
      .slice(0, 5)
  )

  const formatCurrency = (amount: number) =>
    new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(amount)

  const formatDate = (dateStr: string) =>
    new Date(dateStr).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })

  const freqCounts = createMemo(() => {
    const counts: Record<string, number> = {}
    for (const i of items()) {
      counts[i.frequency] = (counts[i.frequency] || 0) + 1
    }
    return Object.entries(counts).sort((a, b) => b[1] - a[1])
  })

  return (
    <div class={styles.card}>
      {loading() ? (
        <div class={styles.emptyState}>Loading...</div>
      ) : items().length === 0 ? (
        <div class={styles.emptyState}>
          <p style={{ 'margin-bottom': '4px' }}>No recurring transactions found</p>
          <p style={{ 'font-size': '12px', color: 'var(--text-secondary)' }}>
            Set up regular transactions to see insights here
          </p>
        </div>
      ) : (
        <>
          <div class={styles.freqRow}>
            <For each={freqCounts().slice(0, 4)}>
              {([freq, count]) => (
                <span class={styles.freqBadge}>
                  {count} {freq}
                </span>
              )}
            </For>
          </div>
          <div class={styles.insightsList}>
            <For each={upcoming()}>
              {(item) => (
                <div class={styles.insightItem}>
                  <span
                    class={styles.dot}
                    style={{ 'background-color': item.category_color || '#94a3b8' }}
                  />
                  <div class={styles.insightContent}>
                    <div class={styles.insightTitle}>{item.description}</div>
                    <div class={styles.insightDescription}>
                      {formatDate(item.next_date!)} • {item.frequency}
                    </div>
                  </div>
                  <span class={`${styles.amount} ${styles[item.type]}`}>
                    {item.type === 'income' ? '+' : '-'}
                    {formatCurrency(item.amount)}
                  </span>
                </div>
              )}
            </For>
          </div>
        </>
      )}
    </div>
  )
}

/**
 * Savings Rate Card Component
 * Shows current savings rate for the period with goal tracking
 */
import { createSignal } from 'solid-js'
import { formatCurrency } from '../../core/api'
import styles from './SavingsRateCard.module.css'

export interface SavingsRateCardProps {
  savingsRate: number
  monthlySavings: number
  goal: number
  onGoalChange: (value: number) => void
}

export default function SavingsRateCard(props: SavingsRateCardProps) {
  const [goalInput, setGoalInput] = createSignal('')

  const rateColor = () => {
    const rate = props.savingsRate
    if (rate >= 20) return styles.rateGood
    if (rate >= 10) return styles.rateWarning
    return styles.rateBad
  }

  const goalStatus = () => {
    return props.savingsRate >= props.goal ? styles.goalMet : styles.goalUnder
  }

  const handleSetGoal = () => {
    const num = parseFloat(goalInput())
    if (!isNaN(num) && num >= 0 && num <= 100) {
      props.onGoalChange(num)
      setGoalInput('')
    }
  }

  return (
    <div class={styles.card}>
      <div class={styles.savingsRateContainer}>
        <div class={styles.savingsRateValue}>
          <span class={styles.rateLabel}>Period Savings:</span>
          <span
            class={`${styles.rateValue} ${props.monthlySavings >= 0 ? styles.rateGood : styles.rateBad}`}
          >
            {formatCurrency(props.monthlySavings)}
          </span>
        </div>

        <div class={styles.rateDivider} />

        <div class={styles.savingsRateValue}>
          <span class={styles.rateLabel}>Savings Rate:</span>
          <span class={`${styles.rateValue} ${rateColor()}`}>{props.savingsRate.toFixed(1)}%</span>
        </div>

        <div class={styles.goalSection}>
          <div class={styles.goalInfo}>
            <span class={styles.rateLabel}>Goal: {props.goal}%</span>
            <span class={`${styles.goalStatus} ${goalStatus()}`}>
              {props.savingsRate >= props.goal
                ? 'Goal met'
                : `${(props.goal - props.savingsRate).toFixed(1)}% to go`}
            </span>
          </div>
          <div class={styles.goalBar}>
            <div
              class={styles.goalBarFill}
              style={{
                width: `${props.goal > 0 ? Math.min((props.savingsRate / props.goal) * 100, 100) : 0}%`,
              }}
            />
          </div>
          <div class={styles.goalInput}>
            <input
              type="number"
              class={styles.goalInputField}
              placeholder="New goal %"
              min="0"
              max="100"
              value={goalInput()}
              onInput={(e) => setGoalInput(e.currentTarget.value)}
            />
            <button class={styles.goalButton} onClick={handleSetGoal}>
              Set Goal
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

/**
 * Dashboard Settings Component - Configure widget visibility and order
 */

import { createSignal, For, onMount } from 'solid-js'
import styles from './DashboardSettings.module.css'
import type { Component } from 'solid-js'

const ALL_WIDGET_IDS = [
  'metrics',
  'category-chart',
  'recent-transactions',
  'upcoming-bills',
  'savings-rate',
  'budget-alerts',
  'recurring-insights',
  'income-vs-expenses',
]

const DEFAULT_WIDGET_ORDER = [
  'metrics',
  'category-chart',
  'recent-transactions',
  'upcoming-bills',
  'savings-rate',
  'budget-alerts',
  'recurring-insights',
  'income-vs-expenses',
]

export interface DashboardSettingsProps {
  onSave?: () => void
}

export const DashboardSettings: Component<DashboardSettingsProps> = (props) => {
  const [selectedWidget, setSelectedWidget] = createSignal<string>(ALL_WIDGET_IDS.join(','))
  const [widgetOrder, setWidgetOrder] = createSignal<string[]>([...DEFAULT_WIDGET_ORDER])
  const [dragIdx, setDragIdx] = createSignal<number | null>(null)

  const widgets = [
    {
      id: 'metrics',
      name: 'Metrics Cards',
      icon: (
        <svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
          <path d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
        </svg>
      ),
    },
    {
      id: 'category-chart',
      name: 'Spending by Category',
      icon: (
        <svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
          <path d="M13 17V9m-4 8v-4m8 4v-2M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
        </svg>
      ),
    },
    {
      id: 'recent-transactions',
      name: 'Recent Transactions',
      icon: (
        <svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
          <path d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
        </svg>
      ),
    },
    {
      id: 'upcoming-bills',
      name: 'Upcoming Bills',
      icon: (
        <svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
          <path d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
        </svg>
      ),
    },
    {
      id: 'savings-rate',
      name: 'Savings Rate',
      icon: (
        <svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
          <path d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
        </svg>
      ),
    },
    {
      id: 'budget-alerts',
      name: 'Budget Alerts',
      icon: (
        <svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
          <path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-2.5L13.732 4c-.77-.833-1.964-.833-2.732 0L3.34 16.5c-.77.833.192 2.5 1.732 2.5z" />
        </svg>
      ),
    },
    {
      id: 'recurring-insights',
      name: 'Recurring Insights',
      icon: (
        <svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
          <path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
        </svg>
      ),
    },
    {
      id: 'income-vs-expenses',
      name: 'Income vs Expenses',
      icon: (
        <svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
          <path d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
        </svg>
      ),
    },
  ]

  // Load saved preferences
  onMount(() => {
    const saved = localStorage.getItem('dashboard_widgets')
    if (saved !== null) {
      try {
        const parsed = JSON.parse(saved)
        if (parsed.visibleWidgets && Array.isArray(parsed.visibleWidgets)) {
          setSelectedWidget(parsed.visibleWidgets.join(','))
        }
        if (parsed.widgetOrder && Array.isArray(parsed.widgetOrder) && parsed.widgetOrder.length > 0) {
          setWidgetOrder(parsed.widgetOrder)
        }
      } catch (e) {
        console.error('Failed to load dashboard settings:', e)
      }
    }
  })

  const toggleWidget = (widgetId: string) => {
    const current = selectedWidget()
    const ids = current ? current.split(',').filter(Boolean) : []
    if (ids.includes(widgetId)) {
      setSelectedWidget(ids.filter((id) => id !== widgetId).join(','))
    } else {
      setSelectedWidget([...ids, widgetId].join(','))
    }
  }

  const isVisible = (widgetId: string) => {
    const current = selectedWidget()
    return current ? current.split(',').includes(widgetId) : false
  }

  // Drag-and-drop handlers
  const handleDragStart = (e: DragEvent, idx: number) => {
    setDragIdx(idx)
    const el = e.currentTarget as HTMLElement
    el.classList.add(styles.dragging)
    e.dataTransfer!.effectAllowed = 'move'
    e.dataTransfer!.setData('text/plain', String(idx))
  }

  const handleDragEnd = (e: DragEvent) => {
    setDragIdx(null)
    const el = e.currentTarget as HTMLElement
    el.classList.remove(styles.dragging)
  }

  const handleDragOver = (e: DragEvent, _idx: number) => {
    e.preventDefault()
    e.dataTransfer!.dropEffect = 'move'
  }

  const handleDrop = (e: DragEvent, toIdx: number) => {
    e.preventDefault()
    const fromIdx = parseInt(e.dataTransfer!.getData('text/plain'), 10)
    if (fromIdx === toIdx || isNaN(fromIdx)) return

    const order = [...widgetOrder()]
    const [removed] = order.splice(fromIdx, 1)
    order.splice(toIdx, 0, removed)
    setWidgetOrder(order)
  }

  // Sort widgets display by widgetOrder (with fallback for corrupted data)
  const orderedWidgets = () => {
    const order = widgetOrder()
    if (!order || order.length === 0) {
      return widgets
    }
    const widgetMap = new Map(widgets.map((w) => [w.id, w]))
    const result = order.map((id) => widgetMap.get(id)).filter(Boolean) as typeof widgets
    return result.length > 0 ? result : widgets
  }

  const saveSettings = () => {
    const current = selectedWidget()
    const ids = current ? current.split(',').filter(Boolean) : []
    localStorage.setItem(
      'dashboard_widgets',
      JSON.stringify({
        visibleWidgets: ids,
        widgetOrder: widgetOrder(),
      })
    )
    props.onSave?.()
  }

  const resetSettings = () => {
    setSelectedWidget(ALL_WIDGET_IDS.join(','))
    setWidgetOrder([...DEFAULT_WIDGET_ORDER])
  }

  return (
    <div class={styles.dashboardSettings}>
      <div class={styles.settingsHeader}>
        <h3>Dashboard Views</h3>
        <button class={`${styles.btnSm} ${styles.btnSecondary}`} onClick={resetSettings}>
          Reset Default
        </button>
      </div>
      <p class={styles.dragHint}>Drag rows to reorder widgets on your dashboard</p>
      <div class={styles.settingsList}>
        <For each={orderedWidgets()}>
          {(widget, idx) => (
            <div
              class={`${styles.settingItem} ${styles.draggable}`}
              classList={{ [styles.dragOver]: dragIdx() !== null && dragIdx() !== idx() }}
              draggable="true"
              onDragStart={(e) => { handleDragStart(e, idx()) }}
              onDragEnd={handleDragEnd}
              onDragOver={(e) => { handleDragOver(e, idx()) }}
              onDrop={(e) => { handleDrop(e, idx()) }}
            >
              <span class={styles.dragHandle} title="Drag to reorder">
                <svg width="16" height="16" fill="currentColor" viewBox="0 0 24 24">
                  <path d="M8 6h2v2H8V6zm6 0h2v2h-2V6zM8 11h2v2H8v-2zm6 0h2v2h-2v-2zm-6 5h2v2H8v-2zm6 0h2v2h-2v-2z" />
                </svg>
              </span>
              <button
                class={styles.widgetToggle}
                classList={{ [styles.active]: isVisible(widget.id) }}
                onClick={() => { toggleWidget(widget.id) }}
              >
                <span class={styles.widgetIcon}>{widget.icon}</span>
                <span class={styles.widgetName}>{widget.name}</span>
                <span class={styles.widgetStatus}>
                  {isVisible(widget.id) ? 'Visible' : 'Hidden'}
                </span>
              </button>
            </div>
          )}
        </For>
      </div>
      <div class={styles.settingsFooter}>
        <button class={`${styles.btnSm} ${styles.btnPrimary}`} onClick={saveSettings}>
          Save & Close
        </button>
      </div>
    </div>
  )
}

import { createSignal, ErrorBoundary as SolidErrorBoundary, onCleanup, onMount } from 'solid-js'
import type { Component, JSX } from 'solid-js'

interface Props {
  children: JSX.Element
}

function isBenignError(msg: string): boolean {
  if (!msg) return false
  return /ResizeObserver loop/i.test(msg)
}

export const ErrorBoundary: Component<Props> = (props) => {
  const [fatalError, setFatalError] = createSignal<Error | null>(null)
  const [errorLog, setErrorLog] = createSignal<string[]>([])

  function addToLog(msg: string) {
    setErrorLog((prev) => [...prev.slice(-19), msg])
  }

  onMount(() => {
    const handleGlobalError = (event: ErrorEvent) => {
      const msg = event.message || (event.error ? String(event.error) : '')
      if (isBenignError(msg)) return
      const err = event.error || new Error(msg)
      addToLog(`[${new Date().toISOString()}] ${err.message || String(err)}`)
      if (!fatalError()) {
        setFatalError(err)
      }
    }

    const handleUnhandledRejection = (event: PromiseRejectionEvent) => {
      const err =
        event.reason instanceof Error ? event.reason : new Error(String(event.reason))
      if (isBenignError(err.message)) return
      addToLog(`[${new Date().toISOString()}] Unhandled: ${err.message}`)
      if (!fatalError()) {
        setFatalError(err)
      }
    }

    window.addEventListener('error', handleGlobalError)
    window.addEventListener('unhandledrejection', handleUnhandledRejection)

    onCleanup(() => {
      window.removeEventListener('error', handleGlobalError)
      window.removeEventListener('unhandledrejection', handleUnhandledRejection)
    })
  })

  const handleReload = () => { window.location.reload() }
  const handleClearLocalStorage = () => {
    localStorage.clear()
    window.location.reload()
  }
  const handleClearIndexedDB = async () => {
    if (window.indexedDB?.databases) {
      try {
        const dbs = await window.indexedDB.databases()
        dbs.forEach((db: any) => {
          if (db.name) window.indexedDB.deleteDatabase(db.name)
        })
      } catch {
        /* ignore */
      }
    }
    window.location.reload()
  }
  const handleDismiss = () => setFatalError(null)

  return (
    <SolidErrorBoundary
      fallback={(err, _reset) => {
        addToLog(`[${new Date().toISOString()}] Render error: ${err.toString()}`)
        const displayError = fatalError() || err
        const logs = errorLog()
        return (
          <CrashModal
            error={displayError}
            logs={logs}
            onReload={handleReload}
            onClearLocalStorage={handleClearLocalStorage}
            onClearIndexedDB={handleClearIndexedDB}
            onDismiss={handleDismiss}
          />
        )
      }}
    >
      {fatalError() ? (
        <CrashModal
          error={fatalError()!}
          logs={errorLog()}
          onReload={handleReload}
          onClearLocalStorage={handleClearLocalStorage}
          onClearIndexedDB={handleClearIndexedDB}
          onDismiss={handleDismiss}
        />
      ) : (
        props.children
      )}
    </SolidErrorBoundary>
  )
}

function CrashModal(props: {
  error: Error
  logs: string[]
  onReload: () => void
  onClearLocalStorage: () => void
  onClearIndexedDB: () => void
  onDismiss: () => void
}) {
  return (
    <div
      style={{
        position: 'fixed',
        inset: 0,
        display: 'flex',
        'align-items': 'center',
        'justify-content': 'center',
        'background-color': 'rgba(0, 0, 0, 0.5)',
        'z-index': 99999,
      }}
    >
      <div
        style={{
          background: 'var(--bg-card, #ffffff)',
          color: 'var(--text-primary, #000000)',
          padding: '2rem',
          'border-radius': '8px',
          'max-width': '550px',
          width: '95%',
          'max-height': '90vh',
          'overflow-y': 'auto',
          'box-shadow': '0 4px 6px rgba(0, 0, 0, 0.1)',
        }}
      >
        <h2 style={{ 'margin-top': 0, color: '#ef4444' }}>App Crashed</h2>
        <p style={{ 'margin-bottom': '1rem' }}>
          An unexpected error occurred. You can try reloading or clearing stored data.
        </p>

        <div
          style={{
            background: 'var(--bg-body, #1f2937)',
            color: '#f87171',
            padding: '1rem',
            'border-radius': '4px',
            'font-family': 'monospace',
            'font-size': '0.8rem',
            'overflow-x': 'auto',
            'margin-bottom': '1rem',
            'max-height': '200px',
            'overflow-y': 'auto',
            'white-space': 'pre-wrap',
            'word-break': 'break-all',
          }}
        >
          <strong>Error:</strong> {props.error.toString()}
          {props.logs.length > 0 && (
            <>
              <div style={{ margin: '8px 0', 'border-top': '1px solid #4b5563' }} />
              <strong>Log:</strong>
              {'\n'}
              {props.logs.join('\n')}
            </>
          )}
        </div>

        <p style={{ 'font-size': '0.85rem', color: 'var(--text-secondary, #6b7280)', 'margin-bottom': '1rem' }}>
          Version: {typeof __APP_VERSION__ !== 'undefined' ? __APP_VERSION__ : 'unknown'}
          {' — '}
          <a
            href="https://github.com/Komediruzecki/finance-manager/issues/new"
            target="_blank"
            rel="noopener noreferrer"
            style={{ color: '#3b82f6', 'text-decoration': 'underline' }}
          >
            Report on GitHub
          </a>
        </p>

        <div style={{ display: 'flex', 'flex-direction': 'column', gap: '0.5rem' }}>
          <button
            onClick={props.onReload}
            style={{
              padding: '0.5rem 1rem',
              background: '#3b82f6',
              color: 'white',
              border: 'none',
              'border-radius': '4px',
              cursor: 'pointer',
            }}
          >
            Reload App
          </button>
          <button
            onClick={props.onClearLocalStorage}
            style={{
              padding: '0.5rem 1rem',
              background: 'transparent',
              color: '#ef4444',
              border: '1px solid #ef4444',
              'border-radius': '4px',
              cursor: 'pointer',
            }}
          >
            Clear Local Storage & Reload
          </button>
          <button
            onClick={props.onClearIndexedDB}
            style={{
              padding: '0.5rem 1rem',
              background: 'transparent',
              color: '#ef4444',
              border: '1px solid #ef4444',
              'border-radius': '4px',
              cursor: 'pointer',
            }}
          >
            Clear IndexedDB & Reload
          </button>
          <button
            onClick={props.onDismiss}
            style={{
              padding: '0.5rem 1rem',
              background: 'transparent',
              color: 'var(--text-secondary, #6b7280)',
              border: '1px solid var(--border, #e5e7eb)',
              'border-radius': '4px',
              cursor: 'pointer',
            }}
          >
            Dismiss & Continue
          </button>
        </div>
      </div>
    </div>
  )
}

/**
 * Export Chart Button Component
 * Button with icons to export chart as PNG or SVG
 */
import { exportChartAsPNG, exportChartAsSVG } from '../utils/chartExport'
import { loadChartExportSettings, resolveBackgroundColor } from '../utils/chartExportSettings'
import styles from './ExportChartButton.module.css'

export interface ExportChartButtonProps {
  chart: any
  filename: string
  variant?: 'icon' | 'inline'
}

export default function ExportChartButton(props: ExportChartButtonProps) {
  const handleExportPNG = () => {
    if (!props.chart) return
    const settings = loadChartExportSettings()
    const bg = resolveBackgroundColor(settings.background)
    exportChartAsPNG(props.chart, props.filename, bg)
  }

  const handleExportSVG = () => {
    if (!props.chart) return
    const settings = loadChartExportSettings()
    const bg = resolveBackgroundColor(settings.background)
    exportChartAsSVG(props.chart, props.filename, bg)
  }

  if (props.variant === 'inline') {
    return (
      <div class={styles.inlineWrapper}>
        <button class={styles.exportBtn} onclick={handleExportPNG} title="Export as PNG">
          <svg width="14" height="14" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path
              stroke-linecap="round"
              stroke-linejoin="round"
              stroke-width={2}
              d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"
            />
          </svg>
        </button>
        <button class={styles.exportBtn} onclick={handleExportSVG} title="Export as SVG">
          <svg width="14" height="14" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path
              stroke-linecap="round"
              stroke-linejoin="round"
              stroke-width={2}
              d="M7 21a4 4 0 01-4-4V5a2 2 0 012-2h4a2 2 0 012 2v12a4 4 0 01-4 4zm0 0h12a2 2 0 002-2v-4a2 2 0 00-2-2h-2.343M11 7.343l1.657-1.657a2 2 0 012.828 0l2.829 2.829a2 2 0 010 2.828l-8.486 8.485M7 17h.01"
            />
          </svg>
        </button>
      </div>
    )
  }

  return (
    <button class={styles.exportBtn} onclick={handleExportPNG}>
      <svg width="16" height="16" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path
          stroke-linecap="round"
          stroke-linejoin="round"
          stroke-width={2}
          d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"
        />
      </svg>
      <span>Export</span>
    </button>
  )
}

/**
 * FilterBar Component
 * Single-line filter bar with categories, tags, search, date presets, reconcile
 */
import { createMemo, createSignal, For } from 'solid-js'
import styles from './FilterBar.module.css'

const MONTH_NAMES = [
  'January',
  'February',
  'March',
  'April',
  'May',
  'June',
  'July',
  'August',
  'September',
  'October',
  'November',
  'December',
]

interface FilterOption {
  id: number
  name: string
  color: string
  type?: string
}

interface FilterState {
  categories?: FilterOption[]
  tags?: FilterOption[]
  selectedCategories: number[] | undefined
  selectedTags: number[] | undefined
  dateRange: { from: string; to: string }
  selectedPreset: string
}

interface FilterBarProps {
  categories: FilterOption[]
  tags: FilterOption[]
  selectedCategories: number[] | undefined
  selectedTags: number[] | undefined
  dateRange: { from: string; to: string }
  selectedPreset: string
  showReconciled?: boolean
  reconciledCount?: number
  onToggleReconciled?: () => void
  onCategoryChange?: (ids: number[]) => void
  searchTerm?: string
  onSearchChange?: (term: string) => void
  filterType?: string
  onFilterTypeChange?: (type: string) => void
  onChange: (filters: FilterState) => void
}

export default function FilterBar(props: FilterBarProps) {
  const [isTagDropdownOpen, setIsTagDropdownOpen] = createSignal(false)
  const [isCatDropdownOpen, setIsCatDropdownOpen] = createSignal(false)

  const selectedTags = () => props.selectedTags || []
  const selectedCats = () => props.selectedCategories || []

  const closeAllDropdowns = () => {
    setIsTagDropdownOpen(false)
    setIsCatDropdownOpen(false)
  }

  const toggleTagDropdown = () => {
    setIsTagDropdownOpen(!isTagDropdownOpen())
    setIsCatDropdownOpen(false)
  }

  const toggleCatDropdown = () => {
    setIsCatDropdownOpen(!isCatDropdownOpen())
    setIsTagDropdownOpen(false)
  }

  const toggleTag = (tagId: number) => {
    const idx = selectedTags().indexOf(tagId)
    if (idx >= 0) {
      props.onChange({
        selectedCategories: props.selectedCategories,
        selectedTags: selectedTags().filter((id) => id !== tagId),
        dateRange: props.dateRange,
        selectedPreset: props.selectedPreset,
      })
    } else {
      props.onChange({
        selectedCategories: props.selectedCategories,
        selectedTags: [...selectedTags(), tagId],
        dateRange: props.dateRange,
        selectedPreset: props.selectedPreset,
      })
    }
  }

  const toggleCat = (catId: number) => {
    const idx = selectedCats().indexOf(catId)
    if (idx >= 0) {
      if (props.onCategoryChange)
        props.onCategoryChange(selectedCats().filter((id) => id !== catId))
    } else {
      if (props.onCategoryChange) props.onCategoryChange([...selectedCats(), catId])
    }
  }

  const clearFilters = () => {
    if (props.onCategoryChange) props.onCategoryChange([])
    if (props.onSearchChange) props.onSearchChange('')
    if (props.onFilterTypeChange) props.onFilterTypeChange('all')
    props.onChange({
      selectedCategories: [],
      selectedTags: [],
      dateRange: { from: '', to: '' },
      selectedPreset: 'all',
    })
  }

  const catLabel = () => {
    if (selectedCats().length === 0) return 'All Categories'
    return `${selectedCats().length} Selected`
  }

  const tagLabel = () => {
    if (selectedTags().length === 0) return 'All Tags'
    return `${selectedTags().length} Selected`
  }

  const now = createMemo(() => new Date())
  const currentYear = createMemo(() => now().getFullYear())
  const currentMonth = createMemo(() => now().getMonth())

  const derivedMonth = createMemo(() => {
    const dr = props.dateRange
    if (dr && dr.from) {
      const d = new Date(dr.from)
      if (!isNaN(d.getTime())) return d.getMonth()
    }
    return currentMonth()
  })

  const derivedYear = createMemo(() => {
    const dr = props.dateRange
    if (dr && dr.from) {
      const d = new Date(dr.from)
      if (!isNaN(d.getTime())) return d.getFullYear()
    }
    return currentYear()
  })

  const years = createMemo(() => {
    const range: number[] = []
    for (let y = currentYear() - 5; y <= currentYear() + 5; y++) range.push(y)
    return range
  })

  const handleMonthYearChange = (month: number, year: number) => {
    const firstDay = new Date(year, month, 1)
    const lastDay = new Date(year, month + 1, 0)
    const fmt = (d: Date) => d.toISOString().slice(0, 10)
    props.onChange({
      selectedCategories: props.selectedCategories,
      selectedTags: props.selectedTags,
      dateRange: { from: fmt(firstDay), to: fmt(lastDay) },
      selectedPreset: 'custom',
    })
  }

  const handlePresetClick = (preset: string) => {
    props.onChange({
      selectedCategories: props.selectedCategories,
      selectedTags: props.selectedTags,
      dateRange: props.dateRange,
      selectedPreset: preset,
    })
  }

  const handleDateChange = (field: 'from' | 'to') => (e: Event) => {
    const target = e.target as HTMLInputElement
    props.onChange({
      selectedCategories: props.selectedCategories,
      selectedTags: props.selectedTags,
      dateRange: { ...props.dateRange, [field]: target.value },
      selectedPreset: 'custom',
    })
  }

  return (
    <div class={styles.filterBar} data-test-id="filter-bar">
      <div class={styles.filterRow}>
        {/* Category dropdown */}
        <div class={styles.filterDropdown}>
          <button class={styles.filterBtn} onClick={toggleCatDropdown}>
            <span class={styles.filterLabel}>{catLabel()}</span>
            <svg
              width="10"
              height="10"
              fill="none"
              stroke="currentColor"
              stroke-width="2"
              viewBox="0 0 24 24"
            >
              <path d="M19 9l-7 7-7-7" />
            </svg>
          </button>
          {isCatDropdownOpen() && (
            <div class={styles.dropdownContent}>
              <div class={styles.optionList}>
                <label class={styles.checkboxLabel}>
                  <input
                    type="checkbox"
                    checked={selectedCats().length === 0}
                    onChange={clearFilters}
                  />
                  All Categories
                </label>
                <For each={props.categories}>
                  {(cat) => (
                    <label class={styles.checkboxLabel}>
                      <input
                        type="checkbox"
                        checked={selectedCats().includes(cat.id)}
                        onChange={() => {
                          toggleCat(cat.id)
                        }}
                      />
                      <span
                        class={styles.catDot}
                        style={{ background: `#${cat.color || '94a3b8'}` }}
                      />
                      <span>{cat.name}</span>
                    </label>
                  )}
                </For>
              </div>
            </div>
          )}
        </div>

        {/* Tag dropdown */}
        <div class={styles.filterDropdown}>
          <button class={styles.filterBtn} onClick={toggleTagDropdown}>
            <span class={styles.filterLabel}>{tagLabel()}</span>
            <svg
              width="10"
              height="10"
              fill="none"
              stroke="currentColor"
              stroke-width="2"
              viewBox="0 0 24 24"
            >
              <path d="M19 9l-7 7-7-7" />
            </svg>
          </button>
          {isTagDropdownOpen() && (
            <div class={styles.dropdownContent}>
              <div class={styles.optionList}>
                <label class={styles.checkboxLabel}>
                  <input
                    type="checkbox"
                    checked={selectedTags().length === 0}
                    onChange={clearFilters}
                  />
                  All Tags
                </label>
                <For each={props.tags}>
                  {(tag) => (
                    <label class={styles.checkboxLabel}>
                      <input
                        type="checkbox"
                        checked={selectedTags().includes(tag.id)}
                        onChange={() => {
                          toggleTag(tag.id)
                        }}
                      />
                      <span class={styles.tagDot} style={{ background: `#${tag.color}` }} />
                      <span>{tag.name}</span>
                    </label>
                  )}
                </For>
              </div>
            </div>
          )}
        </div>

        {/* Type filter */}
        {props.onFilterTypeChange && (
          <div class={styles.typeBtns}>
            <For each={['all', 'income', 'expense', 'transfer']}>
              {(t) => (
                <button
                  class={`${styles.typeBtn} ${(props.filterType || 'all') === t ? styles.typeBtnActive : ''}`}
                  onClick={() => props.onFilterTypeChange?.(t)}
                >
                  {t === 'all' ? 'All' : t.charAt(0).toUpperCase() + t.slice(1)}
                </button>
              )}
            </For>
          </div>
        )}

        {/* Search */}
        {props.onSearchChange !== undefined && (
          <input
            type="text"
            class={styles.searchInput}
            placeholder="Search..."
            value={props.searchTerm || ''}
            onInput={(e) => props.onSearchChange?.((e.target as HTMLInputElement).value)}
          />
        )}

        {/* Date presets */}
        <div class={styles.dateFilters}>
          <For each={['all', 'month', 'lastMonth', 'year']}>
            {(p) => (
              <button
                class={`${styles.presetBtn} ${props.selectedPreset === p ? styles.presetBtnActive : ''}`}
                onClick={() => {
                  handlePresetClick(p)
                }}
              >
                {p === 'all'
                  ? 'All Time'
                  : p === 'month'
                    ? 'This Month'
                    : p === 'lastMonth'
                      ? 'Last Month'
                      : 'This Year'}
              </button>
            )}
          </For>
        </div>

        {/* Month/Year nav */}
        <div class={styles.monthYearNav}>
          <select
            class={styles.monthYearSelect}
            value={derivedMonth()}
            onChange={(e) => {
              handleMonthYearChange(parseInt(e.currentTarget.value), derivedYear())
            }}
          >
            <For each={MONTH_NAMES}>{(name, i) => <option value={i()}>{name}</option>}</For>
          </select>
          <select
            class={styles.monthYearSelect}
            value={derivedYear()}
            onChange={(e) => {
              handleMonthYearChange(derivedMonth(), parseInt(e.currentTarget.value))
            }}
          >
            <For each={years()}>{(y) => <option value={y}>{y}</option>}</For>
          </select>
        </div>

        {/* Actions */}
        <div class={styles.filterActions}>
          {props.onToggleReconciled !== undefined && (
            <button
              class={`${styles.reconcileToggle} ${props.showReconciled ? '' : styles.reconcileToggleActive}`}
              onClick={props.onToggleReconciled}
              title={props.showReconciled ? 'Hide reconciled' : 'Show reconciled'}
            >
              <svg
                width="12"
                height="12"
                fill="none"
                stroke="currentColor"
                stroke-width="2"
                viewBox="0 0 24 24"
              >
                <path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              {(props.reconciledCount ?? 0) > 0 && (
                <span class={styles.reconcileBadge}>{props.reconciledCount}</span>
              )}
            </button>
          )}
          <button class={styles.clearBtn} onClick={clearFilters}>
            <svg
              width="12"
              height="12"
              fill="none"
              stroke="currentColor"
              stroke-width="2"
              viewBox="0 0 24 24"
            >
              <path d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>
      </div>

      {/* Click-outside backdrop for dropdowns */}
      {(isCatDropdownOpen() || isTagDropdownOpen()) && (
        <div class={styles.dropdownBackdrop} onClick={closeAllDropdowns} />
      )}

      {/* Custom date inputs */}
      {props.selectedPreset === 'custom' && (
        <div class={styles.customDates}>
          <div class={styles.dateInput}>
            <label class={styles.inputLabel}>From</label>
            <input
              type="date"
              class={styles.input}
              value={props.dateRange.from}
              onInput={handleDateChange('from')}
            />
          </div>
          <div class={styles.dateInput}>
            <label class={styles.inputLabel}>To</label>
            <input
              type="date"
              class={styles.input}
              value={props.dateRange.to}
              onInput={handleDateChange('to')}
            />
          </div>
        </div>
      )}
    </div>
  )
}

/**
 * LoanAmortizationTable Component
 * Displays detailed amortization schedule for a loan
 */
import { createEffect, createSignal, For, on, onMount } from 'solid-js'
import Chart from '../components/Chart'
import { api as _api, apiPost, formatCurrency, showToast } from '../core/api'
import { theme } from '../core/theme'
import styles from '../features/LoansPage.module.css'

interface AmortizationRow {
  month: number
  date: string
  payment: number
  principal: number
  interest: number
  balance: number
  rate: number
  prepayment?: number
  note?: string
}

interface AmortizationResult {
  summary: {
    totalPaid: number
    totalInterest: number
    payoffDate?: string
    interestSaved?: number
    monthsSaved?: number
    avgMonthlyPayment?: number
  }
  schedule: AmortizationRow[]
}

interface Loan {
  id: number
  name: string
  principal: number
  interest_rate: number
  term_months: number
  start_date: string
  prepayments?: any[]
  rate_periods?: any[]
}

interface Props {
  loanId: number
  loan: Loan
  showDetailed?: boolean
  recalculateKey?: number
}

export default function LoanAmortizationTable(props: Props) {
  const [loading, setLoading] = createSignal(false)
  const [result, setResult] = createSignal<AmortizationResult | null>(null)
  const [showDetailed, setShowDetailed] = createSignal(props.showDetailed || false)
  const chartColors = () => theme.getChartColors()

  const loadAmortizationData = async () => {
    setLoading(true)
    try {
      const res = await apiPost<AmortizationResult>(`/api/loans/${props.loanId}/calculate`, {})
      setResult(res)
    } catch (_err) {
      showToast('Failed to load amortization data', 'error')
    } finally {
      setLoading(false)
    }
  }

  const toggleDetailed = () => {
    setShowDetailed(!showDetailed())
  }

  // Load amortization data on mount and when loan changes
  onMount(() => {
    loadAmortizationData()
  })

  // Recalculate when prepayments change or loan changes
  createEffect(
    on(
      () => [props.recalculateKey, props.loanId],
      () => {
        loadAmortizationData()
      }
    )
  )

  return (
    <div class={styles.loanAmortizationSection}>
      {(() => {
        const schedule = result()?.schedule || []
        if (schedule.length === 0) {
          return <p class={styles.emptyState}>No amortization data available</p>
        }
        const s = result()?.summary
        return (
          <>
            {/* Action Buttons */}
            <div style="display: flex; gap: 8px; margin-bottom: 16px;">
              <button
                class={`${styles.btnSecondary} ${styles.btnSm}`}
                onclick={loadAmortizationData}
                disabled={loading()}
                title="Recalculate with current loan data"
              >
                Recalculate
              </button>
              <button class={`${styles.btnPrimary} ${styles.btnSm}`} onclick={toggleDetailed}>
                {showDetailed() ? 'Hide Amortization' : 'View Amortization'}
              </button>
            </div>

            {/* Summary Cards */}
            <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 16px; margin-bottom: 16px;">
              <div class={styles.summaryCard}>
                <div class={styles.summaryLabel}>Total Paid</div>
                <div class={styles.summaryValue}>{formatCurrency(s?.totalPaid || 0)}</div>
              </div>
              <div class={styles.summaryCard}>
                <div class={styles.summaryLabel}>Total Interest</div>
                <div class={styles.summaryValue} style={{ color: 'var(--expense)' }}>
                  {formatCurrency(s?.totalInterest || 0)}
                </div>
              </div>
              <div class={styles.summaryCard}>
                <div class={styles.summaryLabel}>Payoff Date</div>
                <div class={styles.summaryValue} style={{ 'font-weight': 600 }}>
                  {s?.payoffDate || '-'}
                </div>
              </div>
              <div class={styles.summaryCard}>
                <div class={styles.summaryLabel}>Interest Saved</div>
                <div class={styles.summaryValue} style={{ color: 'var(--success)' }}>
                  {formatCurrency(s?.interestSaved || 0)}
                </div>
              </div>
            </div>

            {/* Prepayments Section */}
            {props.loan.prepayments && props.loan.prepayments.length > 0 && (
              <div style="margin-bottom: 16px;">
                <h4 style="margin: 0 0 8px 0; font-size: 14px; font-weight: 600;">Prepayments</h4>
                <div style="display: flex; flex-direction: column; gap: 8px;">
                  <For each={props.loan.prepayments}>
                    {(p) => {
                      const loanStart = new Date(props.loan.start_date)
                      const prepayDate = new Date(loanStart)
                      prepayDate.setMonth(prepayDate.getMonth() + p.month - 1)
                      return (
                        <div style="display: flex; align-items: center; gap: 8px; padding: 8px; background: var(--bg); border-radius: var(--radius);">
                          <span style={{ 'font-size': '12px', color: 'var(--text-secondary)' }}>
                            {formatDate(prepayDate.toISOString().split('T')[0])}
                          </span>
                          <span style={{ 'font-weight': 600, color: 'var(--success)' }}>
                            +{formatCurrency(p.amount)}
                          </span>
                          {p.note && (
                            <span
                              style={{
                                'font-size': '11px',
                                color: 'var(--warning)',
                                'font-weight': '600',
                              }}
                            >
                              {p.note}
                            </span>
                          )}
                        </div>
                      )
                    }}
                  </For>
                </div>
              </div>
            )}

            {/* Rate Periods Section */}
            {props.loan.rate_periods && props.loan.rate_periods.length > 0 && (
              <div style="margin-bottom: 16px;">
                <h4 style="margin: 0 0 8px 0; font-size: 14px; font-weight: 600;">Rate Periods</h4>
                <div style="display: flex; flex-direction: column; gap: 8px;">
                  <For each={props.loan.rate_periods}>
                    {(rp) => {
                      const loanStart = new Date(props.loan.start_date)
                      const rateDate = new Date(loanStart)
                      rateDate.setMonth(rateDate.getMonth() + rp.start_month - 1)
                      return (
                        <div style="display: flex; align-items: center; gap: 8px; padding: 8px; background: var(--bg); border-radius: var(--radius);">
                          <span style={{ 'font-size': '12px', color: 'var(--text-secondary)' }}>
                            {formatDate(rateDate.toISOString().split('T')[0])}
                          </span>
                          <span style={{ 'font-size': '11px', color: 'var(--text-secondary)' }}>
                            ({rp.start_month}
                            {rp.end_month ? ` - ${rp.end_month}` : '+'} mo)
                          </span>
                          <span style={{ 'font-weight': 600 }}>{rp.rate}%</span>
                        </div>
                      )
                    }}
                  </For>
                </div>
              </div>
            )}

            {/* Charts */}
            <div
              style={{
                display: 'grid',
                'grid-template-columns': '1fr 1fr',
                gap: '16px',
                'margin-bottom': '24px',
              }}
            >
              <div
                style={{
                  background: 'var(--card-bg)',
                  border: '1px solid var(--border)',
                  'border-radius': 'var(--radius)',
                  padding: '12px',
                }}
              >
                <h4
                  style={{
                    'font-size': '13px',
                    'font-weight': 600,
                    margin: '0 0 8px 0',
                    color: 'var(--text-secondary)',
                  }}
                >
                  Monthly Payment Breakdown
                </h4>
                <Chart
                  type="bar"
                  data={{
                    labels: schedule.map((r) => `M${r.month}`),
                    datasets: [
                      {
                        label: 'Principal',
                        data: schedule.map((r) => r.principal),
                        backgroundColor: 'rgba(34, 197, 94, 0.7)',
                        borderColor: '#22c55e',
                        borderWidth: 0,
                        borderRadius: 2,
                      },
                      {
                        label: 'Interest',
                        data: schedule.map((r) => r.interest),
                        backgroundColor: 'rgba(239, 68, 68, 0.7)',
                        borderColor: '#ef4444',
                        borderWidth: 0,
                        borderRadius: 2,
                      },
                    ],
                  }}
                  options={{
                    responsive: true,
                    maintainAspectRatio: false,
                    scales: {
                      x: {
                        stacked: true,
