import { createSignal } from 'solid-js'
import { api } from '../core/api'
import styles from './LoginModal.module.css'

export interface LoginModalProps {
  onClose: () => void
  onSuccess: () => void
}

export default function LoginModal(props: LoginModalProps) {
  const [username, setUsername] = createSignal('')
  const [password, setPassword] = createSignal('')
  const [error, setError] = createSignal('')
  const [loading, setLoading] = createSignal(false)

  const handleSubmit = async () => {
    const u = username().trim()
    const p = password()
    if (!u || !p) return

    setLoading(true)
    setError('')
    try {
      await api.login(u, p)
      props.onSuccess()
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Login failed')
    } finally {
      setLoading(false)
    }
  }

  const handleKeyDown = (e: KeyboardEvent) => {
    if (e.key === 'Enter') handleSubmit()
    if (e.key === 'Escape') props.onClose()
  }

  return (
    <div
      class={styles.overlay}
      onClick={(e) => {
        if (e.target === e.currentTarget) props.onClose()
      }}
    >
      <div class={styles.modal} onKeyDown={handleKeyDown}>
        <h3 class={styles.title}>Sign In</h3>
        <div class={styles.field}>
          <label class={styles.label}>Username</label>
          <input
            type="text"
            class={styles.input}
            placeholder="Enter your username"
            value={username()}
            onInput={(e) => setUsername((e.target as HTMLInputElement).value)}
            autofocus
          />
        </div>
        <div class={styles.field}>
          <label class={styles.label}>Password</label>
          <input
            type="password"
            class={styles.input}
            placeholder="Enter your password"
            value={password()}
            onInput={(e) => setPassword((e.target as HTMLInputElement).value)}
          />
        </div>
        {error() && <div class={styles.error}>{error()}</div>}
        <div class={styles.actions}>
          <button class={styles.btnCancel} onClick={props.onClose} type="button">
            Cancel
          </button>
          <button
            class={styles.btnSubmit}
            onClick={handleSubmit}
            disabled={loading() || !username().trim() || !password()}
            type="button"
          >
            {loading() ? 'Signing in...' : 'Sign In'}
          </button>
        </div>
      </div>
    </div>
  )
}

/**
 * Modal Component - Generic modal dialog
 */

import { createEffect, createSignal, onMount } from 'solid-js'
import styles from './Modal.module.css'
import type { JSX } from 'solid-js'

interface ModalProps {
  isOpen: boolean
  onClose: () => void
  title?: string
  width?: 'small' | 'medium' | 'large'
  children?: JSX.Element
}

export function Modal(props: ModalProps) {
  const [isVisible, setIsVisible] = createSignal(false)
  const [isMounted, setIsMounted] = createSignal(false)

  const handleClose = () => {
    setIsVisible(false)
    // Small delay to allow animation
    setTimeout(() => {
      setIsVisible(false)
      props.onClose()
    }, 200)
  }

  const handleOverlayClick = (e: MouseEvent) => {
    if (e.target === e.currentTarget) {
      handleClose()
    }
  }

  createEffect(() => {
    if (props.isOpen && isMounted()) {
      setIsVisible(true)
      document.body.style.overflow = 'hidden'
    }
    return () => {
      if (!isMounted()) return
      document.body.style.overflow = ''
    }
  })

  onMount(() => {
    setIsMounted(true)
  })

  if (!props.isOpen) return null

  return (
    <div
      class={styles.modalOverlay}
      classList={{ visible: isVisible() }}
      onClick={handleOverlayClick}
    >
      <div class={styles.modal} classList={{ visible: isVisible() }}>
        {/* Modal Header */}
        <div class={styles.modalHeader}>
          <h2 class={styles.modalTitle}>{props.title}</h2>
          <button class={styles.modalClose} onClick={handleClose} aria-label="Close modal">
            <svg width="24" height="24" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path
                stroke-linecap="round"
                stroke-linejoin="round"
                stroke-width="2"
                d="M6 18L18 6M6 6l12 12"
              />
            </svg>
          </button>
        </div>

        {/* Modal Body */}
        <div class={styles.modalBody}>{props.children}</div>

        {/* Modal Footer */}
        <div class={styles.modalFooter}>
          {props.title !== undefined && !props.title?.includes('Settings') && (
            <button class={styles.modalFooterButton} onClick={handleClose}>
              Close
            </button>
          )}
        </div>
      </div>
    </div>
  )
}

/**
 * Pagination Component
 * Generic pagination control for lists
 */
import { For } from 'solid-js'
import styles from './Pagination.module.css'

interface PaginationProps {
  currentPage: number
  totalPages: number
  itemsPerPage: number
  totalItems?: number
  onPageChange: (page: number) => void
}

export default function Pagination(props: PaginationProps) {
  if (props.totalPages <= 1) return null

  const pages = Array.from({ length: props.totalPages }, (_, i) => i + 1)
  const maxVisible = 5
  let visiblePages: number[] = []

  if (props.totalPages <= maxVisible) {
    visiblePages = pages
  } else {
    const middle = Math.floor(maxVisible / 2)
    let start = Math.min(props.currentPage - middle, props.totalPages - maxVisible)
    let end = Math.min(start + maxVisible, props.totalPages)

    if (start < 1) {
      start = 1
      end = Math.min(maxVisible, props.totalPages)
    }
    if (end > props.totalPages) {
      end = props.totalPages
      start = Math.max(1, end - maxVisible + 1)
    }
    visiblePages = pages.slice(start - 1, end)
  }

  const goToPage = (page: number) => {
    if (page >= 1 && page <= props.totalPages && page !== props.currentPage) {
      props.onPageChange(page)
    }
  }

  return (
    <div class={styles.pagination}>
      <div class={styles.paginationInfo}>
        {props.totalItems ?? 0} transaction{(props.totalItems ?? 0) !== 1 ? 's' : ''} (page{' '}
        {props.currentPage}/{props.totalPages})
      </div>
      <div class={styles.paginationControls}>
        <button
          class={`${styles.pageBtn} ${styles.pageBtnPrev}`}
          onClick={() => {
            goToPage(props.currentPage - 1)
          }}
          disabled={props.currentPage === 1}
        >
          <svg width="12" height="12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path d="M15 19l-7-7 7-7" />
          </svg>
        </button>

        {visiblePages[0] > 1 && (
          <>
            <button
              class={styles.pageBtn}
              onClick={() => {
                goToPage(1)
              }}
            >
              1
            </button>
            {visiblePages[0] > 2 && <span class={styles.ellipsis}>...</span>}
          </>
        )}

        <For each={visiblePages}>
          {(page) => (
            <>
              <button
                class={`${styles.pageBtn} ${page === props.currentPage ? styles.pageBtnActive : ''}`}
                onClick={() => {
                  goToPage(page)
                }}
              >
                {page}
              </button>
            </>
          )}
        </For>

        {visiblePages[visiblePages.length - 1] < props.totalPages && (
          <>
            {visiblePages[visiblePages.length - 1] < props.totalPages - 1 && (
              <span class={styles.ellipsis}>...</span>
            )}
            <button
              class={styles.pageBtn}
              onClick={() => {
                goToPage(props.totalPages)
              }}
            >
              {props.totalPages}
            </button>
          </>
        )}

        <button
          class={`${styles.pageBtn} ${styles.pageBtnNext}`}
          onClick={() => {
            goToPage(props.currentPage + 1)
          }}
          disabled={props.currentPage === props.totalPages}
        >
          <svg width="12" height="12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>
    </div>
  )
}

