/**
 * Quick Add Modal Component
 * Quick transaction entry (Ctrl+Shift+T shortcut)
 */
import { createSignal, For, onCleanup, onMount } from 'solid-js'
import { api, toast } from '../core/api'
import quickAddModalStyles from './QuickAddModal.module.css'
import type { Category } from '../types/models'

export interface QuickAddModalProps {
  isOpen: () => boolean
  onClose: () => void
  categories: () => Category[]
  onSave: (transaction: any) => void
}

export function QuickAddModal(props: QuickAddModalProps) {
  let amountRef: HTMLInputElement | undefined
  const [isSubmitting, setIsSubmitting] = createSignal(false)

  const [formData, setFormData] = createSignal({
    amount: '',
    category_id: null as number | null,
    description: '',
    type: 'expense' as 'income' | 'expense',
    date: new Date().toISOString().split('T')[0],
  })

  const handleSubmit = async () => {
    const data = formData()
    const amountNum = parseFloat(data.amount)
    if (!amountNum || amountNum <= 0) {
      toast('Please enter a valid amount', 'error')
      return
    }
    if (!data.category_id) {
      toast('Please select a category', 'error')
      return
    }

    setIsSubmitting(true)
    try {
      const newTransaction = await api.createTransaction({
        amount: amountNum,
        category_id: data.category_id!,
        description: data.description || (amountNum >= 0 ? 'Quick Add' : 'Quick Add'),
        type: data.type,
        date: data.date,
        beneficiary: '',
        payor: '',
        currency: 'EUR',
        amount_local: amountNum >= 0 ? amountNum : null,
        exchange_rate: 1,
        notes: '',
        profile_id: 1,
      })
      props.onSave(newTransaction)
      props.onClose()
    } catch (error) {
      console.error('Failed to create transaction:', error)
      toast('Failed to save transaction', 'error')
    } finally {
      setIsSubmitting(false)
    }
  }

  const handleKeyDown = (e: KeyboardEvent) => {
    if (e.key === 'Escape') {
      props.onClose()
    }
  }

  onMount(() => {
    document.addEventListener('keydown', handleKeyDown)
    onCleanup(() => {
      document.removeEventListener('keydown', handleKeyDown)
    })
    // Auto-focus amount field on open
    const focusTimer = setTimeout(() => {
      amountRef?.focus()
    }, 100)
    onCleanup(() => {
      clearTimeout(focusTimer)
    })
  })

  return (
    <div
      class={quickAddModalStyles.overlay}
      classList={{ [quickAddModalStyles.isOpen]: props.isOpen() }}
    >
      <div class={quickAddModalStyles.modal}>
        <div class={quickAddModalStyles.header}>
          <h2 class={quickAddModalStyles.title}>Quick Add</h2>
          <button
            class={quickAddModalStyles.closeButton}
            onclick={props.onClose}
            disabled={isSubmitting()}
            type="button"
            aria-label="Close modal"
          >
            <svg
              width="20"
              height="20"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              stroke-width="2"
            >
              <path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div class={quickAddModalStyles.content}>
          <div class={quickAddModalStyles.form}>
            <div class={quickAddModalStyles.formRow}>
              <div class={quickAddModalStyles.formGroup}>
                <label class={quickAddModalStyles.label}>Amount</label>
                <div class={quickAddModalStyles.currencyPrefix}>€</div>
                <input
                  ref={amountRef}
                  class={quickAddModalStyles.amountInput}
                  type="number"
                  step="0.01"
                  placeholder="0.00"
                  value={formData().amount}
                  oninput={(e) => setFormData({ ...formData(), amount: e.currentTarget.value })}
                  disabled={isSubmitting()}
                />
              </div>

              <div class={quickAddModalStyles.formGroup}>
                <label class={quickAddModalStyles.label}>Type</label>
                <div class={quickAddModalStyles.typeButtons}>
                  <button
                    class={`${quickAddModalStyles.typeButton} ${formData().type === 'expense' ? quickAddModalStyles.typeSelected : ''}`}
                    onclick={() => setFormData({ ...formData(), type: 'expense' })}
                    type="button"
                  >
                    Expense
                  </button>
                  <button
                    class={`${quickAddModalStyles.typeButton} ${formData().type === 'income' ? quickAddModalStyles.typeSelected : ''}`}
                    onclick={() => setFormData({ ...formData(), type: 'income' })}
                    type="button"
                  >
                    Income
                  </button>
                </div>
              </div>
            </div>

            <div class={quickAddModalStyles.formGroup}>
              <label class={quickAddModalStyles.label}>Category</label>
              <select
                class={quickAddModalStyles.categorySelect}
                value={formData().category_id?.toString() || ''}
                onchange={(e) =>
                  setFormData({
                    ...formData(),
                    category_id: e.currentTarget.value ? Number(e.currentTarget.value) : null,
                  })
                }
                disabled={isSubmitting()}
              >
                <option value="">Select a category</option>
                <For each={props.categories()}>
                  {(category) => <option value={category.id}>{category.name}</option>}
                </For>
              </select>
            </div>

            <div class={quickAddModalStyles.formGroup}>
              <label class={quickAddModalStyles.label}>Description</label>
              <input
                class={quickAddModalStyles.descriptionInput}
                type="text"
                placeholder="Enter description..."
                value={formData().description}
                oninput={(e) => setFormData({ ...formData(), description: e.currentTarget.value })}
                disabled={isSubmitting()}
              />
            </div>

            <div class={quickAddModalStyles.formGroup}>
              <label class={quickAddModalStyles.label}>Date</label>
              <input
                class={quickAddModalStyles.dateInput}
                type="date"
                value={formData().date}
                onchange={(e) => setFormData({ ...formData(), date: e.currentTarget.value })}
                disabled={isSubmitting()}
              />
            </div>
          </div>
        </div>

        <div class={quickAddModalStyles.footer}>
          <button
            class={quickAddModalStyles.cancelButton}
            onclick={props.onClose}
            disabled={isSubmitting()}
            type="button"
          >
            Cancel
          </button>
          <button
            class={`${quickAddModalStyles.saveButton} ${isSubmitting() ? quickAddModalStyles.disabled : ''}`}
            onclick={handleSubmit}
            disabled={isSubmitting()}
            type="button"
          >
            {isSubmitting() ? (
              <span class={quickAddModalStyles.spinner}>
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
                  <circle
                    cx="12"
                    cy="12"
                    r="10"
                    stroke="currentColor"
                    stroke-width="3"
                    stroke-dasharray="30"
                    stroke-dashoffset="60"
                  />
                </svg>
              </span>
            ) : (
              'Save Transaction'
            )}
          </button>
        </div>
      </div>
    </div>
  )
}

export default function QuickAddModalDefault(props: QuickAddModalProps) {
  return <QuickAddModal {...props} />
}

/**
 * Reconciliation Modal Component
 * Mark transactions as reconciled
 */
import { createSignal, onCleanup, onMount, Show } from 'solid-js'
import { api, toast } from '../core/api'

export interface ReconciliationModalProps {
  isOpen: () => boolean
  onClose: () => void
  selectedTransactionIds: number[]
  onReconciled: () => void
}

export default function ReconciliationModal(props: ReconciliationModalProps) {
  const [summary, setSummary] = createSignal<{
    reconciled_count: number
    unreconciled_count: number
    reconciled_total: number
    unreconciled_total: number
  } | null>(null)
  const [isLoading, setIsLoading] = createSignal(false)
  const [isReconciling, setIsReconciling] = createSignal(false)

  const loadSummary = async () => {
    setIsLoading(true)
    try {
      const data = await api.getReconciliationSummary()
      setSummary(data)
    } catch {
      // Summary loading is best-effort
    } finally {
      setIsLoading(false)
    }
  }

  const reconcileSelected = async () => {
    if (props.selectedTransactionIds.length === 0) {
      toast('No transactions selected', 'error')
      return
    }
    setIsReconciling(true)
    try {
      const result = await api.reconcileByIds(props.selectedTransactionIds)
      toast(result.message || `Marked ${result.updated} transactions as reconciled`, 'success')
      await loadSummary()
      props.onReconciled()
      props.onClose()
    } catch {
      toast('Failed to reconcile transactions', 'error')
    } finally {
      setIsReconciling(false)
    }
  }

  const reconcileAllUnreconciled = async () => {
    const s = summary()
    if (!s || s.unreconciled_count === 0) {
      toast('No unreconciled transactions', 'info')
      return
    }
    setIsReconciling(true)
    try {
      // Get all unreconciled transactions and reconcile them
      const result = await api.reconcileByDateRange('2000-01-01', '2099-12-31')
      toast(result.message || `Marked ${result.count} transactions as reconciled`, 'success')
      await loadSummary()
      props.onReconciled()
      props.onClose()
    } catch {
      toast('Failed to reconcile transactions', 'error')
    } finally {
      setIsReconciling(false)
    }
  }

  onMount(() => {
    loadSummary()
  })

  const handleKeyDown = (e: KeyboardEvent) => {
    if (e.key === 'Escape' && props.isOpen()) props.onClose()
  }
  document.addEventListener('keydown', handleKeyDown)
  onCleanup(() => {
    document.removeEventListener('keydown', handleKeyDown)
  })

  return (
    <div style={{ display: props.isOpen() ? 'block' : 'none' }}>
      <div
        style={{
          position: 'fixed',
          inset: 0,
          background: 'rgba(0,0,0,0.5)',
          'z-index': 1000,
          display: 'flex',
          'align-items': 'center',
          'justify-content': 'center',
        }}
        onClick={props.onClose}
      >
        <div
          style={{
            background: 'var(--card-bg)',
            'border-radius': 'var(--radius)',
            padding: '24px',
            'min-width': '400px',
            'max-width': '480px',
            width: '100%',
            'box-shadow': '0 20px 60px rgba(0,0,0,0.3)',
          }}
          onClick={(e) => {
            e.stopPropagation()
          }}
        >
          <div
            style={{
              display: 'flex',
              'justify-content': 'space-between',
              'align-items': 'center',
              'margin-bottom': '20px',
            }}
          >
            <h2 style={{ margin: 0, 'font-size': '18px', 'font-weight': 700 }}>Reconciliation</h2>
            <button
              onClick={props.onClose}
              style={{
                background: 'none',
                border: 'none',
                cursor: 'pointer',
                color: 'var(--text-secondary)',
                padding: '4px',
                'border-radius': '4px',
              }}
            >
              <svg
                width="20"
                height="20"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                stroke-width="2"
              >
                <path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>

          <Show when={isLoading()}>
            <div style={{ display: 'flex', 'justify-content': 'center', padding: '20px' }}>
              <div
                style={{
                  width: '24px',
                  height: '24px',
                  border: '3px solid var(--border)',
                  'border-top-color': 'var(--primary)',
                  'border-radius': '50%',
                  animation: 'spin 0.6s linear infinite',
                }}
              />
            </div>
          </Show>

          <Show when={!isLoading() && summary()}>
            <div
              style={{
                display: 'grid',
                'grid-template-columns': '1fr 1fr',
                gap: '12px',
                'margin-bottom': '20px',
              }}
            >
              <div
                style={{
                  padding: '12px',
                  background: 'var(--bg)',
                  'border-radius': '8px',
                  'text-align': 'center',
                }}
              >
                <div
                  style={{
                    'font-size': '12px',
                    color: 'var(--text-secondary)',
                    'margin-bottom': '4px',
                  }}
                >
                  Reconciled
                </div>
                <div style={{ 'font-size': '20px', 'font-weight': 700, color: 'var(--success)' }}>
                  {summary()!.reconciled_count}
                </div>
              </div>
              <div
                style={{
                  padding: '12px',
                  background: 'var(--bg)',
                  'border-radius': '8px',
                  'text-align': 'center',
                }}
              >
                <div
                  style={{
                    'font-size': '12px',
                    color: 'var(--text-secondary)',
                    'margin-bottom': '4px',
                  }}
                >
                  Unreconciled
                </div>
                <div style={{ 'font-size': '20px', 'font-weight': 700, color: 'var(--warning)' }}>
                  {summary()!.unreconciled_count}
                </div>
              </div>
            </div>
          </Show>

          <div style={{ display: 'flex', 'flex-direction': 'column', gap: '8px' }}>
            <button
              onClick={reconcileSelected}
              disabled={props.selectedTransactionIds.length === 0 || isReconciling()}
              style={{
                padding: '10px 16px',
                background:
                  props.selectedTransactionIds.length > 0
                    ? 'var(--primary)'
                    : 'var(--bg-secondary)',
                color: props.selectedTransactionIds.length > 0 ? '#fff' : 'var(--text-secondary)',
                border: 'none',
                'border-radius': 'var(--radius)',
                cursor: props.selectedTransactionIds.length > 0 ? 'pointer' : 'not-allowed',
                'font-size': '14px',
                'font-weight': 500,
              }}
            >
              Reconcile Selected ({props.selectedTransactionIds.length})
            </button>
            <button
              onClick={reconcileAllUnreconciled}
              disabled={isReconciling()}
              style={{
                padding: '10px 16px',
                background: 'var(--bg-secondary)',
                color: 'var(--text)',
                border: '1px solid var(--border)',
                'border-radius': 'var(--radius)',
                cursor: 'pointer',
                'font-size': '14px',
                'font-weight': 500,
              }}
            >
              Mark All Unreconciled as Reconciled
            </button>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes spin {
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  )
}

/**
 * RecurringSection Component
 * Manages recurring transactions — list, create, edit, delete, populate
 */
import { createSignal, For, onMount } from 'solid-js'
import { api } from '../core/api'
import { showConfirm } from '../core/confirmStore'
import styles from './RecurringSection.module.css'
import type { Category, RecurringTransaction } from '../types/models'

interface RecurringSectionProps {
  categories: Category[]
  onRefreshTransactions: () => void
}

type RecurringFormData = Pick<
  RecurringTransaction,
  | 'description'
  | 'amount'
  | 'type'
  | 'frequency'
  | 'day_of_month'
  | 'next_date'
  | 'category_id'
  | 'notes'
>

export default function RecurringSection(props: RecurringSectionProps) {
  const [items, setItems] = createSignal<RecurringTransaction[]>([])
  const [isModalOpen, setIsModalOpen] = createSignal(false)
  const [editingId, setEditingId] = createSignal<number | null>(null)
  const [expanded, setExpanded] = createSignal(false)

  // Form fields
  const [formDescription, setFormDescription] = createSignal('')
  const [formAmount, setFormAmount] = createSignal('')
  const [formType, setFormType] = createSignal('expense')
  const [formFrequency, setFormFrequency] = createSignal('monthly')
  const [formDay, setFormDay] = createSignal('')
  const [formNextDate, setFormNextDate] = createSignal(new Date().toISOString().slice(0, 10))
  const [formCategory, setFormCategory] = createSignal<number | null>(null)
  const [formNotes, setFormNotes] = createSignal('')

  const loadItems = async () => {
    try {
      const data = await api.getRecurring()
      setItems(Array.isArray(data) ? data : [])
    } catch {
      // Recurring items will remain empty
    }
  }

  onMount(() => {
    loadItems()
  })

  const openAddModal = () => {
    setEditingId(null)
    resetForm()
    setIsModalOpen(true)
  }

  const openEditModal = async (item: RecurringTransaction) => {
    setEditingId(item.id)
    setFormDescription(item.description)
    setFormAmount(item.amount.toString())
    setFormType(item.type)
    setFormFrequency(item.frequency)
    setFormDay(item.day_of_month?.toString() || '')
    setFormNextDate(item.next_date || new Date().toISOString().slice(0, 10))
    setFormCategory(item.category_id)
    setFormNotes(item.notes || '')
    setIsModalOpen(true)
  }

  const resetForm = () => {
    setFormDescription('')
    setFormAmount('')
    setFormType('expense')
    setFormFrequency('monthly')
    setFormDay('')
    setFormNextDate(new Date().toISOString().slice(0, 10))
    setFormCategory(null)
    setFormNotes('')
  }

  const handleSave = async () => {
    const data = {
      description: formDescription(),
      amount: parseFloat(formAmount() || '0'),
      type: formType() as RecurringTransaction['type'],
      frequency: formFrequency() as RecurringTransaction['frequency'],
      day_of_month: formDay() ? parseInt(formDay()) : null,
      next_date: formNextDate(),
      category_id: formCategory(),
      notes: formNotes() || null,
    } satisfies RecurringFormData

    try {
      const id = editingId()
      if (id) {
        await api.updateRecurring(id, data)
      } else {
        await api.createRecurring(data)
      }
      setIsModalOpen(false)
      await loadItems()
    } catch (error) {
      console.error('Failed to save recurring transaction:', error)
    }
  }

  const handleDelete = async (item: RecurringTransaction) => {
    if (!(await showConfirm(`Delete recurring "${item.description}"?`))) return
    try {
      await api.deleteRecurring(item.id)
      await loadItems()
    } catch (error) {
      console.error('Failed to delete recurring:', error)
    }
  }

  const handlePopulate = async (item: RecurringTransaction) => {
    try {
      await api.populateRecurring(item.id)
      props.onRefreshTransactions()
    } catch (error) {
      console.error('Failed to populate recurring:', error)
    }
  }

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(amount)
  }

  const formatDate = (dateStr: string | null) => {
    if (!dateStr) return '-'
    return new Date(dateStr).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
    })
  }

  return (
    <div class={styles.section}>
      <div class={styles.sectionHeader} onClick={() => setExpanded(!expanded())}>
        <svg
          width="16"
          height="16"
          fill="none"
          stroke="currentColor"
          stroke-width="2"
          viewBox="0 0 24 24"
          class={`${styles.chevron} ${expanded() ? styles.chevronOpen : ''}`}
        >
          <path d="M9 18l6-6-6-6" />
        </svg>
        <h2 class={styles.sectionTitle}>Recurring Transactions</h2>
        <span class={styles.count}>{items().length}</span>
        <button
          class={styles.addBtn}
          onClick={(e) => {
            e.stopPropagation()
            openAddModal()
          }}
        >
          <svg
            width="14"
            height="14"
            fill="none"
            stroke="currentColor"
            stroke-width="2"
            viewBox="0 0 24 24"
          >
            <path d="M12 5v14M5 12h14" />
          </svg>
          Add
        </button>
      </div>

      {expanded() && (
        <div class={styles.list}>
          {items().length === 0 ? (
            <div class={styles.emptyState}>
              <svg
                width="40"
                height="40"
                fill="none"
                stroke="currentColor"
                stroke-width="1.5"
                viewBox="0 0 24 24"
                style="opacity: 0.3"
              >
                <path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
              </svg>
              <p>No recurring items</p>
            </div>
          ) : (
            <For each={items()}>
              {(item) => (
                <div class={styles.item}>
                  <div class={styles.itemInfo}>
                    <span
                      class={styles.categoryDot}
                      style={{ 'background-color': item.category_color || '#94a3b8' }}
                    />
                    <span class={styles.itemName}>{item.description}</span>
                    <span class={styles.itemFreq}>{item.frequency}</span>
                  </div>
                  <div class={styles.itemRight}>
                    <span class={`${styles.itemAmount} ${styles[item.type]}`}>
                      {item.type === 'expense' ? '-' : '+'}
                      {formatCurrency(item.amount)}
                    </span>
                    <span class={styles.itemNext}>{formatDate(item.next_date)}</span>
                    <button
                      class={styles.itemAction}
                      onClick={() => handlePopulate(item)}
                      title="Add to transactions"
                    >
                      <svg
                        width="14"
                        height="14"
                        fill="none"
                        stroke="currentColor"
                        stroke-width="2"
                        viewBox="0 0 24 24"
                      >
                        <path d="M12 5v14M5 12h14" />
                      </svg>
                    </button>
                    <button
                      class={styles.itemAction}
                      onClick={() => openEditModal(item)}
                      title="Edit"
                    >
                      <svg
                        width="14"
                        height="14"
                        fill="none"
                        stroke="currentColor"
                        stroke-width="2"
                        viewBox="0 0 24 24"
                      >
                        <path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7" />
                        <path d="M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z" />
                      </svg>
                    </button>
                    <button
                      class={`${styles.itemAction} ${styles.itemActionDanger}`}
                      onClick={() => handleDelete(item)}
                      title="Delete"
                    >
                      <svg
                        width="14"
                        height="14"
                        fill="none"
                        stroke="currentColor"
                        stroke-width="2"
                        viewBox="0 0 24 24"
                      >
                        <path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                      </svg>
                    </button>
                  </div>
                </div>
              )}
            </For>
          )}
        </div>
      )}

      {/* Modal */}
      {isModalOpen() && (
        <div class={styles.modalOverlay} onClick={() => setIsModalOpen(false)}>
          <div
            class={styles.modal}
            onClick={(e) => {
              e.stopPropagation()
            }}
          >
            <div class={styles.modalHeader}>
              <h3>{editingId() ? 'Edit Recurring' : 'Add Recurring'}</h3>
              <button class={styles.closeBtn} onClick={() => setIsModalOpen(false)}>
                <svg
                  width="20"
                  height="20"
                  fill="none"
                  stroke="currentColor"
                  stroke-width="2"
                  viewBox="0 0 24 24"
                >
                  <path d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
            <div class={styles.modalBody}>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Description</label>
                <input
                  type="text"
                  class={styles.formControl}
                  value={formDescription()}
                  onInput={(e) => setFormDescription((e.target as HTMLInputElement).value)}
                />
              </div>
              <div class={styles.formRow}>
                <div class={styles.formGroup}>
                  <label class={styles.formLabel}>Amount</label>
                  <input
                    type="number"
                    step="0.01"
                    class={styles.formControl}
                    value={formAmount()}
                    onInput={(e) => setFormAmount((e.target as HTMLInputElement).value)}
                  />
                </div>
                <div class={styles.formGroup}>
                  <label class={styles.formLabel}>Type</label>
                  <select
                    class={styles.formControl}
                    value={formType()}
                    onChange={(e) => setFormType((e.target as HTMLSelectElement).value)}
                  >
                    <option value="expense">Expense</option>
                    <option value="income">Income</option>
                    <option value="transfer">Transfer</option>
                  </select>
                </div>
              </div>
              <div class={styles.formRow}>
                <div class={styles.formGroup}>
                  <label class={styles.formLabel}>Frequency</label>
                  <select
                    class={styles.formControl}
                    value={formFrequency()}
                    onChange={(e) => setFormFrequency((e.target as HTMLSelectElement).value)}
                  >
                    <option value="daily">Daily</option>
                    <option value="weekly">Weekly</option>
                    <option value="monthly">Monthly</option>
                    <option value="yearly">Yearly</option>
                  </select>
                </div>
                <div class={styles.formGroup}>
                  <label class={styles.formLabel}>Day of Month</label>
                  <input
                    type="number"
                    min="1"
                    max="31"
                    class={styles.formControl}
                    value={formDay()}
                    onInput={(e) => setFormDay((e.target as HTMLInputElement).value)}
                    placeholder="1-31"
                  />
                </div>
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Next Date</label>
                <input
                  type="date"
                  class={styles.formControl}
                  value={formNextDate()}
                  onInput={(e) => setFormNextDate((e.target as HTMLInputElement).value)}
                />
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Category</label>
                <select
                  class={styles.formControl}
                  value={formCategory() ?? ''}
                  onChange={(e) => {
                    const val = (e.target as HTMLSelectElement).value
                    setFormCategory(val ? parseInt(val) : null)
                  }}
                >
                  <option value="">Select category...</option>
                  <For each={props.categories}>
                    {(cat) => <option value={cat.id}>{cat.name}</option>}
                  </For>
                </select>
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Notes</label>
                <textarea
                  class={styles.formControl}
                  rows="2"
                  value={formNotes()}
                  onInput={(e) => setFormNotes((e.target as HTMLTextAreaElement).value)}
                />
              </div>
            </div>
            <div class={styles.modalFooter}>
              <button class={styles.btnSecondary} onClick={() => setIsModalOpen(false)}>
                Cancel
              </button>
              <button class={styles.btnPrimary} onClick={handleSave}>
                Save
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

/**
 * SankeyChart Component
 * D3-based Sankey diagram for budget → spending flow visualization
 */
import { sankey, sankeyLinkHorizontal } from 'd3-sankey'
import { createEffect, onCleanup, onMount } from 'solid-js'
import type * as D3 from 'd3'

let d3Module: typeof D3 | null = null

async function getD3() {
  if (!d3Module) d3Module = await import('d3')
  return d3Module
}

interface SankeyNode {
  name: string
  category: string
  color?: string
}

interface SankeyLink {
  source: string | number
  target: string | number
  value: number
  sourceCategory?: string
  targetCategory?: string
}

/** Sankey node enriched by d3-sankey layout (includes positioning props) */
interface SankeyNodeDatum extends SankeyNode {
  x0: number
  x1: number
  y0: number
  y1: number
  value?: number
  index?: number
  sourceLinks?: SankeyLinkDatum[]
  targetLinks?: SankeyLinkDatum[]
}

/** Sankey link enriched by d3-sankey layout (includes width + positioning) */
interface SankeyLinkDatum {
  source: SankeyNodeDatum | number | string
  target: SankeyNodeDatum | number | string
  value: number
  sourceCategory?: string
  targetCategory?: string
  width: number
  y0: number
  y1: number
  index?: number
}

interface Props {
  data: { nodes: SankeyNode[]; links: SankeyLink[] }
  height?: number
  width?: number
}

export default function SankeyChart(props: Props) {
  let containerRef: HTMLDivElement | undefined
  let resizeDebounce: ReturnType<typeof setTimeout> | undefined

  const renderSankey = async () => {
    const container = containerRef
    if (!container || !props.data?.nodes?.length) return

    const d3 = await getD3()

    const width = props.width || container.clientWidth || 800
    if (width <= 0) return
    const height = props.height || 400
    const margin = { top: 10, right: 20, bottom: 10, left: 20 }

    // Clear previous
    d3.select(container).selectAll('svg').remove()

    const svg = d3
      .select(container)
      .append('svg')
      .attr('width', width)
      .attr('height', height)
      .attr('viewBox', [0, 0, width, height])

    const sankeyGenerator = sankey<SankeyNodeDatum, SankeyLinkDatum>()
      .nodeWidth(20)
      .nodePadding(10)
      .extent([
        [margin.left, margin.top],
        [width - margin.right, height - margin.bottom],
      ])

    const categoryColors: Record<string, string> = {
      budget: '#6366f1',
      category: '#f59e0b',
      actual: '#10b981',
      savings: '#06b6d4',
    }

    const { nodes, links } = sankeyGenerator({
      nodes: props.data.nodes.map(
        (d) => ({ ...d, x0: 0, x1: 0, y0: 0, y1: 0 }) satisfies SankeyNodeDatum
      ),
      links: props.data.links.map(
        (d) => ({ ...d, width: 0, y0: 0, y1: 0 }) satisfies SankeyLinkDatum
      ),
    })

    // Draw links
    const link = svg
      .append('g')
      .attr('fill', 'none')
      .attr('stroke-opacity', 0.4)
      .selectAll('path')
      .data(links)
      .join('path')
      .attr('d', sankeyLinkHorizontal())
      .attr('stroke', (d: SankeyLinkDatum) => {
        const targetNode = typeof d.target === 'object' ? (d.target as SankeyNodeDatum) : null
        const targetCat: string = targetNode?.category || d.targetCategory || ''
        return categoryColors[targetCat] || '#6366f1'
      })
      .attr('stroke-width', (d: SankeyLinkDatum) => Math.max(1, d.width))

    link.append('title').text((d: SankeyLinkDatum) => {
      const srcName =
        typeof d.source === 'object' ? (d.source as SankeyNodeDatum).name : String(d.source)
      const tgtName =
        typeof d.target === 'object' ? (d.target as SankeyNodeDatum).name : String(d.target)
      return `${srcName} → ${tgtName}\n${d3.format(',.2f')(d.value)}`
    })

    // Draw nodes
    const node = svg
      .append('g')
      .selectAll('rect')
      .data(nodes)
      .join('rect')
      .attr('x', (d: SankeyNodeDatum) => d.x0)
      .attr('y', (d: SankeyNodeDatum) => d.y0)
      .attr('height', (d: SankeyNodeDatum) => Math.max(0, d.y1 - d.y0))
      .attr('width', (d: SankeyNodeDatum) => d.x1 - d.x0)
      .attr('fill', (d: SankeyNodeDatum) => d.color || categoryColors[d.category] || '#6b7280')
      .attr('rx', 3)

    node
      .append('title')
      .text((d: SankeyNodeDatum) => `${d.name}\n${d3.format(',.2f')(d.value || 0)}`)

    // Draw labels
    svg
      .append('g')
      .selectAll('text')
      .data(nodes)
      .join('text')
      .attr('x', (d: SankeyNodeDatum) => (d.x0 < width / 2 ? d.x1 + 6 : d.x0 - 6))
      .attr('y', (d: SankeyNodeDatum) => (d.y0 + d.y1) / 2)
      .attr('dy', '0.35em')
      .attr('text-anchor', (d: SankeyNodeDatum) => (d.x0 < width / 2 ? 'start' : 'end'))
      .attr('fill', 'var(--text)')
      .attr('font-size', '11px')
      .text((d: SankeyNodeDatum) => d.name)
  }

  onMount(() => {
    const observer = new ResizeObserver(() => {
      clearTimeout(resizeDebounce)
      resizeDebounce = setTimeout(() => {
        renderSankey()
      }, 150)
    })
    if (containerRef) observer.observe(containerRef)
    onCleanup(() => {
      clearTimeout(resizeDebounce)
      observer.disconnect()
    })
  })

  // Reactive render on data change — also handles initial render
  createEffect(() => {
    if (props.data) renderSankey()
  })

  return (
    <div
      ref={containerRef}
      style={{
        width: '100%',
        height: `${props.height || 400}px`,
        overflow: 'hidden',
      }}
    />
  )
}

/**
 * Settings Dialog - Modal for app settings
 * Supports theme, language, currency, and storage mode selection
 */

import { createSignal, For } from 'solid-js'
import { toast } from '../core/api.js'
import { apiFetch } from '../core/apiFetch'
import { setStorageMode } from '../core/storage/storageFactory.js'
import ConfirmButton from './ConfirmButton.js'
import { Modal } from './Modal.js'
import styles from './SettingsDialog.module.css'
import type { Component } from 'solid-js'
import type { StorageMode } from '../core/storage/storageFactory.js'

interface SettingsDialogProps {
  isOpen: boolean
  onClose: () => void
}

type SettingTab = 'general' | 'storage'

export const SettingsDialog: Component<SettingsDialogProps> = (props) => {
  const [activeTab, setActiveTab] = createSignal<SettingTab>('general')

  // Settings state
  const [language, setLanguage] = createSignal('en')
  const [currency, setCurrency] = createSignal('USD')
  const [primaryCurrency, setPrimaryCurrency] = createSignal('USD')

  // Storage mode state
  const [currentMode, setCurrentMode] = createSignal<StorageMode>('serverless')

  // Load current settings
  const loadSettings = async () => {
    try {
      const response = await apiFetch('/api/settings')
      if (response.ok) {
        const settings = await response.json()
        setLanguage(settings.language !== undefined ? settings.language : 'en')
        setCurrency(settings.currency !== undefined ? settings.currency : 'USD')
        setPrimaryCurrency(
          settings.primary_currency !== undefined ? settings.primary_currency : 'USD'
        )
      }
    } catch (_error: unknown) {
      console.error('Failed to load settings:', _error)
    }

    try {
      const response = await apiFetch('/api/storage-mode')
      if (response.ok) {
        setCurrentMode(await response.json())
      }
    } catch (_error: unknown) {
      console.error('Failed to load storage mode:', _error)
    }
  }

  // Save settings
  const saveSettings = async () => {
    try {
      await apiFetch('/api/settings', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({
          language: language(),
          currency: currency(),
          primary_currency: primaryCurrency(),
        }),
      })
      toast('Settings saved', 'success')
    } catch (_error: unknown) {
      toast('Failed to save settings', 'error')
      console.error('Failed to save settings:', _error)
    }
  }

  // Set storage mode
  const handleSetMode = async (mode: StorageMode) => {
    try {
      await apiFetch('/api/storage-mode', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ mode }),
      })
      setStorageMode(mode)
      setCurrentMode(mode)
      toast(`Storage mode: ${mode === 'serverless' ? 'Serverless' : 'Self-Hosted'}`, 'success')
    } catch {
      toast('Failed to change storage mode', 'error')
    }
  }

  // Export data
  const handleExport = async () => {
    try {
      const response = await apiFetch('/api/export', {
        method: 'GET',
        credentials: 'include',
      })

      if (!response.ok) throw new Error('Export failed')

      const data = await response.json()
      const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' })
      const url = URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = `finance-export-${new Date().toISOString().split('T')[0]}.json`
      a.click()
      URL.revokeObjectURL(url)
      toast('Data exported successfully', 'success')
    } catch {
      toast('Failed to export data', 'error')
    }
  }

  // Import data
  const handleImport = async (e: Event) => {
    const target = e.target as HTMLInputElement
    const file = target.files?.[0]

    if (file === undefined) return

    try {
      const formData = new FormData()
      formData.append('file', file)

      const response = await apiFetch('/api/import', {
        method: 'POST',
        credentials: 'include',
        body: formData,
      })

      if (!response.ok) {
        throw new Error('Import failed')
      }

      const result = await response.json()
      toast(`${result.imported !== undefined ? result.imported : 0} items imported`, 'success')
      props.onClose()
    } catch {
      toast('Failed to import data', 'error')
    }
  }

  // Reset data
  const _handleReset = async () => {
    try {
      await apiFetch('/api/clear-all', {
        method: 'DELETE',
        credentials: 'include',
      })
      toast('All data has been reset', 'success')
      props.onClose()
    } catch {
      toast('Failed to reset data', 'error')
    }
  }

  // Initialize
  if (props.isOpen) {
    void loadSettings()
  }

  const languages = [
    { code: 'en', name: 'English' },
    { code: 'pl', name: 'Polski' },
    { code: 'de', name: 'Deutsch' },
    { code: 'fr', name: 'Français' },
    { code: 'es', name: 'Español' },
  ]

  const currencies = [
    { code: 'USD', name: 'USD - US Dollar' },
    { code: 'EUR', name: 'EUR - Euro' },
    { code: 'GBP', name: 'GBP - British Pound' },
    { code: 'PLN', name: 'PLN - Polish Zloty' },
    { code: 'CZK', name: 'CZK - Czech Koruna' },
    { code: 'SEK', name: 'SEK - Swedish Krona' },
  ]

  return (
    <div class={styles.settingsDialog}>
      <Modal isOpen={props.isOpen} onClose={props.onClose} title="Settings">
        {/* Tabs */}
        <div class={styles.settingsTabs}>
          <button
            class={`${styles.tab} ${activeTab() === 'general' ? styles.active : ''}`}
            onClick={() => {
              setActiveTab('general')
            }}
          >
            General
          </button>
          <button
            class={`${styles.tab} ${activeTab() === 'storage' ? styles.active : ''}`}
            onClick={() => {
              setActiveTab('storage')
            }}
          >
            Storage
          </button>
        </div>

        {/* General Settings */}
        <div class={`${styles.tabContent} ${activeTab() === 'general' ? styles.active : ''}`}>
          {/* Language */}
          <div class={styles.settingGroup}>
            <label class={styles.settingLabel}>Language</label>
            <select
              class={styles.settingSelect}
              value={language()}
              onChange={(e) => {
                setLanguage(e.currentTarget.value)
              }}
            >
              <For each={languages}>{(lang) => <option value={lang.code}>{lang.name}</option>}</For>
            </select>
          </div>

          {/* Currency */}
          <div class={styles.settingGroup}>
            <label class={styles.settingLabel}>Currency</label>
            <select
              class={styles.settingSelect}
              value={currency()}
              onChange={(e) => {
                setCurrency(e.currentTarget.value)
              }}
            >
              <For each={currencies}>
                {(curr) => <option value={curr.code}>{curr.name}</option>}
              </For>
            </select>
          </div>

          <div class={styles.settingGroup}>
            <label class={styles.settingLabel}>Primary Currency</label>
            <select
              class={styles.settingSelect}
              value={primaryCurrency()}
              onChange={(e) => {
                setPrimaryCurrency(e.currentTarget.value)
              }}
            >
              <For each={currencies}>
                {(curr) => <option value={curr.code}>{curr.name}</option>}
              </For>
            </select>
          </div>

          <div class={styles.settingActions}>
            <button
              class={styles.btnPrimary}
              onClick={() => {
                void saveSettings()
              }}
            >
              Save Settings
            </button>
          </div>
        </div>

        {/* Storage Settings */}
        <div class={`${styles.tabContent} ${activeTab() === 'storage' ? styles.active : ''}`}>
          {/* Storage Mode */}
          <div class={styles.settingGroup}>
            <label class={styles.settingLabel}>Storage Mode</label>
            <div class={styles.modeSelector}>
              <button
                class={`${styles.modeBtn} ${currentMode() === 'serverless' ? styles.active : ''}`}
                onClick={() => {
                  void handleSetMode('serverless')
                }}
              >
                <div class={styles.modeInfo}>
                  <strong>Serverless</strong>
                  <span>Browser localStorage storage</span>
                </div>
                <div class={styles.modeIcon}>Serverless</div>
              </button>
              <button
                class={`${styles.modeBtn} ${currentMode() === 'self-hosted' ? styles.active : ''}`}
                onClick={() => {
                  void handleSetMode('self-hosted')
                }}
              >
                <div class={styles.modeInfo}>
                  <strong>Self-Hosted</strong>
                  <span>Backend server storage</span>
                </div>
                <div class={styles.modeIcon}>Self-Hosted</div>
              </button>
            </div>
            <p class={styles.settingHint}>
              {currentMode() === 'serverless'
                ? 'Your data is stored in your browser. You can export/import your data at any time.'
                : 'Your data is stored on the backend server. Use this if you need data access across devices.'}
            </p>
          </div>

          {/* Data Management */}
          <div class={styles.settingGroup}>
            <label class={styles.settingLabel}>Data Management</label>
            <div class={styles.dataActions}>
              <button
                class={styles.btnSecondary}
                onClick={() => {
                  void handleExport()
                }}
              >
                Export Data
              </button>
              <button class={styles.btnSecondary}>
                Import Data
                <input
                  type="file"
                  accept=".json"
                  style="display: none"
                  onChange={(e) => {
                    void handleImport(e)
                  }}
                />
              </button>
            </div>
          </div>

          {/* Reset */}
          <div class={styles.settingGroup}>
            <label class={styles.settingLabel}>Danger Zone</label>
            <ConfirmButton
              class={styles.btnDanger}
              onConfirm={() => {
                void _handleReset()
              }}
              confirmLabel="This will permanently delete all your data. Continue?"
              label="Reset All Data"
            />
          </div>
        </div>
      </Modal>
    </div>
  )
}

/**
 * Spotlight Component
 * Full-screen walkthrough overlay with target highlighting and tooltip
 */
import { createEffect, createMemo, createSignal, onCleanup } from 'solid-js'
import {
  endSpotlight,
  nextSpotlightStep,
  prevSpotlightStep,
  spotlightActive,
  spotlightStep,
  tourSteps,
} from '../core/spotlightStore'
import styles from './Spotlight.module.css'
import type { SpotlightStep } from '../core/spotlightStore'

const GAP = 8
const TOOLTIP_WIDTH = 320

function bestPlacement(
  step: SpotlightStep,
  targetRect: DOMRect
): { placement: string; top: number; left: number } {
  const vw = window.innerWidth
  const vh = window.innerHeight
  const tw = TOOLTIP_WIDTH
  const th = 140

  // If target is huge (most of the viewport), center the tooltip
  const tooBig = targetRect.height > vh * 0.55 || targetRect.width > vw * 0.75
  if (tooBig) {
    return { placement: 'center', top: vh / 2 - th / 2, left: vw / 2 - tw / 2 }
  }

  const pref = step.placement || 'bottom'
  const placements = [pref, 'bottom', 'top', 'right', 'left'].filter(
    (v, i, a) => a.indexOf(v) === i
  )

  for (const p of placements) {
    let top = 0
    let left = 0

    switch (p) {
      case 'bottom':
        top = targetRect.bottom + GAP
        left = targetRect.left + targetRect.width / 2 - tw / 2
        break
      case 'top':
        top = targetRect.top - th - GAP
        left = targetRect.left + targetRect.width / 2 - tw / 2
        break
      case 'right':
        top = targetRect.top + targetRect.height / 2 - th / 2
        left = targetRect.right + GAP
        break
      case 'left':
        top = targetRect.top + targetRect.height / 2 - th / 2
        left = targetRect.left - tw - GAP
        break
    }

    // Clamp to viewport
    const minPad = 12
    if (left < minPad) left = minPad
    if (left + tw > vw - minPad) left = vw - tw - minPad
    if (top < minPad) top = minPad
    if (top + th > vh - minPad) top = vh - th - minPad

    // Check if it fits and doesn't overlap the target center
    const tx = targetRect.left + targetRect.width / 2
    const ty = targetRect.top + targetRect.height / 2
    const overlapsCenter = left < tx && left + tw > tx && top < ty && top + th > ty

    if (top > 0 && left > 0 && top + th < vh && left + tw < vw && !overlapsCenter) {
      return { placement: p, top, left }
    }
  }

  // Fallback: center
  return { placement: 'center', top: vh / 2 - th / 2, left: vw / 2 - tw / 2 }
}

export default function Spotlight() {
  const [highlight, setHighlight] = createSignal({
    top: 0,
    left: 0,
    width: 0,
    height: 0,
    rx: 8,
    visible: false,
  })
  const [tooltip, setTooltip] = createSignal({ top: 0, left: 0, placement: 'bottom' })
  const [tooltipReady, setTooltipReady] = createSignal(false)
  const [targetMissing, setTargetMissing] = createSignal(false)

  let tooltipRef: HTMLDivElement | undefined

  const steps = createMemo(() => tourSteps())
  const stepIdx = createMemo(() => spotlightStep())
  const currentStep = createMemo(() => steps()[stepIdx()])

  const isFirst = createMemo(() => stepIdx() === 0)
  const isLast = createMemo(() => stepIdx() === steps().length - 1)

  const waitForTarget = (selector: string, maxRetries = 20): Promise<HTMLElement | null> => {
    return new Promise((resolve) => {
      let attempts = 0
      const check = () => {
        const el = document.querySelector(selector) as HTMLElement
        if (el) {
          resolve(el)
          return
        }
        attempts++
        if (attempts >= maxRetries) {
          resolve(null)
          return
        }
        setTimeout(check, 100)
      }
      check()
    })
  }

  const updatePositions = () => {
    const step = currentStep()
    if (!step) return

    const selector = step.targetSelector

    if (!selector) {
      // No target — center tooltip
      setHighlight({ top: 0, left: 0, width: 0, height: 0, rx: 8, visible: false })
      const vw = window.innerWidth
      const vh = window.innerHeight
      setTooltip({
        top: vh / 2 - 100,
        left: vw / 2 - TOOLTIP_WIDTH / 2,
        placement: 'center',
      })
      setTargetMissing(false)
      setTooltipReady(true)
      return
    }

    const target = document.querySelector(selector) as HTMLElement
    if (!target) {
      setTargetMissing(true)
      setHighlight({ top: 0, left: 0, width: 0, height: 0, rx: 8, visible: false })
      return
    }

    setTargetMissing(false)
    const rect = target.getBoundingClientRect()
    const pad = 6

    setHighlight({
      top: rect.top - pad,
      left: rect.left - pad,
      width: rect.width + pad * 2,
      height: rect.height + pad * 2,
      rx: Math.min(8, (rect.height + pad * 2) / 4),
      visible: true,
    })

    const tp = bestPlacement(step, rect)
    setTooltip(tp)
    setTooltipReady(true)

    // Scroll target into view if needed
    const margin = 80
    if (rect.top < margin || rect.bottom > window.innerHeight - margin) {
      target.scrollIntoView({ behavior: 'smooth', block: 'center' })
    }
  }

  // Effect: when step changes, wait for target then update positions
  createEffect(() => {
    const step = currentStep()
    if (!step || !spotlightActive()) return

    const selector = step.targetSelector
    setTargetMissing(false)
    setTooltipReady(false)

    if (!selector) {
      setTimeout(() => {
        updatePositions()
      }, 50)
      return
    }

    // Try immediate match first (already on correct page)
    const immediate = document.querySelector(selector) as HTMLElement
    if (immediate) {
      updatePositions()
      return
    }

    // Poll for element (page might be loading)
    waitForTarget(selector).then((el) => {
      if (!el) {
        setTargetMissing(true)
        // Show tooltip centered with "coming soon" message
        const vw = window.innerWidth
        const vh = window.innerHeight
        setHighlight({ top: 0, left: 0, width: 0, height: 0, rx: 8, visible: false })
        setTooltip({
          top: vh / 2 - 100,
          left: vw / 2 - TOOLTIP_WIDTH / 2,
          placement: 'center',
        })
        setTooltipReady(true)
        return
      }
      updatePositions()
    })
  })

  // Effect: reposition on resize/scroll
  createEffect(() => {
    if (!spotlightActive()) return

    const onResize = () => {
      updatePositions()
    }
    window.addEventListener('resize', onResize)
    window.addEventListener('scroll', onResize, { passive: true })

    // Initial position after render
    setTimeout(() => {
      updatePositions()
    }, 100)

    onCleanup(() => {
      window.removeEventListener('resize', onResize)
      window.removeEventListener('scroll', onResize)
    })
  })

  // Keyboard navigation
  createEffect(() => {
    if (!spotlightActive()) return

    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'ArrowRight' || e.key === 'Enter') {
        nextSpotlightStep()
      } else if (e.key === 'ArrowLeft') {
        prevSpotlightStep()
      } else if (e.key === 'Escape') {
        endSpotlight()
      }
    }
    window.addEventListener('keydown', onKey)
    onCleanup(() => {
      window.removeEventListener('keydown', onKey)
    })
  })

  const tooltipStyle = () => {
    const t = tooltip()
    return {
      top: `${t.top}px`,
      left: `${t.left}px`,
    }
  }

  return (
    <div class={styles.overlay}>
      {/* Backdrop with cutout highlight */}
      <svg class={styles.backdropSvg} viewBox={`0 0 ${window.innerWidth} ${window.innerHeight}`}>
        <defs>
          <mask id="spotlight-mask">
            <rect width="100%" height="100%" fill="white" />
            <rect
              x={highlight().left}
              y={highlight().top}
              width={highlight().width}
              height={highlight().height}
              rx={highlight().rx}
              fill="black"
            />
          </mask>
        </defs>
        <rect width="100%" height="100%" fill="rgba(0,0,0,0.55)" mask="url(#spotlight-mask)" />
        {/* Border glow around highlight */}
        {highlight().visible && (
          <rect
            x={highlight().left}
            y={highlight().top}
            width={highlight().width}
            height={highlight().height}
            rx={highlight().rx}
            fill="none"
            stroke="var(--primary, #3b82f6)"
            stroke-width="2"
            opacity="0.8"
          />
        )}
      </svg>

      {/* Tooltip */}
      <div
        ref={tooltipRef}
        class={styles.tooltip}
        classList={{
          [styles.visible]: tooltipReady(),
          [styles.bottom]: tooltip().placement === 'bottom',
          [styles.top]: tooltip().placement === 'top',
          [styles.center]: tooltip().placement === 'center',
        }}
        style={tooltipStyle()}
      >
        {targetMissing() && currentStep().targetSelector && (
          <div class={styles.targetMissing}>
            This step's feature isn't visible on the current page. Click Next to continue, or
            navigate to the relevant page and the highlight will appear.
          </div>
        )}

        <div class={styles.stepCounter}>
          Step {stepIdx() + 1} of {steps().length}
        </div>

        <h3 class={styles.title}>{currentStep().title}</h3>
        <p class={styles.description}>{currentStep().description}</p>

        <div class={styles.actions}>
          <button class={styles.btnGhost} onClick={endSpotlight}>
            End Tour
          </button>
          <div class={styles.navActions}>
            <button class={styles.btnGhost} onClick={prevSpotlightStep} disabled={isFirst()}>
              Back
            </button>
            <button class={styles.btnPrimary} onClick={nextSpotlightStep}>
              {isLast() ? 'Finish' : 'Next'}
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

/**
 * SubscriptionCard — Beautiful branded card for subscription items.
 *
 * Follows the Categories page card pattern:
 * - Brand-colored icon box (40x40, rounded)
 * - Name + amount row
 * - Due countdown with contextual styling
 * - Category pill badge
 * - Hover-revealed action buttons
 */

/** @jsxImportSource solid-js */
import { Show } from 'solid-js'
import { formatCurrency } from '../core/api'
import { matchBrand } from '../features/subscriptionBrands'
import ConfirmButton from './ConfirmButton'
import styles from './SubscriptionCard.module.css'

export interface SubscriptionCardBill {
  id: number
  name: string
  amount: number
  due_date: string
  frequency: string
  is_active?: number
  paid?: boolean
  category?: string
  category_name?: string
  category_color?: string
  type?: string
}

interface SubscriptionCardProps {
  subscription: SubscriptionCardBill
  onMarkPaid: (id: number) => void
  onPause: (id: number) => void
  onDelete: (id: number) => void
  onEdit: (id: number) => void
  markingPaid: () => Set<number>
}

/* ── Due date helpers ── */

function dueText(dateStr: string): string {
  const target = new Date(dateStr)
  const today = new Date()
  today.setHours(0, 0, 0, 0)
  target.setHours(0, 0, 0, 0)
  const diff = Math.ceil((target.getTime() - today.getTime()) / (1000 * 60 * 60 * 24))
  if (diff < 0) return `${Math.abs(diff)}d overdue`
  if (diff === 0) return 'Due today'
  if (diff === 1) return 'Due tomorrow'
  return `Due in ${diff}d`
}

function dueClass(dateStr: string): string {
  const target = new Date(dateStr)
  const today = new Date()
  today.setHours(0, 0, 0, 0)
  target.setHours(0, 0, 0, 0)
  const diff = Math.ceil((target.getTime() - today.getTime()) / (1000 * 60 * 60 * 24))
  if (diff < 0) return styles.dueOverdue
  if (diff <= 1) return styles.dueSoon
  return styles.dueNormal
}

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
  })
}

export default function SubscriptionCard(props: SubscriptionCardProps) {
  const sub = () => props.subscription
  const brand = () => matchBrand(sub().name, sub().category_color)
  const isActive = () => sub().is_active !== 0
  const isPaying = () => props.markingPaid().has(sub().id)
  const categoryLabel = () => sub().category_name || sub().category || brand().defaultCategory

  return (
    <div class={`${styles.card} ${!isActive() ? styles.paused : ''}`}>
      {/* Top accent border color */}
      <div class={styles.accent} style={{ 'background-color': brand().color }} />

      {/* Header: icon + info */}
      <div class={styles.header}>
        <div
          class={styles.iconBox}
          style={{
            'background-color': brand().bgColor,
            color: brand().color,
          }}
        >
          {brand().icon()}
        </div>
        <div class={styles.info}>
          <h4 class={styles.name}>{brand().displayName || sub().name}</h4>
          <p class={styles.meta}>
            {sub().name !== brand().displayName && brand().displayName ? sub().name : ''}
          </p>
        </div>
        <div class={styles.amount}>
          <span class={styles.amountValue}>{formatCurrency(sub().amount)}</span>
          <span class={styles.frequency}>
            /{sub().frequency === 'monthly' ? 'mo' : sub().frequency === 'weekly' ? 'wk' : 'biwk'}
          </span>
        </div>
      </div>

      {/* Meta row: due date + category */}
      <div class={styles.metaRow}>
        <span class={`${styles.due} ${dueClass(sub().due_date)}`}>
          <svg
            width="12"
            height="12"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            stroke-width="2"
          >
            <rect x="3" y="4" width="18" height="18" rx="2" ry="2" />
            <line x1="16" y1="2" x2="16" y2="6" />
            <line x1="8" y1="2" x2="8" y2="6" />
            <line x1="3" y1="10" x2="21" y2="10" />
          </svg>
          {dueText(sub().due_date)}
          {' · '}
          {formatDate(sub().due_date)}
        </span>
        <span
          class={styles.categoryPill}
          style={{ 'background-color': brand().bgColor, color: brand().color }}
        >
          {categoryLabel()}
        </span>
      </div>

      {/* Status badge */}
      <div class={styles.statusRow}>
        <Show when={sub().paid}>
          <span class={styles.paidBadge}>Paid</span>
        </Show>
        <Show when={!isActive()}>
          <span class={styles.pausedBadge}>Paused</span>
        </Show>
      </div>

      {/* Hover-revealed actions */}
      <div class={styles.actions}>
        <button
          class={`${styles.actionBtn} ${styles.actionPrimary}`}
          onClick={() => {
            props.onMarkPaid(sub().id)
          }}
          disabled={isPaying()}
        >
          {isPaying() ? 'Paying...' : 'Mark Paid'}
        </button>
        <Show
          when={isActive()}
          fallback={
            <button
              class={`${styles.actionBtn} ${styles.actionPrimary}`}
              onClick={() => {
                props.onPause(sub().id)
              }}
              title="Resume subscription"
            >
              Resume
            </button>
          }
        >
          <button
            class={`${styles.actionBtn} ${styles.actionGhost}`}
            onClick={() => {
              props.onPause(sub().id)
            }}
            title="Pause subscription"
          >
            Pause
          </button>
        </Show>
        <button
          class={`${styles.actionBtn} ${styles.actionGhost}`}
          onClick={() => {
            props.onEdit(sub().id)
          }}
          title="Edit subscription"
        >
          Edit
        </button>
        <ConfirmButton
          class={`${styles.actionBtn} ${styles.actionGhost}`}
          onConfirm={() => {
            props.onDelete(sub().id)
          }}
          label="Delete"
        />
      </div>
    </div>
  )
}

/**
 * Tag Chips Component
 * Displays tags as clickable chips with optional remove buttons
 */
import { createMemo, For, Show } from 'solid-js'
import tagChipsStyles from './TagChips.module.css'

export interface TagChipsProps {
  tags: () => string[]
  onRemove?: (tag: string) => void
  editable?: boolean
  maxSize?: number
  pill?: boolean
}

export function TagChips(props: TagChipsProps) {
  const displayedTags = createMemo(() => {
    const tags = props.tags()
    return props.maxSize && props.maxSize > 0 ? tags.slice(0, props.maxSize) : tags
  })

  return (
    <Show when={displayedTags().length > 0}>
      <div class={tagChipsStyles.tagChips}>
        <Show when={displayedTags().length > (props.maxSize || 0)}>
          <span class={tagChipsStyles.moreTags}>
            +{displayedTags().length - (props.maxSize || 0)} more
          </span>
        </Show>
        <For each={displayedTags()}>
          {(tag) => (
            <span class={`${tagChipsStyles.tagChip} ${props.pill ? tagChipsStyles.pill : ''}`}>
              {tag}
              <Show when={props.editable && props.onRemove}>
                <button
                  class={tagChipsStyles.removeButton}
                  onClick={() => props.onRemove?.(tag)}
                  aria-label={`Remove tag ${tag}`}
                  type="button"
                >
                  ×
                </button>
              </Show>
            </span>
          )}
        </For>
      </div>
    </Show>
  )
}

export default function TagChipsDefault(props: TagChipsProps) {
  return <TagChips {...props} />
}

/**
 * Tag Filter Component
 * Dropdown filter for filtering transactions by tags
 */
import { createEffect, createMemo, createSignal, For, Show } from 'solid-js'
import tagFilterStyles from './TagFilter.module.css'

export interface TagFilterProps {
  availableTags: () => string[]
  selectedTags: () => Set<string>
  onToggle: (tag: string) => void
  onClear: () => void
}

export function TagFilter(props: TagFilterProps) {
  const [isOpen, setIsOpen] = createSignal(false)
  const [filterText, setFilterText] = createSignal('')

  // Reactive: recompute when parent signals change (prevents frozen-at-mount values)
  const tags = createMemo(() => props.availableTags())
  const selectedTags = createMemo(() => props.selectedTags())

  const filteredTags = () => {
    if (!filterText()) return tags()
    return tags().filter((tag) => tag.toLowerCase().includes(filterText().toLowerCase()))
  }

  const selectedCount = () => selectedTags().size

  const allSelected = () => {
    return selectedTags().size === tags().length && tags().length > 0
  }

  const anySelected = () => selectedTags().size > 0

  createEffect(() => {
    if (!isOpen()) {
      setFilterText('')
    }
  })

  return (
    <div class={tagFilterStyles.tagFilterContainer}>
      <div class={tagFilterStyles.filterButton} onClick={() => setIsOpen(!isOpen())}>
        <span class={tagFilterStyles.filterLabel}>Filter by tags:</span>
        <span class={tagFilterStyles.filterCount}>
          {anySelected() ? `${selectedCount()} selected` : ''}
        </span>
      </div>

      <Show when={isOpen()}>
        <div class={tagFilterStyles.dropdown}>
          <div class={tagFilterStyles.searchContainer}>
            <input
              class={tagFilterStyles.searchInput}
              type="text"
              placeholder="Search tags..."
              onInput={(e) => setFilterText(e.currentTarget.value)}
            />
            <button
              class={tagFilterStyles.clearSearch}
              onClick={() => setFilterText('')}
              aria-label="Clear search"
              type="button"
            >
              ×
            </button>
          </div>

          <div class={tagFilterStyles.tagList}>
            <div class={tagFilterStyles.selectAllRow}>
              <button
                class={tagFilterStyles.selectAllButton}
                onClick={() => {
                  if (allSelected()) {
                    props.onClear()
                  } else {
                    tags().forEach((tag) => {
                      props.onToggle(tag)
                    })
                  }
                }}
                type="button"
              >
                {allSelected() ? 'Deselect All' : 'Select All'}
              </button>
            </div>

            <For each={filteredTags()}>
              {(tag) => {
                const isSelected = () => selectedTags()?.has(tag) ?? false
                return (
                  <div class={tagFilterStyles.tagItem}>
                    <button
                      class={`${tagFilterStyles.tagCheckbox} ${isSelected() ? tagFilterStyles.selected : ''}`}
                      onClick={() => {
                        if (selectedTags()) props.onToggle(tag)
                      }}
                      type="button"
                    >
                      <span class={tagFilterStyles.checkboxIndicator}>
                        <svg
                          width="12"
                          height="12"
                          viewBox="0 0 12 12"
                          fill="none"
                          stroke="white"
                          stroke-width="2"
                        >
                          <polyline points="2 6 4.5 8.5 10 2.5" />
                        </svg>
                      </span>
                    </button>
                    <span class={tagFilterStyles.tagName}>{tag}</span>
                  </div>
                )
              }}
            </For>

            <Show when={filteredTags().length === 0}>
              <div class={tagFilterStyles.noResults}>No tags found</div>
            </Show>
          </div>

          <div class={tagFilterStyles.footer}>
            <button class={tagFilterStyles.clearButton} onClick={props.onClear} type="button">
              Clear Selection
            </button>
          </div>
        </div>
      </Show>
    </div>
  )
}

