// ── HTTP verb helpers ─────────────────────────────────────────────────────────

function getProfileIdForHeaders(): string {
  const id = localStorage.getItem('currentProfileId')
  return (id !== null ? parseInt(id, 10) : 1).toString()
}

function getHeaders(): Record<string, string> {
  return {
    'Content-Type': 'application/json',
    'X-Profile-Id': getProfileIdForHeaders(),
  }
}

async function parseJsonResponse<T>(response: Response): Promise<T> {
  const contentType = response.headers.get('content-type')
  if (contentType !== null && contentType.includes('application/json')) {
    const data = (await response.json()) as T
    if (!response.ok) {
      const errorData = data as { error?: string } | undefined
      throw new Error(errorData?.error || `Request failed with status ${response.status}`)
    }
    return data
  }
  throw new Error('Invalid response format')
}

export async function apiGet<T = unknown>(url: string): Promise<T> {
  const response = await apiFetch(url, {
    credentials: 'include',
    method: 'GET',
    headers: getHeaders(),
  })
  if (!response.ok) throw new Error(`Request failed with status ${response.status}`)
  return parseJsonResponse<T>(response)
}

export async function apiPost<T = unknown>(
  url: string,
  body: unknown,
  options?: RequestInit
): Promise<T> {
  const response = await apiFetch(url, {
    credentials: 'include',
    method: 'POST',
    headers: getHeaders(),
    body: JSON.stringify(body),
    ...options,
  })
  if (!response.ok) throw new Error(`Request failed with status ${response.status}`)
  return parseJsonResponse<T>(response)
}

export async function apiPut<T = unknown>(
  url: string,
  body: unknown,
  options?: RequestInit
): Promise<T> {
  const response = await apiFetch(url, {
    credentials: 'include',
    method: 'PUT',
    headers: getHeaders(),
    body: JSON.stringify(body),
    ...options,
  })
  if (!response.ok) throw new Error(`Request failed with status ${response.status}`)
  return parseJsonResponse<T>(response)
}

export async function apiDelete<T = unknown>(url: string): Promise<T> {
  const response = await apiFetch(url, {
    credentials: 'include',
    method: 'DELETE',
    headers: { 'X-Profile-Id': getProfileIdForHeaders() },
  })
  if (!response.ok) throw new Error(`Request failed with status ${response.status}`)
  return parseJsonResponse<T>(response)
}

/**
 * API Fetch Interceptor
 * Routes API calls to either the real backend (self-hosted) or IndexedDB (serverless)
 */
import { getStorageMode } from './storage/storageFactory'
import type { StorageMode } from './storage/storageFactory'

// We lazy-import to avoid circular deps and to only load IndexedDB when needed
let _localApiRouter: ((url: string, init?: RequestInit) => Promise<Response>) | null = null

async function getLocalRouter(): Promise<(url: string, init?: RequestInit) => Promise<Response>> {
  if (!_localApiRouter) {
    const mod = await import('./storage/localApiRouter')
    _localApiRouter = mod.routeApiRequest
  }
  return _localApiRouter
}

/**
 * Replacement for window.fetch that intercepts /api/* calls in serverless mode.
 * In self-hosted mode, passes through to the real fetch.
 */
export async function apiFetch(url: string, init?: RequestInit): Promise<Response> {
  const mode: StorageMode = getStorageMode()

  // Self-hosted: use real fetch
  if (mode === 'self-hosted') {
    return fetch(url, init)
  }

  // Serverless: intercept /api/* calls
  if (url.startsWith('/api')) {
    const router = await getLocalRouter()
    return router(url, init)
  }

  // Non-API calls (CDN, external) pass through
  return fetch(url, init)
}

/**
 * Authentication module - handles login/logout and auth state
 */

import { api } from './api.js'

/**
 * Auth store - handles authentication state
 */
export class AuthStore {
  private isAuthenticated = false
  private currentUser: { username?: string; profile_id?: number } | null = null

  /**
   * Check if user is logged in
   */
  async checkLogin(): Promise<boolean> {
    try {
      await api.checkLogin()
      this.isAuthenticated = true
      return true
    } catch {
      this.isAuthenticated = false
      return false
    }
  }

  /**
   * Login with username and password
   */
  async login(username: string, password: string): Promise<void> {
    try {
      await api.login(username, password)
      this.isAuthenticated = true
      await this.checkLogin()
    } catch (error) {
      this.isAuthenticated = false
      throw error
    }
  }

  /**
   * Logout
   */
  async logout(): Promise<void> {
    try {
      await api.logout()
    } catch (error) {
      console.error('Logout error:', error)
    } finally {
      this.isAuthenticated = false
      this.currentUser = null
    }
  }

  /**
   * Get current user info
   */
  getCurrentUser(): { username?: string; profile_id?: number } | null {
    return this.currentUser
  }

  /**
   * Get auth status
   */
  isLoggedIn(): boolean {
    return this.isAuthenticated
  }
}

// Export singleton instance
export const auth = new AuthStore()

// Initialize auth on load
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', async () => {
    await auth.checkLogin()
  })
}

/**
 * Shared confirm dialog store — signal-based, similar to toastStore
 */
import { createRoot, createSignal } from 'solid-js'

export interface ConfirmRequest {
  id: number
  message: string
  resolve: (value: boolean) => void
}

let nextId = 0

const { confirmRequests, setConfirmRequests } = createRoot(() => {
  const [confirmRequests, setConfirmRequests] = createSignal<ConfirmRequest[]>([])
  return { confirmRequests, setConfirmRequests }
})

export { confirmRequests }

export function showConfirm(message: string): Promise<boolean> {
  return new Promise((resolve) => {
    const id = ++nextId
    setConfirmRequests((prev) => [...prev, { id, message, resolve }])
  })
}

export function resolveConfirm(id: number, value: boolean): void {
  const req = confirmRequests().find((r) => r.id === id)
  if (req) req.resolve(value)
  setConfirmRequests((prev) => prev.filter((r) => r.id !== id))
}

/**
 * Loan Calculator with variable rate periods and prepayments
 * Ported from backend/models/loanCalculator.js for client-only/serverless mode.
 */

interface RatePeriod {
  rate: number
  start_month: number
  end_month?: number | null
}

interface Prepayment {
  month: number
  amount: number
  note?: string
}

interface ScheduleRow {
  month: number
  date: string
  payment: number
  principal: number
  interest: number
  balance: number
  prepayment: number
  rate: number
  note: string
}

interface Summary {
  totalPaid: number
  totalInterest: number
  interestSaved: number
  monthsSaved: number
  payoffDate: string | null
  totalPayments: number
  avgMonthlyPayment: number
  maxBalance: number
  originalTotalInterest: number
  originalTotalPayments: number
}

export function calcMonthlyPayment(principal: number, annualRate: number, months: number): number {
  if (annualRate === 0) return principal / months
  const r = annualRate / 100 / 12
  return (principal * (r * Math.pow(1 + r, months))) / (Math.pow(1 + r, months) - 1)
}

export function calculateSchedule(
  principal: number,
  startDate: string,
  termMonths: number,
  ratePeriods: RatePeriod[],
  prepayments: Prepayment[] = []
): ScheduleRow[] {
  const sortedRates = [...ratePeriods].sort((a, b) => a.start_month - b.start_month)
  const sortedPrepayments = [...prepayments].sort((a, b) => a.month - b.month)

  const schedule: ScheduleRow[] = []
  let balance = principal
  let monthIndex = 0
  let lockedPayment: number | null = null

  while (balance > 0.01 && monthIndex < termMonths * 2) {
    monthIndex++

    let currentRate = 0
    for (const rp of sortedRates) {
      if (rp.start_month <= monthIndex) {
        if (!rp.end_month || monthIndex <= rp.end_month) {
          currentRate = rp.rate
        }
      }
    }

    const prepayment = sortedPrepayments.find((p) => p.month === monthIndex)
    const prepayAmount = prepayment ? prepayment.amount : 0

    const remainingMonths = termMonths - monthIndex + 1
    if (remainingMonths <= 0) break

    if (prepayment || lockedPayment === null) {
      lockedPayment = calcMonthlyPayment(balance, currentRate, remainingMonths)
    }

    const interestPortion = balance * (currentRate / 100 / 12)
    let principalPortion = lockedPayment - interestPortion

    if (prepayment) {
      principalPortion += prepayAmount
    }

    if (principalPortion > balance) {
      principalPortion = balance
    }

    balance = Math.max(0, balance - principalPortion)

    const d = new Date(startDate)
    d.setMonth(d.getMonth() + monthIndex - 1)
    const monthDate = d.toISOString().split('T')[0]

    schedule.push({
      month: monthIndex,
      date: monthDate,
      payment: lockedPayment,
      principal: principalPortion - (prepayment ? prepayAmount : 0),
      interest: interestPortion,
      balance,
      prepayment: prepayAmount || 0,
      rate: currentRate,
      note: prepayment ? prepayment.note || '' : '',
    })
  }

  return schedule
}

export function calculateScheduleNoPrepayments(
  principal: number,
  startDate: string,
  termMonths: number,
  ratePeriods: RatePeriod[]
): ScheduleRow[] {
  return calculateSchedule(principal, startDate, termMonths, ratePeriods, [])
}

export function totalInterest(schedule: ScheduleRow[]): number {
  return schedule.reduce((sum, row) => sum + row.interest, 0)
}

export function totalPaid(schedule: ScheduleRow[]): number {
  return schedule.reduce((sum, row) => sum + row.payment + row.prepayment, 0)
}

export function payoffDate(schedule: ScheduleRow[]): string | null {
  if (schedule.length === 0) return null
  return schedule[schedule.length - 1].date
}

export function interestSaved(
  originalSchedule: ScheduleRow[],
  prepaySchedule: ScheduleRow[]
): number {
  return totalInterest(originalSchedule) - totalInterest(prepaySchedule)
}

export function monthsSaved(
  originalSchedule: ScheduleRow[],
  prepaySchedule: ScheduleRow[]
): number {
  const saved = interestSaved(originalSchedule, prepaySchedule)
  const monthlyPayment = originalSchedule.length > 0 ? originalSchedule[0].payment : 1
  const equivMonths = Math.round(saved / monthlyPayment)
  const eliminatedMonths = originalSchedule.length - prepaySchedule.length
  return Math.max(equivMonths, eliminatedMonths)
}

export function getSummary(schedule: ScheduleRow[], originalSchedule: ScheduleRow[]): Summary {
  const originalInterest = totalInterest(originalSchedule)
  const newInterest = totalInterest(schedule)
  const originalMonths = originalSchedule.length

  return {
    totalPaid: totalPaid(schedule),
    totalInterest: newInterest,
    interestSaved: originalInterest - newInterest,
    monthsSaved: monthsSaved(originalSchedule, schedule),
    payoffDate: payoffDate(schedule),
    totalPayments: schedule.length,
    avgMonthlyPayment:
      schedule.length > 0 ? schedule.reduce((s, r) => s + r.payment, 0) / schedule.length : 0,
    maxBalance: schedule.length > 0 ? schedule[0].balance : 0,
    originalTotalInterest: originalInterest,
    originalTotalPayments: originalMonths,
  }
}

/**
 * Centralized Logging System
 * Logs to both console and localStorage so you can view logs on mobile devices
 * where console access is limited
 */

export type LogLevel = 'debug' | 'info' | 'warn' | 'error'

export interface LogEntry {
  timestamp: string
  level: LogLevel
  message: string
  details?: unknown
  component?: string
}

const STORAGE_KEY = 'app_logs'
const MAX_LOGS = 500

// In-memory buffer for logs
let logBuffer: LogEntry[] = []
let isInitialized = false

/**
 * Get all logs from localStorage
 */
function getLogsFromStorage(): LogEntry[] {
  try {
    const stored = localStorage.getItem(STORAGE_KEY)
    if (stored) {
      return JSON.parse(stored)
    }
  } catch {
    // Storage might be disabled or corrupted
  }
  return []
}

/**
 * Save logs to localStorage
 */
function saveLogsToStorage(logs: LogEntry[]): void {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(logs))
  } catch {
    // Ignore storage errors
  }
}

/**
 * Create a log entry
 */
function createLogEntry(
  level: LogLevel,
  message: string,
  details?: unknown,
  component?: string
): LogEntry {
  const timestamp = new Date().toISOString()
  return { timestamp, level, message, details, component }
}

/**
 * Add a log entry to both buffer and storage
 */
function addLogEntry(entry: LogEntry): void {
  logBuffer.push(entry)

  // Periodically flush to storage (every 10 logs or on error)
  if (entry.level === 'error' || logBuffer.length >= MAX_LOGS || logBuffer.length % 10 === 0) {
    flushLogs()
  }
}

/**
 * Write logs to console
 */
function writeLogToConsole(entry: LogEntry): void {
  const { timestamp, level, message, details } = entry
  const timestampFmt = new Date(timestamp).toLocaleTimeString()
  const debugMode = isDebugMode()

  switch (level) {
    case 'debug':
      if (debugMode) {
        console.info(`[${timestampFmt}] [DEBUG] ${message}`, details ?? '')
      }
      break
    case 'info':
      if (debugMode) {
        console.info(`[${timestampFmt}] [INFO] ${message}`, details ?? '')
      }
      break
    case 'warn':
      if (debugMode) {
        console.warn(`[${timestampFmt}] [WARN] ${message}`, details ?? '')
      }
      break
    case 'error':
      console.error(`[${timestampFmt}] [ERROR] ${message}`, details ?? '')
      break
  }
}

/**
 * Check if debug mode is enabled
 */
function isDebugMode(): boolean {
  try {
    return localStorage.getItem('debugMode') === 'true'
  } catch {
    return false
  }
}

/**
 * Flush logs to localStorage
 */
function flushLogs(): void {
  try {
    const allLogs = getLogsFromStorage()
    const newLogs = logBuffer.concat(allLogs)

    // Sort by timestamp (newest first)
    newLogs.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())

    // Keep only the last MAX_LOGS
    const trimmedLogs = newLogs.slice(0, MAX_LOGS)

    saveLogsToStorage(trimmedLogs)

    // Write to console
    trimmedLogs.forEach(writeLogToConsole)

    // Clear buffer
    logBuffer = []
  } catch {
    // Ignore errors
  }
}

/**
 * Clear all logs
 */
function clearLogs(): void {
  logBuffer = []
  localStorage.removeItem(STORAGE_KEY)
}

/**
 * Get filtered logs
 */
function getLogs(
  filter?: {
    level?: LogLevel[]
    component?: string
    startDate?: string
    endDate?: string
  },
  limit?: number
): LogEntry[] {
  let logs = getLogsFromStorage()

  if (filter?.level && filter.level.length > 0) {
    logs = logs.filter((log) => filter.level!.includes(log.level))
  }

  if (filter?.component) {
    logs = logs.filter((log) => log.component === filter.component)
  }

  if (filter?.startDate) {
    logs = logs.filter((log) => new Date(log.timestamp) >= new Date(filter.startDate!))
  }

  if (filter?.endDate) {
    logs = logs.filter((log) => new Date(log.timestamp) <= new Date(filter.endDate!))
  }

  if (limit) {
    logs = logs.slice(0, limit)
  }

  return logs
}

/**
 * Get log statistics
 */
function getLogStats(): {
  total: number
  errors: number
  warnings: number
  infos: number
  debugs: number
  last24h: number
  last7d: number
} {
  const logs = getLogsFromStorage()

  const errorLogs = logs.filter((log) => log.level === 'error')
  const warnLogs = logs.filter((log) => log.level === 'warn')
  const infoLogs = logs.filter((log) => log.level === 'info')
  const debugLogs = logs.filter((log) => log.level === 'debug')

  const now = new Date()
  const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000)
  const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000)

  const last24h = logs.filter((log) => new Date(log.timestamp) >= yesterday).length

  const last7d = logs.filter((log) => new Date(log.timestamp) >= weekAgo).length

  return {
    total: logs.length,
    errors: errorLogs.length,
    warnings: warnLogs.length,
    infos: infoLogs.length,
    debugs: debugLogs.length,
    last24h,
    last7d,
  }
}

// ============ PUBLIC API ============

/**
 * Initialize logging system
 */
export function initLogging(): void {
  if (isInitialized) return
  isInitialized = true

  // Load existing logs
  const existingLogs = getLogsFromStorage()
  logBuffer = existingLogs

  // Log initialization
  log('info', 'Logging system initialized')

  // Flush any pending logs to localStorage
  if (logBuffer.length > 0) {
    flushLogs()
  }
}

/**
 * Add a log entry
 */
export function log(level: LogLevel, message: string, details?: unknown, component?: string): void {
  const entry = createLogEntry(level, message, details, component)
  addLogEntry(entry)
  writeLogToConsole(entry)
}

/**
 * Debug log
 */
export function debug(message: string, details?: unknown, component?: string): void {
  log('debug', message, details, component)
}

/**
 * Info log
 */
export function info(message: string, details?: unknown, component?: string): void {
  log('info', message, details, component)
}

/**
 * Warning log
 */
export function warn(message: string, details?: unknown, component?: string): void {
  log('warn', message, details, component)
}

/**
 * Error log
 */
export function error(message: string, details?: unknown, component?: string): void {
  log('error', message, details, component)
}

/**
 * Error with full stack trace
 */
export function errorWithStack(message: string, error: unknown, component?: string): void {
  let details: Record<string, unknown> = { message }

  if (error instanceof Error) {
    details = {
      message: error.message,
      stack: error.stack,
      name: error.name,
    }
  } else if (typeof error === 'object' && error !== null) {
    details = error as Record<string, unknown>
  }

  log('error', message, details, component)
}

/**
 * Set debug mode
 */
export function setDebugMode(enabled: boolean): void {
  try {
    localStorage.setItem('debugMode', enabled ? 'true' : 'false')
    log('info', `Debug mode ${enabled ? 'enabled' : 'disabled'}`)
  } catch {
    // Ignore errors
  }
}

/**
 * Check debug mode status
 */
export function isDebugging(): boolean {
  return isDebugMode()
}

// Export all utility functions
export const logger = {
  init: initLogging,
  log,
  debug,
  info,
  warn,
  error,
  errorWithStack,
  clear: clearLogs,
  getLogs,
  getStats: getLogStats,
  setDebugMode,
  isDebugMode: isDebugging,
}

