    const withdrawalRate = parseFloat(query.get('withdrawalRate') || query.get('rate') || '4') || 4
    const country = query.get('country') || 'US'

    const result = calculateRetirementProjection(
      currentAge,
      retirementAge,
      currentSavings,
      monthlyContribution,
      annualReturn,
      withdrawalRate,
