  async getBalanceHistory(accountId: number): Promise<BalanceEntry[]> {
    const response = await fetch(`/api/accounts/${accountId}/history`, {
      method: 'GET',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
    })

    if (!response.ok) {
      throw new Error('Failed to get balance history')
    }

    const data = await response.json()
    return data || []
  }

  async recordBalance(accountId: number, balance: number): Promise<number> {
    const response = await fetch(`/api/accounts/${accountId}/history`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ balance }),
    })

    if (!response.ok) {
      throw new Error('Failed to record balance')
    }

    return (await response.json()).id
  }

  // Settings
  async getSettings(): Promise<Settings> {
    const response = await fetch('/api/settings', {
      method: 'GET',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
    })

    if (!response.ok) {
      throw new Error('Failed to get settings')
    }

    return response.json()
  }

  async updateSettings(settings: Partial<Settings>): Promise<void> {
    await fetch('/api/settings', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify(settings),
    })
  }

  // Transaction (ACID)
  async transaction<T>(callback: (tx: StorageAdapter) => Promise<T>): Promise<T> {
    // For self-hosted, we rely on the backend for transactions
    return callback(this)
  }

  // Export/Import
  async exportData(): Promise<ExportData> {
    const response = await fetch('/api/export', {
      method: 'GET',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
    })

    if (!response.ok) {
      throw new Error('Failed to export data')
    }

    return response.json()
  }

  async importData(data: ExportData): Promise<void> {
    const response = await fetch('/api/import', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify(data),
    })

    if (!response.ok) {
      throw new Error('Failed to import data')
    }
  }

  // Cleanup
  async clearAllData(): Promise<void> {
    await fetch('/api/clear-all', {
      method: 'DELETE',
      credentials: 'include',
    })
  }
}

/**
 * Theme module - handles light/dark theme switching
 */

const THEME_STORAGE_KEY = 'finance-theme'

type Theme = 'light' | 'dark'

/**
 * Theme store - handles theme state and CSS variable updates
 */
export class ThemeStore {
  private currentTheme: Theme = 'dark'

  /**
   * Check if dark theme is active
   */
  isDark(): boolean {
    return document.documentElement.getAttribute('data-theme') === 'dark'
  }

  /**
   * Get current theme
   */
  getTheme(): Theme {
    return this.currentTheme
  }

  /**
   * Set theme
   */
  setTheme(theme: Theme): void {
    this.currentTheme = theme
    document.documentElement.setAttribute('data-theme', theme)
    localStorage.setItem(THEME_STORAGE_KEY, theme)
    // Trigger chart refreshes
    this.refreshCharts()
  }

  /**
   * Toggle between light and dark theme
   */
  toggle(): void {
    const newTheme = this.isDark() ? 'light' : 'dark'
    this.setTheme(newTheme)
  }

  /**
   * Initialize theme from localStorage
   */
  init(): void {
    const saved = localStorage.getItem(THEME_STORAGE_KEY) as Theme | null
    const themeToUse = saved || 'dark'
    this.currentTheme = themeToUse
    document.documentElement.setAttribute('data-theme', themeToUse)
  }

  /**
   * Get chart colors based on current theme
   */
  getChartColors() {
    const cs = window.getComputedStyle(document.documentElement)
    return {
      income: '#22c55e',
      expense: '#ef4444',
      transfer: '#6366f1',
      primary: '#3b82f6',
      incomeBg: 'rgba(34,197,94,.2)',
      expenseBg: 'rgba(239,68,68,.2)',
      primaryBg: 'rgba(59,130,246,.15)',
      grid:
        cs.getPropertyValue('--chart-grid').trim() ||
        (this.isDark() ? 'rgba(255,255,255,.06)' : 'rgba(0,0,0,.06)'),
      text: cs.getPropertyValue('--text').trim(),
      textSecondary: cs.getPropertyValue('--text-secondary').trim(),
      border: cs.getPropertyValue('--border').trim(),
      legend: cs.getPropertyValue('--text').trim(),
    }
  }

  /**
   * Refresh charts after theme change
   * This is a placeholder - actual implementation would call chart refresh methods
   */
  private refreshCharts(): void {
    // Called when theme changes to refresh charts
    // Implementation would depend on which charts are loaded
  }
}

// Export singleton instance
export const theme = new ThemeStore()

// Initialize theme on load
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', () => {
    theme.init()
  })
} else {
  theme.init()
}

/**
 * Shared toast store — signal-based, no DOM manipulation needed
 */
import { createRoot, createSignal } from 'solid-js'

export interface ToastItem {
  id: number
  message: string
  type: 'success' | 'error' | 'info' | 'warning'
}

let nextId = 0

const { toasts, setToasts } = createRoot(() => {
  const [toasts, setToasts] = createSignal<ToastItem[]>([])
  return { toasts, setToasts }
})

export { toasts }

export function addToast(message: string, type: ToastItem['type'] = 'info'): void {
  const id = ++nextId
  setToasts((prev) => [...prev, { id, message, type }])
  setTimeout(() => {
    setToasts((prev) => prev.filter((t) => t.id !== id))
  }, 4000)
}

