                      >
                        {data()!.savingsRate >= 20
                          ? 'Above target'
                          : data()!.savingsRate >= 10
                            ? 'Below target'
                            : 'Critical'}
                      </span>
                    </div>
                  </div>
                </div>
                <div class={styles.savingsTips}>
                  <h4>Tips to Improve Savings</h4>
                  <ul>
                    {data()!.savingsRate < 20 && (
                      <li>
                        <strong>Reduce discretionary spending:</strong> Review subscriptions and
                        optional expenses
                      </li>
                    )}
                    {data()!.savingsRate < 10 && (
                      <>
                        <li>
                          <strong>Increase income:</strong> Consider side gigs or ask for a raise
                        </li>
                        <li>
                          <strong>Lower bills:</strong> Compare insurance rates and reduce energy
                          usage
                        </li>
                      </>
                    )}
                    <li>
                      <strong>Use the 50/30/20 rule:</strong> 50% needs, 30% wants, 20% savings
                    </li>
                    <li>
                      <strong>Build an emergency fund:</strong> Start with 3-6 months of expenses
                    </li>
                  </ul>
                </div>
              </div>
            </div>
          </div>

          {/* Top Categories Breakdown - Full Width */}
          {data()!.byCategory.length > 0 && (
            <div class={styles.chartsFullWidth}>
              <div class={styles.analyticsChart}>
                <h3 class={styles.chartTitle}>Top Categories Breakdown</h3>
                <div class={styles.chartContainer}>
                  <div class={styles.categoryBars}>
                    {(() => {
                      const total =
                        data()!.byCategory.reduce(
                          (s: number, c: { amount: number }) => s + c.amount,
                          0
                        ) || 1
                      return (
                        <For each={data()!.byCategory}>
                          {(item) => {
                            const pct = ((item.amount / total) * 100).toFixed(1)
                            return (
                              <div class={styles.categoryBarItem}>
                                <div class={styles.barInfo}>
                                  <div class={styles.barName}>{item.category_name}</div>
                                  <div class={styles.barPercent}>{pct}%</div>
                                </div>
                                <div class={styles.barTrack}>
                                  <div
                                    class={styles.barFill}
                                    style={{ width: `${Math.min(Number(pct), 100)}%` }}
                                  />
                                </div>
                                <div class={styles.barAmount}>{formatAmount(item.amount)}</div>
                              </div>
                            )
                          }}
                        </For>
                      )
                    })()}
                  </div>
                  {/* Averages */}
                  <div
                    style={{
                      margin: '20px 0 0',
                      display: 'flex',
                      gap: '20px',
                      'flex-wrap': 'wrap',
                      'border-top': '1px solid var(--border)',
                      'padding-top': '16px',
                    }}
                  >
                    {(() => {
                      const total = data()!.byCategory.reduce(
                        (s: number, c: { amount: number }) => s + c.amount,
                        0
                      )
                      const count = data()!.byCategory.length
                      const avg = count > 0 ? total / count : 0
                      const monthly = total / 6
                      const daily = monthly / 30
                      return (
                        <>
                          <div>
                            <div class={styles.statLabel}>Total {categoryType()}</div>
                            <div class={styles.statValue}>{formatAmount(total)}</div>
                          </div>
                          <div>
                            <div class={styles.statLabel}>Monthly Average</div>
                            <div class={styles.statValue}>{formatAmount(monthly)}</div>
                          </div>
                          <div>
                            <div class={styles.statLabel}>Daily Average</div>
                            <div class={styles.statValue}>{formatAmount(daily)}</div>
                          </div>
                          <div>
                            <div class={styles.statLabel}>Per-Category Avg</div>
                            <div class={styles.statValue}>{formatAmount(avg)}</div>
                          </div>
                        </>
                      )
                    })()}
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Recent Transactions */}
          <div class={styles.analyticsRecent}>
            <h3 class={styles.sectionTitle}>Recent Transactions</h3>
            <div class={styles.transactionList}>
              <For each={data()!.recentTransactions}>
                {(tx: Transaction) => (
                  <div class={styles.transactionItem}>
                    <div
                      class={styles.transactionIcon}
                      style={{
                        background: tx.type === 'expense' ? 'var(--danger)' : 'var(--income)',
                      }}
                    >
                      {tx.type === 'expense' ? '↓' : '↑'}
                    </div>
                    <div class={styles.transactionDetails}>
                      <div class={styles.transactionName}>{tx.description}</div>
                      <div class={styles.transactionMeta}>
                        {new Date(tx.date).toLocaleDateString()} •{' '}
                        {tx.category_name || 'No category'}
                      </div>
                    </div>
                    <div
                      class={`${styles.transactionAmount} ${tx.type === 'expense' ? styles.expense : styles.income}`}
                    >
                      {tx.type === 'expense' ? '-' : '+'}
                      {formatAmount(tx.amount)}
                    </div>
                  </div>
                )}
              </For>
            </div>
            <div class={styles.viewAllLink}>
              <a href="#transactions">View All Transactions →</a>
            </div>
          </div>
        </>
      )}
    </div>
  )
}

/**
 * BillCalendar — Monthly calendar view of bills
 *
 * GIVEN: A user is viewing the Bills page with the Calendar tab active
 * WHEN: The calendar loads
 * THEN: A monthly grid displays with day headers (Sun–Sat) and bill dots on due dates
 *
 * GIVEN: The user clicks a day with bills
 * WHEN: The day is selected
 * THEN: A popover/sidebar shows bill details for that day with mark-paid and edit actions
 *
 * GIVEN: The user is viewing a month
 * WHEN: They click the prev/next arrows
 * THEN: The calendar navigates to the previous/next month
 *
 * GIVEN: A bill is overdue
 * WHEN: The calendar renders
 * THEN: The bill dot shows in red (--danger color) with an overdue indicator
 */
import { createMemo, createResource, createSignal, For, Show } from 'solid-js'
import ConfirmButton from '../components/ConfirmButton'
import { formatCurrency, apiGet, apiPost, apiPut, apiDelete, showToast } from '../core/api'
import { useAppState } from '../core/appStore'
import styles from './BillCalendar.module.css'
import type { Component } from 'solid-js'

interface CalendarBill {
  id: number
  name: string
  amount: number
  frequency: string
  category_name?: string
  category_color?: string
  category_id?: number | null
  date: string
  paid: boolean
  type: 'bill' | 'subscription'
  is_overdue: boolean
}

interface CalendarDay {
  bills: CalendarBill[]
}

interface CalendarData {
  year: number
  month: number
  monthLabel: string
  firstDow: number
  days: Record<string, CalendarBill[]>
  summary: {
    totalAmount: number
    paidAmount: number
    billCount: number
  }
}

interface Category {
  id: number
  name: string
  type: 'expense' | 'income'
  color: string
}

interface BillCalendarProps {
  onRefresh?: () => void
}

const WEEKDAYS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

const BillCalendar: Component<BillCalendarProps> = (props) => {
  const state = useAppState()

  const [currentYear, setCurrentYear] = createSignal(new Date().getFullYear())
  const [currentMonth, setCurrentMonth] = createSignal(new Date().getMonth() + 1)
  const [selectedDay, setSelectedDay] = createSignal<number | null>(null)
  const [selectedBills, setSelectedBills] = createSignal<CalendarBill[]>([])
  const [markingPaid, setMarkingPaid] = createSignal(new Set<number>())
  const [popoverStyle, setPopoverStyle] = createSignal<Record<string, string>>({})

  const [calendarData, { refetch: refetchCalendar, mutate: mutateCalendar }] =
    createResource(
      () => ({ year: currentYear(), month: currentMonth(), v: state.profileVersion }),
      async ({ year, month }) => {
        const data = await apiGet<CalendarData>(
          `/api/bills/calendar?year=${year}&month=${month}`
        )
        return data
      }
    )

  const loading = () => calendarData.loading && !calendarData()

  const prevMonth = () => {
    if (currentMonth() === 1) {
      setCurrentMonth(12)
      setCurrentYear(currentYear() - 1)
    } else {
      setCurrentMonth(currentMonth() - 1)
    }
    setSelectedDay(null)
  }

  const nextMonth = () => {
    if (currentMonth() === 12) {
      setCurrentMonth(1)
      setCurrentYear(currentYear() + 1)
    } else {
      setCurrentMonth(currentMonth() + 1)
    }
    setSelectedDay(null)
  }

  const goToToday = () => {
    const now = new Date()
    setCurrentYear(now.getFullYear())
    setCurrentMonth(now.getMonth() + 1)
    setSelectedDay(null)
  }

  const daysArray = createMemo(() => {
    const data = calendarData()
    if (!data) return []
    const lastDay = new Date(data.year, data.month, 0).getDate()
    return Array.from({ length: lastDay }, (_, i) => i + 1)
  })

  const isToday = (day: number) => {
    const now = new Date()
    return (
      day === now.getDate() &&
      currentMonth() === now.getMonth() + 1 &&
      currentYear() === now.getFullYear()
    )
  }

  const hasOverdue = (bills: CalendarBill[]) => bills.some((b) => b.is_overdue)
  const hasUnpaid = (bills: CalendarBill[]) => bills.some((b) => !b.paid && !b.is_overdue)

  const selectDay = (day: number, bills: CalendarBill[], event?: MouseEvent) => {
    setSelectedDay(day)
    setSelectedBills(bills)

    // Position the popover near the click
    if (event) {
      const target = event.currentTarget as HTMLElement
      const rect = target.getBoundingClientRect()
      // Center the popover horizontally, position above/below based on viewport
      const popoverWidth = 320
      let left = rect.left + rect.width / 2 - popoverWidth / 2
      // Clamp to viewport
      if (left < 10) left = 10
      if (left + popoverWidth > window.innerWidth - 10)
        left = window.innerWidth - popoverWidth - 10

      // Position below the cell if room, otherwise above
      const top = rect.bottom + 8
      setPopoverStyle({
        position: 'fixed',
        left: `${left}px`,
        top: `${top}px`,
        'max-width': `${popoverWidth}px`,
      })
    }
  }

  const closePopover = () => {
    setSelectedDay(null)
    setSelectedBills([])
  }

  // Mark a bill as paid from the calendar
  const markPaid = async (billId: number) => {
    setMarkingPaid(new Set([...markingPaid(), billId]))
    try {
      await apiPost(`/api/bills/${billId}/mark-paid`, {})
      showToast('Bill marked as paid', 'success')
      // Optimistic update in selected bills
      setSelectedBills((prev) => prev.map((b) => (b.id === billId ? { ...b, paid: true } : b)))
      // Refresh calendar data
      await refetchCalendar()
      props.onRefresh?.()
    } catch (err) {
      console.error('Failed to mark bill as paid:', err)
      showToast('Failed to mark bill as paid', 'error')
    } finally {
      const next = new Set(markingPaid())
      next.delete(billId)
      setMarkingPaid(next)
    }
  }

  // Format date for display
  const formatDate = (dateStr: string): string => {
    const date = new Date(dateStr)
    if (isNaN(date.getTime())) return dateStr
    return date.toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
    })
  }

  // Day status class
  const dayStatusClass = (bills: CalendarBill[]): string => {
    if (!bills.length) return ''
    if (hasOverdue(bills)) return styles.dayOverdue
    if (bills.every((b) => b.paid)) return styles.dayAllPaid
    return styles.dayUpcoming
  }

  return (
    <div class={styles.calendarWrap}>
      {/* Month header */}
      <div class={styles.monthHeader}>
        <button class={styles.navBtn} onClick={prevMonth} title="Previous month">
          <svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
            <path d="M15 19l-7-7 7-7" />
          </svg>
        </button>
        <div class={styles.monthLabelGroup}>
          <h2 class={styles.monthLabel}>{calendarData()?.monthLabel || ''}</h2>
          <button class={styles.todayBtn} onClick={goToToday}>
            Today
          </button>
        </div>
        <button class={styles.navBtn} onClick={nextMonth} title="Next month">
          <svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
            <path d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      {/* Summary bar */}
      <Show when={calendarData()}>
        <div class={styles.calSummary}>
          <div class={styles.calSummaryItem}>
            <span class={styles.calSummaryLabel}>Bills</span>
            <span class={styles.calSummaryValue}>{calendarData()!.summary.billCount}</span>
          </div>
          <div class={styles.calSummaryItem}>
            <span class={styles.calSummaryLabel}>Total</span>
            <span class={styles.calSummaryValue}>{formatCurrency(calendarData()!.summary.totalAmount)}</span>
          </div>
          <div class={styles.calSummaryItem}>
            <span class={styles.calSummaryLabel}>Paid</span>
            <span class={`${styles.calSummaryValue} ${styles.calSummaryPaid}`}>
              {formatCurrency(calendarData()!.summary.paidAmount)}
            </span>
          </div>
        </div>
      </Show>

      {/* Loading state */}
      <Show when={loading()}>
        <div class={styles.loadingState}>Loading calendar...</div>
      </Show>

      {/* Calendar grid */}
      <Show when={calendarData()}>
        <div class={styles.calendarGrid}>
          {/* Day headers */}
          <For each={WEEKDAYS}>
            {(day) => <div class={styles.dayHeader}>{day}</div>}
          </For>

          {/* Empty cells before first day of month */}
          {Array.from({ length: calendarData()!.firstDow }, (_, i) => (
            <div class={`${styles.dayCell} ${styles.dayEmpty}`} />
          ))}

          {/* Day cells */}
          <For each={daysArray()}>
            {(day) => {
              const bills: CalendarBill[] = calendarData()!.days[String(day)] || []
              return (
                <div
                  class={`${styles.dayCell} ${dayStatusClass(bills)} ${
                    isToday(day) ? styles.today : ''
                  } ${selectedDay() === day ? styles.daySelected : ''} ${
                    bills.length > 0 ? styles.hasBills : ''
                  }`}
                  onClick={(e) => bills.length > 0 && selectDay(day, bills, e)}
                  role={bills.length > 0 ? 'button' : undefined}
                  tabIndex={bills.length > 0 ? 0 : undefined}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' && bills.length > 0) selectDay(day, bills)
                  }}
                >
                  <span class={styles.dayNumber}>{day}</span>
                  {bills.length > 0 && (
                    <div class={styles.billDots}>
                      <For each={bills.slice(0, 4)}>
                        {(bill) => (
                          <span
                            class={`${styles.billDot} ${
                              bill.paid
                                ? styles.dotPaid
                                : bill.is_overdue
                                  ? styles.dotOverdue
                                  : styles.dotUpcoming
                            }`}
                            style={
                              bill.category_color
                                ? { 'background-color': bill.paid ? undefined : bill.category_color }
                                : undefined
                            }
                            title={bill.name}
                          />
                        )}
                      </For>
                      {bills.length > 4 && (
                        <span class={styles.moreBills}>+{bills.length - 4}</span>
                      )}
                    </div>
                  )}
                </div>
              )
            }}
          </For>
        </div>
      </Show>

      {/* Day detail popover */}
      <Show when={selectedDay() !== null && selectedBills().length > 0}>
        <div class={styles.popoverBackdrop} onClick={closePopover} />
        <div class={styles.popover} style={popoverStyle()}>
          <div class={styles.popoverHeader}>
            <h3 class={styles.popoverTitle}>
              {calendarData() &&
                formatDate(
                  `${calendarData()!.year}-${String(calendarData()!.month).padStart(2, '0')}-${String(selectedDay()).padStart(2, '0')}`
                )}
            </h3>
            <button class={styles.popoverClose} onClick={closePopover}>
              <svg width="18" height="18" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
          <div class={styles.popoverBody}>
            <For each={selectedBills()}>
              {(bill) => (
                <div
                  class={`${styles.popoverBill} ${
                    bill.is_overdue ? styles.popoverBillOverdue : bill.paid ? styles.popoverBillPaid : ''
                  }`}
                >
                  <div class={styles.popoverBillLeft}>
                    {bill.category_color && (
                      <span
                        class={styles.popoverBillColor}
                        style={{ 'background-color': bill.category_color }}
                      />
                    )}
                    <div class={styles.popoverBillInfo}>
                      <span class={styles.popoverBillName}>{bill.name}</span>
                      <span class={styles.popoverBillMeta}>
                        {bill.frequency === 'monthly'
                          ? 'Monthly'
                          : bill.frequency === 'weekly'
                            ? 'Weekly'
                            : bill.frequency === 'biweekly'
                              ? 'Biweekly'
                              : bill.frequency}
                        {bill.category_name && ` • ${bill.category_name}`}
                        {bill.paid && ' • Paid'}
                        {bill.is_overdue && !bill.paid && ' • Overdue'}
                      </span>
                    </div>
                  </div>
                  <div class={styles.popoverBillRight}>
                    <span
                      class={`${styles.popoverBillAmount} ${
                        bill.is_overdue && !bill.paid ? styles.amountOverdue : ''
                      }`}
                    >
                      {formatCurrency(bill.amount)}
                    </span>
                    {!bill.paid && (
                      <button
                        class={styles.popoverMarkPaid}
                        onClick={() => markPaid(bill.id)}
                        disabled={markingPaid().has(bill.id)}
                      >
                        {markingPaid().has(bill.id) ? '...' : 'Pay'}
                      </button>
                    )}
                    {bill.paid && <span class={styles.popoverPaidCheck}>✓</span>}
                  </div>
                </div>
              )}
            </For>
          </div>
        </div>
      </Show>
    </div>
  )
}

export default BillCalendar
export type { CalendarBill, CalendarData }

/**
 * Bills Component - EARS Specification
 *
 * GIVEN: A user is viewing the Bills page
 * WHEN: The page loads
 * THEN: The header displays "Bills" and page subtitle "Track upcoming payments and never miss a due date"
 *
 * GIVEN: The user has unpaid bills
 * WHEN: The page displays bills
 * THEN: Bills are shown in the Upcoming Bills section with:
 *       - Bill name
 *       - Due date
 *       - Days until due (with special messages: "Due today", "Due tomorrow", "X days overdue", "Due in X days")
 *       - Amount in currency
 *       - Frequency (Monthly, Weekly, Biweekly)
 *       - Icon (regular or autopay badge)
 *       - Mark as Paid button
 *
 * GIVEN: The user has paid bills
 * WHEN: The page displays paid bills
 * THEN: Bills are shown in the Paid Bills section with:
 *       - Bill name
 *       - Due date
 *       - "Paid" status
 *       - Delete button
 *
 * GIVEN: The user has all bills
 * WHEN: The page displays all bills
 * THEN: All bills are shown in the All Bills section with the same details as unpaid bills,
 *       but without the Mark as Paid button (use Delete button instead for paid bills)
 *
 * GIVING: A new bill modal
 * WHEN: The user clicks "Add Bill" button
 * THEN: The modal opens with form fields:
 *       - Bill Name (required, text input)
 *       - Amount (required, number input)
 *       - Due Date (required, date input)
 *       - Category (select with existing expense categories)
 *       - + Add Category button
 *       - Frequency (select: Monthly, Weekly, Biweekly)
 *       - Autopay toggle
 *       - Cancel and Add Bill buttons in footer
 *
 * GIVING: A category modal
 * WHEN: The user clicks "+ Add Category"
 * THEN: The modal opens with form fields:
 *       - Category Name (required)
 *       - Type (select: Expense, Income)
 *       - Color (color picker)
 *       - Cancel and Add buttons
 *
 * ENSURING: Data integrity
 * WHEN: A bill is marked as paid
 * THEN: The bill is moved from upcoming/paid lists to paid list
 * WHEN: A bill is deleted
 * THEN: The bill is removed from all lists with confirmation
 */

import { createMemo, createResource, createSignal, For } from 'solid-js'
import BillCalendar from './BillCalendar'
import ConfirmButton from '../components/ConfirmButton'
import SubscriptionCard from '../components/SubscriptionCard'
import { formatCurrency } from '../core/api'
import { apiDelete, apiGet, apiPost, apiPut, showToast } from '../core/api'
import { useAppState } from '../core/appStore'
import styles from './BillsPage.module.css'
import { matchBrand } from './subscriptionBrands'
import type { SubscriptionCardBill } from '../components/SubscriptionCard'

interface Bill {
  id: number
  name: string
  amount: number
  due_date: string
  category?: string
  category_id?: number | null
  category_name?: string
  category_color?: string
  account_id?: number
  frequency: 'monthly' | 'weekly' | 'biweekly'
  paid: boolean
  autopay: boolean
  profile_id: number
  created_at: string
  type?: 'bill' | 'subscription'
  is_active?: number
}

interface Category {
  id: number
  name: string
  type: 'expense' | 'income'
  color: string
  tax_deductible?: boolean
}

export default function Bills() {
  const state = useAppState()

  // Bills resource — fetches bills + expense categories
  const [billsResource, { refetch: refetchBills, mutate: mutateBills }] = createResource(
    () => state.profileVersion,
    async () => {
      const [allRes, categoryRes] = await Promise.all([
        apiGet<Bill[]>('/api/bills'),
        apiGet<Category[]>('/api/categories'),
      ])
      return {
        bills: allRes,
        categories: categoryRes.filter((c) => c.type === 'expense'),
      }
    }
  )
  const loading = () => billsResource.loading && !billsResource()
  const bills = () => billsResource()?.bills ?? []
  const categories = () => billsResource()?.categories ?? []
  const [showAddModal, setShowAddModal] = createSignal(false)
  const [showCategoryModal, setShowCategoryModal] = createSignal(false)
  const [editingId, setEditingId] = createSignal<number | null>(null)
  const [formData, setFormData] = createSignal({
    name: '',
    amount: '',
    due_date: '',
    category: '',
    frequency: 'monthly' as Bill['frequency'],
    autopay: false,
    type: 'bill' as 'bill' | 'subscription',
  })
  const [categoryForm, setCategoryForm] = createSignal({
    name: '',
    type: 'expense' as 'expense' | 'income',
    color: '#6b7280',
  })

  // Tab state: 'all' | 'subscriptions' | 'calendar'
  const [billTab, setBillTab] = createSignal<'all' | 'subscriptions' | 'calendar'>('all')

  // Memoized filtered lists
  const subscriptions = createMemo(() =>
    bills().filter((b) => (b.type || 'bill') === 'subscription')
  )
  const activeSubscriptions = createMemo(() => subscriptions().filter((b) => b.is_active !== 0))
  const totalMonthlySubs = createMemo(() =>
    activeSubscriptions().reduce((sum, b) => sum + b.amount, 0)
  )

  // Group active subscriptions by category
  const subscriptionGroups = createMemo(() => {
    const groups = new Map<string, Bill[]>()
    for (const sub of activeSubscriptions()) {
      const brand = matchBrand(sub.name, sub.category_color)
      const cat = brand.defaultCategory
      if (!groups.has(cat)) groups.set(cat, [])
      groups.get(cat)!.push(sub)
    }
    return [...groups.entries()]
  })

  const pausedSubscriptions = createMemo(() => subscriptions().filter((b) => b.is_active === 0))

  // Pause a subscription
  const pauseSubscription = async (id: number) => {
    const sub = bills().find((b) => b.id === id)
    if (!sub) return
    try {
      await apiPut(`/api/bills/${id}`, { ...sub, is_active: 0, type: sub.type })
      await refetchBills()
    } catch {
      showToast('Failed to pause subscription', 'error')
    }
  }
  const unpaidBills = createMemo(() =>
    bills().filter((b) => !b.paid && (b.type || 'bill') !== 'subscription')
  )
  const paidBills = createMemo(() =>
    bills().filter((b) => b.paid && (b.type || 'bill') !== 'subscription')
  )

  // Add category
  const addCategory = async (e: Event) => {
    e.preventDefault()
    try {
      await apiPost('/api/categories', categoryForm())
      showToast('Category added', 'success')
      setCategoryForm({ name: '', type: 'expense', color: '#6b7280' })
      setShowCategoryModal(false)
      refetchBills()
    } catch (err) {
      console.error('Failed to add category', err)
      showToast('Failed to add category', 'error')
    }
  }

  // Open category modal
  const openCategoryModal = () => {
    setShowCategoryModal(true)
  }

  // Handle form submit
  const handleSubmit = async (e: Event) => {
    e.preventDefault()
    const data = {
      name: formData().name,
      amount: parseFloat(formData().amount),
      dueDate: formData().due_date,
      category_id: formData().category ? parseInt(formData().category, 10) : undefined,
      frequency: formData().frequency,
      type: formData().type,
    }

    try {
      const id = editingId()
      if (id) {
        await apiPut(`/api/bills/${id}`, data)
        showToast('Bill updated', 'success')
      } else {
        await apiPost('/api/bills', data)
        showToast('Bill saved', 'success')
      }
      setShowAddModal(false)
      setEditingId(null)
      setFormData({
        name: '',
        amount: '',
        due_date: '',
        category: '',
        frequency: 'monthly',
        autopay: false,
        type: 'bill',
      })
      refetchBills()
    } catch (err) {
      console.error('Failed to save bill:', err)
      showToast('Failed to save bill', 'error')
    }
  }

  // Open edit modal pre-filled with bill data
  const openEditModal = (idOrBill: number | Bill) => {
    const bill = typeof idOrBill === 'number' ? bills().find((b) => b.id === idOrBill) : idOrBill
    if (!bill) return
    setEditingId(bill.id)
    setFormData({
      name: bill.name,
      amount: bill.amount.toString(),
      due_date: bill.due_date,
      category: bill.category || '',
      frequency: bill.frequency,
      autopay: bill.autopay,
      type: bill.type || 'bill',
    })
    setShowAddModal(true)
  }

  const [markingPaid, setMarkingPaid] = createSignal<Set<number>>(new Set())

  // Mark bill as paid
  const markPaid = async (id: number) => {
    // Optimistic update: mark as paid locally immediately
    mutateBills((prev) =>
      prev
        ? { ...prev, bills: prev.bills.map((b) => (b.id === id ? { ...b, paid: true } : b)) }
        : prev
    )
    setMarkingPaid(new Set([...markingPaid(), id]))

    try {
      await apiPost(`/api/bills/${id}/mark-paid`, {})
      showToast('Bill marked as paid', 'success')
      // Reload to get fresh data from server
      await refetchBills()
    } catch (err) {
      console.error('Failed to mark bill as paid:', err)
      showToast('Failed to mark bill as paid', 'error')
      // Revert optimistic update on failure
      await refetchBills()
    } finally {
      const next = new Set(markingPaid())
      next.delete(id)
      setMarkingPaid(next)
    }
  }

  // Delete bill
  const deleteBill = async (id: number) => {
    try {
      await apiDelete(`/api/bills/${id}`)
      showToast('Bill deleted successfully', 'success')
      refetchBills()
    } catch (err) {
      console.error('Failed to delete bill:', err)
      showToast('Failed to delete bill', 'error')
    }
  }

  // Days until due
  const daysUntil = (dateStr: string): string => {
    const target = new Date(dateStr)
    const today = new Date()
    today.setHours(0, 0, 0, 0)
    target.setHours(0, 0, 0, 0)
    const diff = Math.ceil((target.getTime() - today.getTime()) / (1000 * 60 * 60 * 24))
    if (diff < 0) return `${Math.abs(diff)} days overdue`
    if (diff === 0) return 'Due today'
    if (diff === 1) return 'Due tomorrow'
    return `Due in ${diff} days`
  }

  const isOverdue = (dateStr: string): boolean => {
    const target = new Date(dateStr)
    const today = new Date()
    today.setHours(0, 0, 0, 0)
    target.setHours(0, 0, 0, 0)
    return target < today
  }

  // Format date
  const formatDate = (dateStr: string): string => {
    const date = new Date(dateStr)
    if (isNaN(date.getTime())) {
      console.error('Invalid date:', dateStr, 'Date object:', date)
      return 'Invalid Date'
    }
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    })
  }

  return (
    <div class={`${styles.billsPage} page page-bills page-enter`}>
      <div class={styles.pageHeader}>
        <div class={styles.headerTop}>
          <h1 data-test-id="bills-header">Bills</h1>
          <button
            data-test-id="add-bill-btn"
            class={styles.btnPrimary}
            onClick={() => {
              setEditingId(null)
              setFormData({
                ...formData(),
                name: '',
                amount: '',
                due_date: '',
                category: '',
                type: billTab() === 'subscriptions' ? 'subscription' : 'bill',
              })
              setShowAddModal(true)
            }}
          >
            <svg width="16" height="16" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
            </svg>
            {billTab() === 'subscriptions' ? 'Add Subscription' : 'Add Bill'}
          </button>
        </div>
        <p data-test-id="bills-subtitle" class={styles.pageSubtitle}>
          Track upcoming payments and never miss a due date
        </p>
      </div>

      {/* Tab navigation */}
      <div class={styles.tabs}>
        <button
          class={`${styles.tabBtn} ${billTab() === 'all' ? styles.tabActive : ''}`}
          onClick={() => setBillTab('all')}
        >
          <svg
            width="16"
            height="16"
            fill="none"
            stroke="currentColor"
            stroke-width="2"
            viewBox="0 0 24 24"
          >
            <path d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
          </svg>
          Regular Bills
        </button>
        <button
          class={`${styles.tabBtn} ${billTab() === 'subscriptions' ? styles.tabActive : ''}`}
          onClick={() => setBillTab('subscriptions')}
        >
          <svg
            width="16"
            height="16"
            fill="none"
            stroke="currentColor"
            stroke-width="2"
            viewBox="0 0 24 24"
          >
            <path d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
          </svg>
          Subscriptions
          {activeSubscriptions().length > 0 && (
            <span class={styles.tabBadge}>{activeSubscriptions().length}</span>
          )}
        </button>
        <button
          class={`${styles.tabBtn} ${billTab() === 'calendar' ? styles.tabActive : ''}`}
          onClick={() => setBillTab('calendar')}
        >
          <svg
            width="16"
            height="16"
            fill="none"
            stroke="currentColor"
            stroke-width="2"
            viewBox="0 0 24 24"
          >
            <path d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
          </svg>
          Calendar
        </button>
      </div>

      {loading() ? (
        <div data-test-id="loading-state" class={styles.emptyState}>
          Loading bills...
        </div>
      ) : billTab() === 'calendar' ? (
        <BillCalendar onRefresh={refetchBills} />
      ) : billTab() === 'subscriptions' ? (
        <div class={styles.subscriptionView}>
          {/* Subscription Summary Card */}
          <div class={styles.subscriptionSummary}>
            <div class={styles.subSummaryRow}>
              <div class={styles.subSummaryCard}>
                <span class={styles.subSummaryLabel}>Active Subs</span>
                <span class={styles.subSummaryValue}>{activeSubscriptions().length}</span>
              </div>
              <div class={styles.subSummaryCard}>
                <span class={styles.subSummaryLabel}>Monthly Total</span>
                <span class={styles.subSummaryValue}>{formatCurrency(totalMonthlySubs())}</span>
              </div>
              <div class={styles.subSummaryCard}>
                <span class={styles.subSummaryLabel}>Categories</span>
                <span class={styles.subSummaryValue}>{subscriptionGroups().length}</span>
              </div>
            </div>
          </div>

          {/* Category Groups — Gallery Grid */}
          {activeSubscriptions().length > 0 && (
            <For each={subscriptionGroups()}>
              {([category, subs]) => (
                <div class={styles.categoryGroup}>
                  <h3 class={styles.categoryGroupTitle}>
                    {category}
                    <span class={styles.categoryGroupCount}>{subs.length}</span>
                  </h3>
                  <div class={styles.subscriptionGallery}>
                    <For each={subs}>
                      {(sub) => (
                        <SubscriptionCard
                          subscription={sub as SubscriptionCardBill}
                          onMarkPaid={markPaid}
                          onPause={pauseSubscription}
                          onDelete={deleteBill}
                          onEdit={openEditModal}
                          markingPaid={markingPaid}
                        />
                      )}
                    </For>
                  </div>
                </div>
              )}
            </For>
          )}

          {/* Paused Subscriptions */}
          {pausedSubscriptions().length > 0 && (
            <div class={styles.categoryGroup}>
              <h3 class={styles.categoryGroupTitle}>
                Paused
                <span class={styles.categoryGroupCount}>{pausedSubscriptions().length}</span>
              </h3>
              <div class={styles.subscriptionGallery}>
                <For each={pausedSubscriptions()}>
                  {(sub) => (
                    <SubscriptionCard
                      subscription={sub as SubscriptionCardBill}
                      onMarkPaid={markPaid}
                      onPause={async (id) => {
                        const s = bills().find((b) => b.id === id)
                        if (!s) return
                        await apiPut(`/api/bills/${id}`, {
                          ...s,
                          is_active: 1,
                          type: s.type,
                        })
                        await refetchBills()
                      }}
                      onDelete={deleteBill}
                      onEdit={openEditModal}
                      markingPaid={markingPaid}
                    />
                  )}
                </For>
              </div>
            </div>
          )}

          {subscriptions().length === 0 && (
            <div class={styles.emptyState}>
              <p>No subscriptions yet</p>
              <p>Add streaming services, software subscriptions, and other recurring services.</p>
              <button
                class={styles.btnPrimary}
                onClick={() => {
                  setEditingId(null)
                  setFormData({
                    name: '',
                    amount: '',
                    due_date: '',
                    category: '',
                    frequency: 'monthly',
                    autopay: false,
                    type: 'subscription',
                  })
                  setShowAddModal(true)
                }}
              >
                Add Subscription
              </button>
            </div>
          )}
        </div>
      ) : bills().length === 0 ? (
        <div data-test-id="bills-empty" class={styles.emptyState}>
          <p>No bills yet</p>
          <p>Add your first bill to start tracking your payments.</p>
          <button
            data-test-id="bills-add-btn-empty"
            class={styles.btnPrimary}
            onClick={() => {
              setEditingId(null)
              setFormData({
                name: '',
                amount: '',
                due_date: '',
                category: '',
                frequency: 'monthly',
                autopay: false,
                type: 'bill',
              })
              setShowAddModal(true)
            }}
          >
            Add Bill
          </button>
        </div>
      ) : (
        <div class={styles.billsGrid}>
          {/* Unpaid Bills Section */}
          {unpaidBills().length > 0 && (
            <div data-test-id="bills-upcoming-section" class={styles.billsSection}>
              <h2 class={styles.sectionTitle}>
                <svg
                  width="16"
                  height="16"
                  fill="none"
                  stroke="currentColor"
                  stroke-width="2"
                  viewBox="0 0 24 24"
                >
                  <path d="M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9M13.73 21a2 2 0 01-3.46 0" />
                </svg>{' '}
                Unpaid Bills
                <span class={styles.sectionSubtitle}>{unpaidBills().length} bills</span>
              </h2>
              <div data-test-id="bills-list" class={styles.billsList}>
                <For each={unpaidBills()}>
                  {(bill) => (
                    <div
                      data-test-id="bill-card"
                      class={`${styles.billCard} ${isOverdue(bill.due_date) ? styles.overdue : ''}`}
                    >
                      <div class={styles.billMain}>
                        <div data-test-id="bill-icon" class={styles.billIcon}>
                          {bill.autopay ? (
                            <svg
                              width="18"
                              height="18"
                              fill="none"
                              stroke="currentColor"
                              stroke-width="2"
                              viewBox="0 0 24 24"
                            >
                              <path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                            </svg>
                          ) : (
                            <svg
                              width="18"
                              height="18"
                              fill="none"
                              stroke="currentColor"
                              stroke-width="2"
                              viewBox="0 0 24 24"
                            >
                              <path d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                            </svg>
                          )}
                        </div>
                        <div class={styles.billInfo}>
                          <h3 data-test-id="bill-name" class={styles.billName}>
                            {bill.name}
                          </h3>
                          <p data-test-id="bill-details" class={styles.billDetails}>
                            {formatDate(bill.due_date)} • {daysUntil(bill.due_date)} •{' '}
                            {bill.frequency === 'monthly'
                              ? 'Monthly'
                              : bill.frequency === 'weekly'
                                ? 'Weekly'
                                : 'Biweekly'}
                          </p>
                        </div>
                      </div>
                      <div
                        data-test-id="bill-amount-container"
                        class={`${styles.billAmount} ${isOverdue(bill.due_date) ? styles.overdue : ''}`}
                      >
                        <div class={styles.amountValue}>{formatCurrency(bill.amount)}</div>
                        <div class={styles.billActions}>
                          <button
                            class={`${styles.btnPrimary} ${styles.btnSm}`}
                            onClick={() => markPaid(bill.id)}
                            disabled={markingPaid().has(bill.id)}
                          >
                            {markingPaid().has(bill.id) ? 'Paying...' : 'Mark Paid'}
                          </button>
                          <button
                            class={`${styles.btnGhost} ${styles.btnSm}`}
                            onClick={() => {
                              openEditModal(bill)
                            }}
                            title="Edit bill"
                          >
                            Edit
                          </button>
                        </div>
                      </div>
                    </div>
                  )}
                </For>
              </div>
            </div>
          )}

          {/* Paid Bills Section */}
          {paidBills().length > 0 && (
            <div data-test-id="bills-paid-section" class={styles.billsSection}>
              <h2 class={styles.sectionTitle}>
                <span>
                  <svg
                    width="16"
                    height="16"
                    fill="none"
                    stroke="currentColor"
                    stroke-width="2"
                    viewBox="0 0 24 24"
                  >
                    <path d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4" />
                  </svg>
                </span>{' '}
                Paid Bills
                <span class={styles.sectionSubtitle}>{paidBills().length} paid</span>
              </h2>
              <div class={styles.billsList}>
                <For each={paidBills()}>
                  {(bill) => (
                    <div
                      class={`${styles.billCard} ${bill.paid ? styles.paid : ''} ${isOverdue(bill.due_date) && !bill.paid ? styles.overdue : ''}`}
                    >
                      <div class={styles.billMain}>
                        <div data-test-id="bill-icon" class={styles.billIcon}>
                          {bill.autopay ? (
                            <svg
                              width="18"
                              height="18"
                              fill="none"
                              stroke="currentColor"
                              stroke-width="2"
                              viewBox="0 0 24 24"
                            >
                              <path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                            </svg>
                          ) : (
                            <svg
                              width="18"
                              height="18"
                              fill="none"
                              stroke="currentColor"
                              stroke-width="2"
                              viewBox="0 0 24 24"
                            >
                              <path d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                            </svg>
                          )}
                        </div>
                        <div class={styles.billInfo}>
                          <h3 data-test-id="bill-name" class={styles.billName}>
                            {bill.name}
                            {bill.paid && <span class={styles.paidBadge}>Paid</span>}
                          </h3>
                          <p data-test-id="bill-details" class={styles.billDetails}>
                            {formatDate(bill.due_date)} •{' '}
                            {bill.frequency === 'monthly'
                              ? 'Monthly'
                              : bill.frequency === 'weekly'
                                ? 'Weekly'
                                : 'Biweekly'}
                            {bill.category && ` • ${bill.category}`}
                          </p>
                        </div>
                      </div>
                      <div class={styles.billAmount}>
                        <div class={styles.amountValue}>{formatCurrency(bill.amount)}</div>
                        <div class={styles.billActions}>
                          <button
                            class={`${styles.btnGhost} ${styles.btnSm}`}
                            onClick={() => {
                              openEditModal(bill)
                            }}
                            title="Edit bill"
                          >
                            Edit
                          </button>
                          {!bill.paid ? (
                            <button
                              data-test-id="bill-mark-paid-btn"
                              class={`${styles.btnPrimary} ${styles.btnSm}`}
                              onClick={() => markPaid(bill.id)}
                              disabled={markingPaid().has(bill.id)}
                            >
                              {markingPaid().has(bill.id)
                                ? 'Paying...'
                                : isOverdue(bill.due_date)
                                  ? 'Mark as Paid (Overdue)'
                                  : 'Mark Paid'}
                            </button>
                          ) : (
                            <ConfirmButton
                              class={`${styles.btnSm} ${styles.btnGhost}`}
                              onConfirm={() => deleteBill(bill.id)}
                              label={
                                <svg
                                  width="16"
                                  height="16"
                                  fill="none"
                                  stroke="currentColor"
                                  viewBox="0 0 24 24"
                                >
                                  <path d="M6 18L18 6M6 6l12 12" />
                                </svg>
                              }
                            />
                          )}
                        </div>
                      </div>
                    </div>
                  )}
                </For>
              </div>
            </div>
          )}
        </div>
      )}

      {/* Add Bill Modal */}
      {showAddModal() && (
        <div
          class={styles.modalOverlay}
          onclick={(e) => {
            if (e.target === e.currentTarget) {
              setShowAddModal(false)
              setEditingId(null)
            }
          }}
        >
          <div
            class={styles.modal}
            onclick={(e) => {
              e.stopPropagation()
            }}
          >
            <div class={styles.modalHeader}>
              <h3 class={styles.modalTitle}>
                {editingId() ? 'Edit' : 'Add'}{' '}
                {formData().type === 'subscription' ? 'Subscription' : 'Bill'}
              </h3>
              <button
                class={styles.modalClose}
                onClick={() => {
                  setShowAddModal(false)
                  setEditingId(null)
                }}
              >
                <svg width="24" height="24" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
            <form class={styles.modalBody} onSubmit={handleSubmit}>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Bill Name</label>
                <input
                  type="text"
                  class={styles.formControl}
                  placeholder="e.g., Rent, Electricity, Internet"
                  value={formData().name}
                  oninput={(e) => setFormData({ ...formData(), name: e.target.value })}
                  autofocus
                  required
                />
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Amount</label>
                <input
                  type="number"
                  step="0.01"
                  class={styles.formControl}
                  placeholder="500.00"
                  value={formData().amount}
                  oninput={(e) => setFormData({ ...formData(), amount: e.target.value })}
                  required
                />
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Due Date</label>
                <input
                  type="date"
                  class={styles.formControl}
                  value={formData().due_date}
                  oninput={(e) => setFormData({ ...formData(), due_date: e.target.value })}
                  required
                />
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Category</label>
                <select
                  class={styles.formControl}
                  value={formData().category}
                  oninput={(e) => setFormData({ ...formData(), category: e.target.value })}
                >
                  <option value="">No category</option>
                  <For each={categories()}>
                    {(cat) => <option value={cat.name}>{cat.name}</option>}
                  </For>
                </select>
                <button
                  type="button"
                  class={styles.btnLink}
                  style={{ 'margin-top': '8px' }}
                  onClick={openCategoryModal}
                >
                  + Add Category
                </button>
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Frequency</label>
                <select
                  class={styles.formControl}
                  value={formData().frequency}
                  oninput={(e) =>
                    setFormData({ ...formData(), frequency: e.target.value as Bill['frequency'] })
                  }
                >
                  <option value="monthly">Monthly</option>
                  <option value="weekly">Weekly</option>
                  <option value="biweekly">Biweekly</option>
                </select>
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Type</label>
                <select
                  class={styles.formControl}
                  value={formData().type}
                  oninput={(e) =>
                    setFormData({ ...formData(), type: e.target.value as 'bill' | 'subscription' })
                  }
                >
                  <option value="bill">Regular Bill</option>
                  <option value="subscription">Subscription</option>
                </select>
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>
                  <span>
                    <svg
                      width="16"
                      height="16"
                      fill="none"
                      stroke="currentColor"
                      stroke-width="2"
                      viewBox="0 0 24 24"
                    >
                      <path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                    </svg>{' '}
                    Autopay
                  </span>
                  <span style="font-size: 14px; color: var(--text-secondary)">
                    Automatically pay this bill
                  </span>
                </label>
                <label class={styles.toggleSwitch}>
                  <input
                    type="checkbox"
                    checked={formData().autopay}
                    oninput={(e) => setFormData({ ...formData(), autopay: e.target.checked })}
                  />
                  <span class={styles.toggleSlider}></span>
                </label>
              </div>
              <div class={styles.modalFooter}>
                <button
                  type="button"
                  class={styles.btnSecondary}
                  onClick={() => setShowAddModal(false)}
                >
                  Cancel
                </button>
                <button type="submit" class={styles.btnPrimary}>
                  {editingId() ? 'Update' : 'Add'}{' '}
                  {formData().type === 'subscription' ? 'Subscription' : 'Bill'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Add Category Modal */}
      {showCategoryModal() && (
        <div
          class={styles.modalOverlay}
          onclick={(e) => {
            if (e.target === e.currentTarget) setShowCategoryModal(false)
          }}
        >
          <div
            class={styles.modal}
            onclick={(e) => {
              e.stopPropagation()
            }}
          >
            <div class={styles.modalHeader}>
              <h3 class={styles.modalTitle}>Add Category</h3>
              <button class={styles.modalClose} onClick={() => setShowCategoryModal(false)}>
                <svg width="24" height="24" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
            <form class={styles.modalBody} onSubmit={addCategory}>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Category Name</label>
                <input
                  type="text"
                  class={styles.formControl}
                  placeholder="e.g., Utilities, Entertainment"
                  value={categoryForm().name}
                  oninput={(e) => setCategoryForm({ ...categoryForm(), name: e.target.value })}
                  autofocus
                  required
                />
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Type</label>
                <select
                  class={styles.formControl}
                  value={categoryForm().type}
                  oninput={(e) =>
                    setCategoryForm({
                      ...categoryForm(),
                      type: e.target.value as 'expense' | 'income',
                    })
                  }
                >
                  <option value="expense">Expense</option>
                  <option value="income">Income</option>
                </select>
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Color</label>
                <input
                  type="color"
                  class={styles.colorInput}
                  value={categoryForm().color}
                  oninput={(e) => setCategoryForm({ ...categoryForm(), color: e.target.value })}
                />
              </div>
              <div class={styles.modalFooter}>
                <button
                  type="button"
                  class={styles.btnSecondary}
                  onClick={() => setShowCategoryModal(false)}
                >
                  Cancel
                </button>
                <button type="submit" class={styles.btnPrimary}>
                  Add Category
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* View Bill Modal - disabled as unused - kept for future use */}
    </div>
  )
}

/**
 * Budgets Component - EARS Specification
 *
 * GIVEN: A user is viewing the Budgets page
 * WHEN: The page loads
 * THEN: The header displays "Budgets" and shows all budget categories with progress
 *
 * GIVEN: A user wants to create a new budget
 * WHEN: They click the "Create Budget" button
 * THEN: A budget creation modal opens with form fields for category and amount
 *
 * GIVEN: A user creates a budget
 * WHEN: They enter a category name and monthly amount
 * THEN: The new budget appears in the budget list with a progress indicator
 *
 * GIVEN: A user has spent more than their budget
 * WHEN: The page displays their spending vs budget
 * THEN: The progress bar and color indicator show they are over budget (red)
 *
 * GIVEN: A user has budget rollover enabled
 * WHEN: A budget category has unspent remaining budget
 * THEN: The remaining amount rolls over to the next month
 *
 * GIVEN: A user wants to set a budget from expenses
 * WHEN: They click "Set from Expenses"
 * THEN: The budget is calculated based on past spending in that category
 */

/**
 * Budgets Component
 * Includes traditional budgeting view, zero-based budgeting (envelope-style), and forecasting
 */
import { createEffect, createResource, createSignal, For, onMount } from 'solid-js'
import Badge from '../components/Badge'
import Button from '../components/Button'
import CategoryIcon, { getCategorySvg } from '../components/CategoryIcon'
import Chart from '../components/Chart'
import ConfirmButton from '../components/ConfirmButton'
import { api, getLocalCurrency } from '../core/api'
import { apiDelete, apiGet, apiPost, apiPut, showToast } from '../core/api'
import { useAppState } from '../core/appStore'
import { theme } from '../core/theme'
import styles from './BudgetsPage.module.css'
import type { BudgetImprovement, ZeroBasedAllocation, ZeroBasedResponse } from '../types/models'

type AllocationStatus = 'ok' | 'warning' | 'over'

interface ForecastMonth {
  month: string
  label: string
  budget_amount: number
  predicted_spent: number
  adherence: number
  status: 'ok' | 'warning' | 'over'
  forecast_remaining: number
}

interface ForecastData {
  period: string
  history: unknown[]
  forecast: ForecastMonth[]
  total_budget: number
  avg_adherence: number
}

interface CategoryAllocation {
  budget_id: number | null
  category_id: number
  category_name: string
  category_color: string
  category_icon: string | null
  allocated: number
  spent: number
  remaining_budget: number
  percent_used: number
  status: AllocationStatus
  can_allocate: boolean
  is_budgeted: boolean
  is_fully_allocated: boolean
  rollover_enabled: boolean
}

interface ZeroBasedSummary {
  categories: CategoryAllocation[]
  remaining_income: number
  already_budgeted: number
  unassigned_budget: number
  period: string
  can_allocate: boolean
  total_budget: number
  total_spent: number
  remaining: number
  zero_based_remaining: number
  income: number
}

interface Category {
  id: number
  name: string
  type: 'expense' | 'income'
  color: string
  icon: string | null
  profile_id: number
  budget?: number
}

export default function Budgets() {
  const state = useAppState()
  const [month, setMonth] = createSignal(new Date().toISOString().slice(0, 7))
  const [improvements, setImprovements] = createSignal<BudgetImprovement[]>([])
  const [error, setError] = createSignal<string | null>(null)
  const [budgetMessage, setBudgetMessage] = createSignal<string>('')
  const [budgetResource, { refetch: refetchBudget }] = createResource(
    () => ({ m: month(), pv: state.profileVersion }),
    async ({ m }) => {
      const [allocationsRes, summaryRes, forecastDataRaw] = await Promise.all([
        apiGet<ZeroBasedResponse>(`/api/budgets/zero-based?month=${m}`),
        apiGet<any>(`/api/budgets/zero-based/summary?month=${m}`),
        apiGet<ForecastData>(`/api/budgets/forecast?month=${m}`).catch(() => null),
      ])

      const allocationsList = (allocationsRes?.allocations || allocationsRes?.categories || []).map(
        (item: ZeroBasedAllocation): any => ({
          ...item,
          amount: item.amount || item.allocated || 0,
          allocated: item.amount || item.allocated || 0,
          status:
            item.status ||
            (item.percent_used > 100 ? 'over' : item.percent_used >= 90 ? 'warning' : 'ok'),
          is_fully_allocated:
            item.is_fully_allocated ?? (((item as any).is_budgeted as boolean) && item.amount > 0),
        })
      )
      const unallocated = summaryRes?.zero_based_remaining || summaryRes?.zeroBasedRemaining || 0
      return {
        allocations: allocationsList,
        summary: {
          ...summaryRes,
          categories: summaryRes?.allocations || summaryRes?.categories || [],
        },
        forecastData: forecastDataRaw || null,
        budgetMessage:
          unallocated > 0
            ? `Unallocated: ${new Intl.NumberFormat(undefined, { style: 'currency', currency: getLocalCurrency() }).format(unallocated)}`
            : `All income allocated!`,
      }
    }
  )
  const loading = () => budgetResource.loading && !budgetResource()
  const allocations = () => budgetResource()?.allocations ?? []
  const summary = () => (budgetResource()?.summary ?? null) as ZeroBasedSummary | null
  const forecastData = () => budgetResource()?.forecastData ?? null

  const [showAllocateModal, setShowAllocateModal] = createSignal(false)
  const [selectedCategory, setSelectedCategory] = createSignal<CategoryAllocation | null>(null)
  const [allocateAmount, setAllocateAmount] = createSignal('')
  const [showMonthPicker, setShowMonthPicker] = createSignal(false)
  const [showYearPicker, setShowYearPicker] = createSignal(false)

  // Categories state
  const [categories, setCategories] = createSignal<Category[]>([])
  const [showCatModal, setShowCatModal] = createSignal(false)
  const [showCatBudgetModal, setShowCatBudgetModal] = createSignal(false)
  const [editingCategory, setEditingCategory] = createSignal<Category | null>(null)
  const [selectedCat, setSelectedCat] = createSignal<Category | null>(null)
  const [catBudgetAmount, setCatBudgetAmount] = createSignal('')
  const [filterType, setFilterType] = createSignal<'all' | 'expense' | 'income'>('all')
  const [categoryBudgetSummary, setCategoryBudgetSummary] = createSignal<
    Record<number, { spent: number; budget: number; remaining: number; percent_used: number }>
  >({})
  const [catFormData, setCatFormData] = createSignal({
    name: '',
    type: 'expense' as 'expense' | 'income',
    color: '#3b82f6',
    icon: '',
  })

  const MONTHS = [
    'January',
    'February',
    'March',
    'April',
    'May',
    'June',
    'July',
    'August',
    'September',
    'October',
    'November',
    'December',
  ]
  const currentYear = () => new Date().getFullYear()
  const [availableYears, setAvailableYears] = createSignal<number[]>([
    currentYear() - 1,
    currentYear(),
    currentYear() + 1,
  ])

  const loadYearRange = async () => {
    try {
      const { years } = await api.getTransactionYears()
      if (years.length > 0) setAvailableYears([...years].sort((a, b) => b - a))
    } catch {
      /* keep defaults */
    }
  }

  const currentMonthNum = () => parseInt(month().split('-')[1])
  const currentYearNum = () => parseInt(month().split('-')[0])

  const setMonthNum = (m: number) => {
    const y = currentYearNum()
    setMonth(`${y}-${String(m).padStart(2, '0')}`)
  }
  const setYearNum = (y: number) => {
    const m = currentMonthNum()
    setMonth(`${y}-${String(m).padStart(2, '0')}`)
  }
  const goToPrevMonth = () => {
    const date = new Date(`${month()}-01`)
    date.setMonth(date.getMonth() - 1)
    setMonth(date.toISOString().slice(0, 7))
  }
  const goToNextMonth = () => {
    const date = new Date(`${month()}-01`)
    date.setMonth(date.getMonth() + 1)
    setMonth(date.toISOString().slice(0, 7))
  }

  // Load historical improvements data for trend chart
  const loadImprovements = async () => {
    try {
      const data = await apiGet<BudgetImprovement[]>(`/api/budgets/improvements?months=6`)
      setImprovements(data || [])
    } catch {
      // History loading is best-effort
    }
  }

  // Duplicate budgets from previous month
  const duplicateLastMonth = async () => {
    const [year, mon] = month().split('-')
    try {
      const result = await apiPost<{ ok: boolean; count?: number; message?: string }>(
        '/api/budgets/duplicate-last',
        {
          year: parseInt(year),
          month: parseInt(mon),
        }
      )
      if (result.ok) {
        showToast(`Duplicated ${result.count} budgets from last month`, 'success')
        await refetchBudget()
      } else {
        showToast(result.message || 'Nothing to duplicate', 'info')
      }
    } catch (_err) {
      showToast('Failed to duplicate budgets', 'error')
    }
  }

  // Set budgets from previous month's expenses
  const setFromExpenses = async () => {
    const [year, mon] = month().split('-')
    try {
      const result = await apiPost<{ ok: boolean; count?: number; message?: string }>(
        '/api/budgets/from-expenses',
        {
          year: parseInt(year),
          month: parseInt(mon),
        }
      )
      if (result.ok) {
        showToast(`Set ${result.count} budgets from last month's expenses`, 'success')
        await refetchBudget()
      } else {
        showToast(result.message || 'No expenses found', 'info')
      }
    } catch (_err) {
      showToast('Failed to set budgets from expenses', 'error')
    }
  }

  // Toggle rollover for a budget
  const toggleRollover = async (budgetId: number, enabled: boolean) => {
    try {
      await apiPut(`/api/budgets/${budgetId}/rollover`, {
        rollover_enabled: enabled,
      })
      showToast(enabled ? 'Rollover enabled' : 'Rollover disabled', 'success')
      await refetchBudget()
    } catch {
      showToast('Failed to update rollover', 'error')
    }
  }

  // Allocate budget to a category
  const allocateBudget = async () => {
    const allocNum = parseFloat(allocateAmount()) || 0
    if (!selectedCategory() || allocNum <= 0) {
      return
    }

    try {
      await apiPost('/api/budgets/allocate', {
        category_id: selectedCategory()!.category_id,
        amount: allocNum,
        period: 'monthly',
      })

      showToast('Budget allocated successfully!', 'success')
      setShowAllocateModal(false)
      setAllocateAmount('')
      refetchBudget()
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to allocate budget')
      showToast('Failed to allocate budget', 'error')
    }
  }

  // Theme-aware chart colors (Canvas API doesn't resolve CSS custom properties)
  const chartColors = () => theme.getChartColors()

  // Format currency
  const formatCurrency = (value: number) => {
    const currency = getLocalCurrency()
    return new Intl.NumberFormat(undefined, {
      style: 'currency',
      currency,
    }).format(value)
  }

  // Get status class
  const getStatusClass = (status: AllocationStatus) => {
    switch (status) {
      case 'over':
        return 'status-over'
      case 'warning':
        return 'status-warning'
      default:
        return 'status-ok'
    }
  }

  // Show allocate modal for a category
  const openAllocateModal = (category: CategoryAllocation) => {
    setSelectedCategory(category)
    setAllocateAmount('')
    setBudgetMessage('')
    setShowAllocateModal(true)
  }

  // Load categories
  const loadCategories = async () => {
    try {
      const [allRes, budgetRes] = await Promise.all([
        apiGet<Category[]>('/api/categories'),
        apiGet<any[]>(
          `/api/budgets/summary?year=${currentYearNum()}&month=${currentMonthNum()}`
        ).catch((): any[] => []),
      ])
      setCategories(allRes)
      const summary: Record<
        number,
        { spent: number; budget: number; remaining: number; percent_used: number }
      > = {}
      if (Array.isArray(budgetRes)) {
        for (const b of budgetRes) {
          summary[b.category_id] = {
            spent: b.spent || 0,
            budget: b.amount || 0,
            remaining: b.remaining || 0,
            percent_used: b.percentage || 0,
          }
        }
      }
      setCategoryBudgetSummary(summary)
    } catch (err) {
      console.error('Failed to load categories:', err)
    }
  }

  // Handle category form submit
  const handleCatSubmit = async (e: Event) => {
    e.preventDefault()
    const data = {
      name: catFormData().name,
      type: catFormData().type,
      color: catFormData().color,
      icon: catFormData().icon || null,
    }

    try {
      if (editingCategory()) {
        await apiPut(`/api/categories/${editingCategory()!.id}`, data)
        showToast('Category updated successfully', 'success')
      } else {
        await apiPost('/api/categories', data)
        showToast('Category created successfully', 'success')
      }
      setShowCatModal(false)
      setEditingCategory(null)
      setCatFormData({ name: '', type: 'expense', color: '#3b82f6', icon: '' })
      loadCategories()
    } catch (err) {
      console.error('Failed to save category:', err)
      showToast('Failed to save category', 'error')
    }
  }

  // Delete category
  const deleteCategory = async (id: number) => {
    try {
      await apiDelete(`/api/categories/${id}`)
      showToast('Category deleted successfully', 'success')
      loadCategories()
    } catch (err) {
      console.error('Failed to delete category:', err)
      showToast('Failed to delete category', 'error')
    }
  }

  // Update category color
  const updateCategoryColor = async (id: number, color: string) => {
    try {
      await apiPut(`/api/categories/${id}`, { color })
      loadCategories()
    } catch (err) {
      console.error('Failed to update color:', err)
      showToast('Failed to update color', 'error')
    }
  }

  // Edit category
  const editCategory = (category: Category) => {
    setEditingCategory(category)
    setCatFormData({
      name: category.name,
      type: category.type,
      color: category.color,
      icon: category.icon || '',
    })
    setShowCatModal(true)
  }

  // Open budget modal for a category
  const openCatBudgetModal = (category: Category) => {
    setSelectedCat(category)
    setCatBudgetAmount('')
    setShowCatBudgetModal(true)
  }

  // Update budget for a category
  const updateCatBudget = async (amount: number) => {
    if (!selectedCat()) return
    try {
      const now = new Date()
      const startDate = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-01`
      await apiPost('/api/budgets', {
        category_id: selectedCat()!.id,
        amount,
        period: 'monthly',
        start_date: startDate,
      })
      showToast('Budget set successfully', 'success')
      setShowCatBudgetModal(false)
      setSelectedCat(null)
      loadCategories()
    } catch (err) {
      console.error('Failed to set budget', err)
      showToast('Failed to set budget', 'error')
    }
  }

  // Load improvements and categories once on mount
  onMount(() => {
    loadImprovements()
    loadCategories()
    loadYearRange()
  })

  // Reload when profile selection changes
  createEffect(() => {
    void state.profileVersion
    loadImprovements()
    loadCategories()
    loadYearRange()
  })

  // Reload categories when month changes (budget resource auto-refetches via source tracking)
  createEffect(() => {
    void month()
    loadCategories()
  })

  return (
    <div class={`page page-budgets page-enter ${styles.budgetsPage}`}>
      <div class={styles.pageHeader}>
        <div class={styles.headerTop}>
          <h1 data-test-id="budgets-header">Budgets</h1>
          <div data-test-id="month-selector" class={styles.monthSelector}>
            <button
              data-test-id="month-prev-btn"
              class={styles.btnGhost}
              onClick={goToPrevMonth}
              aria-label="Previous month"
            >
              <svg width="16" height="16" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path
                  stroke-linecap="round"
                  stroke-linejoin="round"
                  stroke-width="2"
                  d="M15 19l-7-7 7-7"
                />
              </svg>
            </button>
            <div class={styles.dropdownWrapper}>
              <button
                data-test-id="month-display"
                class={styles.monthBtn}
                onClick={() => {
                  setShowMonthPicker(!showMonthPicker())
                  setShowYearPicker(false)
                }}
              >
                {MONTHS[currentMonthNum() - 1]}
                <svg width="10" height="6" viewBox="0 0 10 6" fill="currentColor">
                  <path d="M5 6L0 0h10z" />
                </svg>
              </button>
              {showMonthPicker() && (
                <div class={styles.dropdown}>
                  <For each={MONTHS}>
                    {(name, i) => (
                      <button
                        class={styles.dropdownItem}
                        classList={{ [styles.selected]: i() + 1 === currentMonthNum() }}
                        onClick={() => {
                          setMonthNum(i() + 1)
                          setShowMonthPicker(false)
                        }}
                      >
                        {name}
                      </button>
                    )}
                  </For>
                </div>
              )}
            </div>
            <div class={styles.dropdownWrapper}>
              <button
                class={styles.yearBtn}
                onClick={() => {
                  setShowYearPicker(!showYearPicker())
                  setShowMonthPicker(false)
                }}
              >
                {currentYearNum()}
                <svg width="10" height="6" viewBox="0 0 10 6" fill="currentColor">
                  <path d="M5 6L0 0h10z" />
                </svg>
              </button>
              {showYearPicker() && (
                <div class={styles.dropdown}>
                  <For each={availableYears()}>
                    {(y) => (
                      <button
                        class={styles.dropdownItem}
                        classList={{ [styles.selected]: y === currentYearNum() }}
                        onClick={() => {
                          setYearNum(y)
                          setShowYearPicker(false)
                        }}
                      >
                        {y}
                      </button>
                    )}
                  </For>
                </div>
              )}
            </div>
            <button class={styles.btnGhost} onClick={goToNextMonth} aria-label="Next month">
              <svg width="16" height="16" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path
                  stroke-linecap="round"
                  stroke-linejoin="round"
                  stroke-width="2"
                  d="M9 5l7 7-7 7"
                />
              </svg>
            </button>
            {(showMonthPicker() || showYearPicker()) && (
              <div
                class={styles.overlay}
                onClick={() => {
                  setShowMonthPicker(false)
                  setShowYearPicker(false)
                }}
              />
            )}
          </div>
        </div>
        <p data-test-id="budgets-subtitle" class={styles.pageSubtitle}>
          Zero-based budgeting: allocate every dollar to a category
        </p>
      </div>

      {/* Budget Summary Cards */}
      <div data-test-id="budget-summary" class={styles.budgetSummary}>
        <div class={styles.summaryCard}>
          <div class={styles.summaryLabel}>Income</div>
          <div class={styles.summaryValue}>{formatCurrency(summary()?.income ?? 0)}</div>
        </div>
        <div class={styles.summaryCard}>
          <div class={styles.summaryLabel}>Allocated</div>
          <div class={styles.summaryValue}>{formatCurrency(summary()?.total_budget || 0)}</div>
        </div>
        <div class={styles.summaryCard}>
          <div class={styles.summaryLabel}>Spent</div>
          <div class={styles.summaryValue}>{formatCurrency(summary()?.total_spent || 0)}</div>
        </div>
        <div class={`${styles.summaryCard} ${styles.highlighted}`}>
          <div class={styles.summaryLabel}>Remaining</div>
          <div class={styles.summaryValue}>{formatCurrency(summary()?.remaining || 0)}</div>
        </div>
        <div class={styles.summaryCard}>
          <div class={styles.summaryLabel}>Unallocated</div>
          <div class={styles.summaryValue}>
            {formatCurrency(summary()?.zero_based_remaining || 0)}
          </div>
        </div>
      </div>

      {/* Category Allocation Chart */}
      <div class={styles.categoryChartSection}>
        <h3>Category Allocation</h3>
        <div class={styles.chartWrapper}>
          {allocations().length === 0 ? (
            <div class={styles.emptyState}>No allocations for this month</div>
          ) : (
            <Chart
              type="doughnut"
              data={{
                labels: allocations().map((a) => a.category_name),
                datasets: [
                  {
                    data: allocations().map((a) => a.allocated),
                    backgroundColor: allocations().map((a) => a.category_color || '#6b7280'),
                    borderWidth: 0,
                  },
                ],
              }}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                  legend: {
                    position: 'right',
                    labels: {
                      usePointStyle: true,
                      padding: 15,
                      font: { size: 12 },
                      color: chartColors().legend,
                    },
                  },
                },
              }}
              height={250}
              width="100%"
            />
          )}
        </div>
      </div>

      {/* Spending vs Budget Bar Chart */}
      {allocations().length > 0 && (
        <div class={styles.categoryChartSection}>
          <h3>Spending vs Budget</h3>
          <div class={styles.chartWrapper}>
            <Chart
              type="bar"
              data={{
                labels: allocations().map((a) => a.category_name),
                datasets: [
                  {
                    label: 'Budget',
                    data: allocations().map((a) => a.allocated),
                    backgroundColor: 'rgba(59, 130, 246, 0.6)',
                    borderColor: 'rgba(59, 130, 246, 1)',
                    borderWidth: 1,
                  },
                  {
                    label: 'Spent',
                    data: allocations().map((a) => a.spent),
                    backgroundColor: 'rgba(239, 68, 68, 0.6)',
                    borderColor: 'rgba(239, 68, 68, 1)',
                    borderWidth: 1,
                  },
                ],
              }}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                  legend: {
                    position: 'top',
                    labels: {
                      usePointStyle: true,
                      padding: 15,
                      font: { size: 12 },
                      color: chartColors().legend,
                    },
                  },
                },
                scales: {
                  x: { ticks: { color: chartColors().text }, grid: { color: chartColors().grid } },
                  y: {
                    beginAtZero: true,
                    ticks: {
                      callback: (value: any) => {
                        return new Intl.NumberFormat(undefined, {
                          style: 'currency',
                          currency: getLocalCurrency(),
                          minimumFractionDigits: 0,
                          maximumFractionDigits: 0,
                        }).format(value)
                      },
                      color: chartColors().text,
                    },
                    grid: { color: chartColors().grid },
                  },
                },
              }}
              height={300}
