              </div>
            </div>
            <div class={styles.modalFooter}>
              <button class={styles.btnGhost} onClick={() => setShowCatBudgetModal(false)}>
                Cancel
              </button>
              <button
                class={styles.btnPrimary}
                onClick={() => {
                  updateCatBudget(parseFloat(catBudgetAmount()) || 0)
                }}
              >
                Save Budget
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

/**
 * Categories Component - EARS Specification
 *
 * GIVEN: A user is viewing the Categories page
 * WHEN: The page loads
 * THEN: The header displays "Categories" and shows all expense and income categories
 *
 * GIVEN: A user wants to create a new category
 * WHEN: They click the "Create Category" button
 * THEN: A category creation modal opens with fields for name, type (expense/income), and color
 *
 * GIVEN: A user creates a category
 * WHEN: They enter a name, select a type, and choose a color
 * THEN: The new category appears in the list with its chosen color
 *
 * GIVEN: A user wants to edit a category
 * WHEN: They click the edit button on a category
 * THEN: The category details populate the edit form with existing values
 *
 * GIVEN: A user modifies a category
 * WHEN: They change the name or color and save
 * THEN: The category is updated throughout the application with the new values
 *
 * GIVEN: A user wants to delete a category
 * WHEN: They select a category and confirm deletion
 * THEN: The category is removed from the list
 */

/**
 * Categories Component
 * Manages expense and income categories with CRUD operations
 */
import { createEffect, createResource, createSignal, For, onMount } from 'solid-js'
import CategoryIcon from '../components/CategoryIcon'
import ConfirmButton from '../components/ConfirmButton'
import { formatCurrency } from '../core/api'
import { apiDelete, apiGet, apiPost, apiPut, showToast } from '../core/api'
import { useAppState } from '../core/appStore'
import styles from './CategoriesPage.module.css'

interface Category {
  id: number
  name: string
  type: 'expense' | 'income'
  color: string
  icon: string | null
  profile_id: number
  budget?: number
}

export default function Categories() {
  const state = useAppState()

  // Categories resource — fetches categories + budget summary
  const [categoriesResource, { refetch: refetchCategories }] = createResource(
    () => state.profileVersion,
    async () => {
      const [allRes, budgetRes] = await Promise.all([
        apiGet<Category[]>('/api/categories'),
        apiGet<any[]>('/api/budgets/summary').catch(() => [] as any[]),
      ])
      const summary: Record<
        number,
        { spent: number; budget: number; remaining: number; percent_used: number }
      > = {}
      if (Array.isArray(budgetRes)) {
        for (const b of budgetRes) {
          summary[b.category_id] = {
            spent: b.spent || 0,
            budget: b.amount || 0,
            remaining: b.remaining || 0,
            percent_used: b.percentage || 0,
          }
        }
      }
      return { categories: allRes, budgetSummary: summary }
    }
  )
  const loading = () => categoriesResource.loading && !categoriesResource()
  const categories = () => categoriesResource()?.categories ?? []
  const budgetSummary = () => categoriesResource()?.budgetSummary ?? {}

  const [showAddModal, setShowAddModal] = createSignal(false)
  const [showBudgetModal, setShowBudgetModal] = createSignal(false)
  const [editingCategory, setEditingCategory] = createSignal<Category | null>(null)
  const [selectedCategory, setSelectedCategory] = createSignal<Category | null>(null)
  const [budgetAmount, setBudgetAmount] = createSignal('')
  const [filterType, setFilterType] = createSignal<'all' | 'expense' | 'income'>('all')
  const [formData, setFormData] = createSignal({
    name: '',
    type: 'expense' as 'expense' | 'income',
    color: '#3b82f6',
    icon: '',
  })

  // Handle form submit
  const handleSubmit = async (e: Event) => {
    e.preventDefault()
    const data = {
      name: formData().name,
      type: formData().type,
      color: formData().color,
      icon: formData().icon || null,
    }

    try {
      if (editingCategory()) {
        await apiPut(`/api/categories/${editingCategory()!.id}`, data)
        showToast('Category updated successfully', 'success')
      } else {
        await apiPost('/api/categories', data)
        showToast('Category created successfully', 'success')
      }
      setShowAddModal(false)
      setEditingCategory(null)
      setFormData({ name: '', type: 'expense', color: '#3b82f6', icon: '' })
      refetchCategories()
    } catch (err) {
      console.error('Failed to save category:', err)
      showToast('Failed to save category', 'error')
    }
  }

  // Delete category
  const deleteCategory = async (id: number) => {
    try {
      await apiDelete(`/api/categories/${id}`)
      showToast('Category deleted successfully', 'success')
      refetchCategories()
    } catch (err) {
      console.error('Failed to delete category:', err)
      showToast('Failed to delete category', 'error')
    }
  }

  // Update category color
  const updateColor = async (id: number, color: string) => {
    try {
      await apiPut(`/api/categories/${id}`, { color })
      refetchCategories()
    } catch (err) {
      console.error('Failed to update color:', err)
      showToast('Failed to update color', 'error')
    }
  }

  // Open edit modal
  const editCategory = (category: Category) => {
    setEditingCategory(category)
    setFormData({
      name: category.name,
      type: category.type,
      color: category.color,
      icon: category.icon || '',
    })
    setShowAddModal(true)
  }

  // Open budget modal
  const openBudgetModal = (category: Category) => {
    setSelectedCategory(category)
    setBudgetAmount('')
    setShowBudgetModal(true)
  }

  // Update budget
  const updateBudget = async (amount: number) => {
    if (!selectedCategory()) return
    try {
      const now = new Date()
      const startDate = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-01`
      await apiPost('/api/budgets', {
        category_id: selectedCategory()!.id,
        amount,
        period: 'monthly',
        start_date: startDate,
      })
      showToast('Budget set successfully', 'success')
      setShowBudgetModal(false)
      setSelectedCategory(null)
      refetchCategories()
    } catch (err) {
      console.error('Failed to set budget', err)
      showToast('Failed to set budget', 'error')
    }
  }

  // OnMount
  onMount(() => {
    refetchCategories()
  })
  createEffect(() => {
    void state.profileVersion
    void refetchCategories()
  })

  const categoryIconColors: Record<string, string> = {
    '#ef4444': 'bg-red-100 text-red-600',
    '#f97316': 'bg-orange-100 text-orange-600',
    '#eab308': 'bg-yellow-100 text-yellow-600',
    '#22c55e': 'bg-green-100 text-green-600',
    '#3b82f6': 'bg-blue-100 text-blue-600',
    '#8b5cf6': 'bg-violet-100 text-violet-600',
    '#ec4899': 'bg-pink-100 text-pink-600',
    '#6b7280': 'bg-gray-100 text-gray-600',
  }

  const getIconClass = (color: string): string => {
    return categoryIconColors[color] || 'bg-blue-100 text-blue-600'
  }

  return (
    <div class={`page page-categories page-enter ${styles.categoriesPage}`}>
      <div class={styles.pageHeader}>
        <div class={styles.headerTop}>
          <h1 data-test-id="categories-header">Categories</h1>
          <button
            data-test-id="add-category-btn"
            class={styles.addCategoryBtn}
            onClick={() => setShowAddModal(true)}
          >
            <svg width="16" height="16" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
            </svg>
            Add Category
          </button>
        </div>
        <p data-test-id="categories-subtitle" class={styles.pageSubtitle}>
          Organize your transactions with expense and income categories
        </p>
      </div>

      <div data-test-id="category-tabs" class={styles.categoriesTabs}>
        <button
          data-test-id="tab-all"
          class={`${styles.tab} ${filterType() === 'all' ? styles.active : ''}`}
          onClick={() => setFilterType('all')}
        >
          All Categories
        </button>
        <button
          data-test-id="tab-expense"
          class={`${styles.tab} ${filterType() === 'expense' ? styles.active : ''}`}
          onClick={() => setFilterType('expense')}
        >
          Expenses
        </button>
        <button
          data-test-id="tab-income"
          class={`${styles.tab} ${filterType() === 'income' ? styles.active : ''}`}
          onClick={() => setFilterType('income')}
        >
          Income
        </button>
      </div>

      {loading() ? (
        <div data-test-id="loading-state" class={styles.emptyState}>
          Loading categories...
        </div>
      ) : categories().length === 0 ? (
        <div class={styles.emptyState}>
          <p>No categories yet</p>
          <p>Create your first category to start organizing your transactions.</p>
          <button class={styles.addCategoryBtn} onClick={() => setShowAddModal(true)}>
            Add Category
          </button>
        </div>
      ) : (
        <div data-test-id="categories-grid" class={styles.categoriesGrid}>
          <For
            each={categories().filter((c) =>
              filterType() === 'all' ? true : c.type === filterType()
            )}
          >
            {(category) => {
              const iconClass = getIconClass(category.color)
              const summary = budgetSummary()[category.id]
              const spent = summary?.spent || 0
              const budget = summary?.budget || 0
              const remaining = summary?.remaining ?? budget - spent
              const percentUsed = summary?.percent_used || 0
              const isOverBudget = percentUsed > 100

              return (
                <div data-test-id="category-card" class={styles.categoryCard}>
                  <div class={styles.categoryHeader}>
                    <div
                      data-test-id="category-color"
                      class={`${styles.categoryIcon} ${iconClass}`}
                    >
                      <CategoryIcon name={category.name} icon={category.icon} size={18} />
                    </div>
                    <div class={styles.categoryInfo}>
                      <h3 data-test-id="category-name" class={styles.categoryName}>
                        {category.name}
                      </h3>
                      <span class={styles.categoryType}>{category.type}</span>
                    </div>
                    <div class={styles.categoryActions}>
                      <button
                        class={`${styles.btnSm} ${styles.btnGhost}`}
                        onClick={() => {
                          openBudgetModal(category)
                        }}
                      >
                        <svg
                          width="16"
                          height="16"
                          fill="none"
                          stroke="currentColor"
                          viewBox="0 0 24 24"
                        >
                          <path d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                        </svg>
                        Budget
                      </button>
                      <button
                        data-test-id="edit-category-btn"
                        class={`${styles.btnSm} ${styles.btnGhost}`}
                        onClick={() => {
                          editCategory(category)
                        }}
                      >
                        <svg
                          width="16"
                          height="16"
                          fill="none"
                          stroke="currentColor"
                          viewBox="0 0 24 24"
                        >
                          <path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                        </svg>
                      </button>
                      <ConfirmButton
                        class={`${styles.btnSm} ${styles.btnGhost}`}
                        onConfirm={() => deleteCategory(category.id)}
                        label={
                          <svg
                            width="16"
                            height="16"
                            fill="none"
                            stroke="currentColor"
                            viewBox="0 0 24 24"
                          >
                            <path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                          </svg>
                        }
                      />
                    </div>
                  </div>
                  <div data-test-id="category-spending" class={styles.categorySpending}>
                    <div class={styles.spendingHeader}>
                      <span class={styles.spendingLabel}>Spent</span>
                      <span class={`${styles.spendingAmount} ${isOverBudget ? styles.over : ''}`}>
                        {formatCurrency(spent)}
                      </span>
                    </div>
                    {category.type === 'expense' && budget > 0 && (
                      <>
                        <div class={styles.progressBar}>
                          <div
                            class={`${styles.progressFill} ${isOverBudget ? styles.over : ''}`}
                            style={{ width: `${Math.min(100, percentUsed)}%` }}
                          />
                        </div>
                        <div class={styles.spendingFooter}>
                          <span class={styles.budgetLimits}>{formatCurrency(budget)} limit</span>
                          <span
                            class={`${styles.remainingAmount} ${isOverBudget ? styles.over : ''}`}
                          >
                            {formatCurrency(remaining)} remaining
                          </span>
                        </div>
                      </>
                    )}
                  </div>
                  <div class={styles.categoryColors}>
                    <span class={styles.colorLabel}>Color:</span>
                    <div class={styles.colorPicker}>
                      <For
                        each={[
                          '#ef4444',
                          '#f97316',
                          '#eab308',
                          '#22c55e',
                          '#3b82f6',
                          '#8b5cf6',
                          '#ec4899',
                          '#6b7280',
                        ]}
                      >
                        {(color) => (
                          <button
                            class={`${styles.colorBtn} ${category.color === color ? styles.active : ''}`}
                            style={{ background: color }}
                            onClick={() => updateColor(category.id, color)}
                            title={color}
                          >
                            {category.color === color && (
                              <svg
                                width="12"
                                height="12"
                                fill="none"
                                stroke="white"
                                stroke-width="3"
                                viewBox="0 0 24 24"
                              >
                                <path d="M20 6L9 17l-5-5" />
                              </svg>
                            )}
                          </button>
                        )}
                      </For>
                    </div>
                  </div>
                </div>
              )
            }}
          </For>
        </div>
      )}

      {/* Add/Edit Modal */}
      {showAddModal() && (
        <div
          class={styles.modalOverlay}
          data-test-id="category-modal-overlay"
          onclick={(e) => {
            if (e.target === e.currentTarget) {
              setShowAddModal(false)
              setEditingCategory(null)
              setFormData({ name: '', type: 'expense', color: '#3b82f6', icon: '' })
            }
          }}
        >
          <div
            class={styles.modal}
            onclick={(e) => {
              e.stopPropagation()
            }}
          >
            <div class={styles.modalHeader}>
              <h3 class={styles.modalTitle} data-test-id="category-modal-title">
                {editingCategory() ? 'Edit Category' : 'Add Category'}
              </h3>
              <button
                class={styles.modalClose}
                onClick={() => {
                  setShowAddModal(false)
                  setEditingCategory(null)
                  setFormData({ name: '', type: 'expense', color: '#3b82f6', icon: '' })
                }}
              >
                <svg width="24" height="24" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
            <form class={styles.modalBody} onSubmit={handleSubmit}>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Category Name</label>
                <input
                  type="text"
                  class={styles.formControl}
                  placeholder="e.g., Food, Rent"
                  value={formData().name}
                  oninput={(e) => setFormData({ ...formData(), name: e.target.value })}
                  required
                />
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Category Type</label>
                <select
                  class={styles.formControl}
                  value={formData().type}
                  oninput={(e) => setFormData({ ...formData(), type: e.target.value as any })}
                >
                  <option value="expense">Expense</option>
                  <option value="income">Income</option>
                </select>
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Icon (emoji)</label>
                <input
                  type="text"
                  class={styles.formControl}
                  placeholder="e.g., food, home, car"
                  value={formData().icon}
                  oninput={(e) => setFormData({ ...formData(), icon: e.target.value })}
                  maxlength="2"
                />
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Color</label>
                <div class={styles.colorPicker}>
                  <For
                    each={[
                      '#ef4444',
                      '#f97316',
                      '#eab308',
                      '#22c55e',
                      '#3b82f6',
                      '#8b5cf6',
                      '#ec4899',
                      '#6b7280',
                    ]}
                  >
                    {(color) => (
                      <button
                        class={`${styles.colorPickerBtn} ${formData().color === color ? styles.active : ''}`}
                        style={{ background: color }}
                        onClick={() => setFormData({ ...formData(), color })}
                        title={color}
                      >
                        {formData().color === color && (
                          <svg
                            width="14"
                            height="14"
                            fill="none"
                            stroke="white"
                            stroke-width="3"
                            viewBox="0 0 24 24"
                          >
                            <path d="M20 6L9 17l-5-5" />
                          </svg>
                        )}
                      </button>
                    )}
                  </For>
                </div>
              </div>
              <div class={styles.modalFooter}>
                <button
                  type="button"
                  class={styles.btnSecondary}
                  onClick={() => {
                    setShowAddModal(false)
                    setEditingCategory(null)
                    setFormData({ name: '', type: 'expense', color: '#3b82f6', icon: '' })
                  }}
                >
                  Cancel
                </button>
                <button type="submit" class={styles.btnPrimary}>
                  {editingCategory() ? 'Update' : 'Add'} Category
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Budget Modal */}
      {showBudgetModal() && selectedCategory() && (
        <div
          class={styles.modalOverlay}
          onclick={(e) => {
            if (e.target === e.currentTarget) setShowBudgetModal(false)
          }}
        >
          <div
            class={styles.modal}
            onclick={(e) => {
              e.stopPropagation()
            }}
          >
            <div class={styles.modalHeader}>
              <h3 class={styles.modalTitle}>Set Budget</h3>
              <button class={styles.modalClose} onClick={() => setShowBudgetModal(false)}>
                <svg width="24" height="24" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
            <div class={styles.modalBody}>
              <p class={styles.modalText}>
                Set a monthly budget for <strong>{selectedCategory()!.name}</strong>
              </p>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Monthly Budget Amount</label>
                <input
                  type="number"
                  step="0.01"
                  class={styles.formControl}
                  placeholder="500.00"
                  value={budgetAmount()}
                  oninput={(e) => setBudgetAmount((e.target as HTMLInputElement).value)}
                />
              </div>
            </div>
            <div class={styles.modalFooter}>
              <button class={styles.btnSecondary} onClick={() => setShowBudgetModal(false)}>
                Cancel
              </button>
              <button
                class={styles.btnPrimary}
                onClick={() => {
                  updateBudget(parseFloat(budgetAmount()) || 0)
                }}
              >
                Save Budget
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

/**
 * Compound Interest Projector Component - EARS Specification
 *
 * GIVEN: A user is on the Compound Interest page
 * WHEN: The page loads
 * THEN: The header displays "Compound Interest" and default calculation form appears
 *
 * GIVEN: A user enters investment parameters
 * WHEN: They input principal, monthly contribution, return rate, and years
 * THEN: The calculator immediately projects the investment growth
 *
 * GIVEN: A user views results
 * WHEN: The calculation completes
 * THEN: Charts display projected balance over time with contribution and interest breakdown
 *
 * GIVEN: A user creates comparison scenarios
 * WHEN: They add scenarios with different return rates
 * THEN: Multiple lines are shown on the chart for comparison
 */

/**
 * Compound Interest Projector Component
 * Calculates investment growth with scenario comparisons
 */
import { createSignal, For, onCleanup } from 'solid-js'
import Chart from '../components/Chart'
import ExportChartButton from '../components/ExportChartButton'
import { formatCurrency } from '../core/api'
import { apiPost, showToast } from '../core/api'
import { theme } from '../core/theme'
import sharedStyles from './CalculatorShared.module.css'
import styles from './CompoundInterestCalculator.module.css'

interface CompoundInterestResult {
  projection: Array<{ year: number; balance: number; contributions: number; interest: number }>
  principal: number
  monthlyContribution: number
  annualReturn: number
  years: number
  finalBalance: number
  totalContributions: number
  totalInterest: number
  scenarios: Array<{
    name: string
    return: number
    color: string
    finalBalance: number
    totalContributions: number
    interest: number
  }>
}

interface FormState {
  principal: string
  monthlyContribution: string
  annualReturn: string
  years: string
}

export default function CompoundInterestCalculator() {
  const [loading, setLoading] = createSignal(false)
  const chartColors = () => theme.getChartColors()
  const [results, setResults] = createSignal<CompoundInterestResult | null>(null)
  const [form, setForm] = createSignal<FormState>({
    principal: '10000',
    monthlyContribution: '500',
    annualReturn: '7',
    years: '10',
  })

  const calculate = async () => {
    setLoading(true)
    try {
      const f = form()
      const n = (s: string) => parseFloat(s.replace(',', '.')) || 0
      const payload = {
        principal: n(f.principal),
        monthlyContribution: n(f.monthlyContribution),
        annualReturn: n(f.annualReturn),
        years: parseInt(f.years) || 0,
      }
      const data = await apiPost('/api/calculator/compound-interest', payload)
      setResults(data as CompoundInterestResult)
    } catch (e: any) {
      showToast(e.message || 'Calculation failed', 'error')
    } finally {
      setLoading(false)
    }
  }

  // Auto-calculate on mount and debounced
  let debounceTimer: number | null = null

  onCleanup(() => {
    if (debounceTimer) clearTimeout(debounceTimer)
  })

  onCalculate()

  function onCalculate() {
    if (debounceTimer) clearTimeout(debounceTimer)
    debounceTimer = window.setTimeout(() => calculate(), 400)
  }

  const updateForm = (field: keyof FormState, value: string) => {
    setForm({ ...form(), [field]: value })
    onCalculate()
  }

  const summary = () => {
    const r = results()
    if (!r) return null
    return {
      finalBalance: r.finalBalance,
      contributions: r.totalContributions,
      interest: r.totalInterest,
      scenarios: r.scenarios,
    }
  }

  const [chartRef, setChartRef] = createSignal<any>(undefined)

  return (
    <div class={sharedStyles.page}>
      <div class={sharedStyles.pageHeader}>
        <h1>Compound Interest Projector</h1>
        <p>Project investment growth over time</p>
      </div>

      <div class={styles.calcContainer}>
        {/* Calculator Form */}
        <div class={styles.calcSection}>
          <h3 class={styles.calcTitle}>Investment Parameters</h3>
          <div class={styles.formGrid}>
            <div class={styles.formGroup}>
              <label>Initial Investment</label>
              <input
                type="number"
                step="100"
                value={form().principal}
                oninput={(e) => {
                  updateForm('principal', e.target.value)
                }}
              />
            </div>
            <div class={styles.formGroup}>
              <label>Monthly Contribution</label>
              <input
                type="number"
                step="100"
                value={form().monthlyContribution}
                oninput={(e) => {
                  updateForm('monthlyContribution', e.target.value)
                }}
              />
            </div>
            <div class={styles.formGroup}>
              <label>Annual Return (%)</label>
              <input
                type="text"
                inputmode="decimal"
