/**
 * Counterparties Page
 * Aggregates beneficiary/payor data to show "who owes who"
 */
import { createEffect, createMemo, createSignal, For, onMount } from 'solid-js'
import { formatCurrency } from '../core/api'
import { apiGet } from '../core/api'
import { useAppState } from '../core/appStore'
import styles from './CounterpartiesPage.module.css'

interface Counterparty {
  name: string
  incoming: number
  outgoing: number
  net: number
  transaction_count: number
}

type SortField = 'name' | 'incoming' | 'outgoing' | 'net' | 'transaction_count'

export default function Counterparties() {
  const state = useAppState()
  const [counterparties, setCounterparties] = createSignal<Counterparty[]>([])
  const [loading, setLoading] = createSignal(true)
  const [sortField, setSortField] = createSignal<SortField>('net')
  const [sortAsc, setSortAsc] = createSignal(false)

  const loadData = async () => {
    try {
      const data = await apiGet<Counterparty[]>('/api/counterparties')
      if (Array.isArray(data)) {
        setCounterparties(data)
      }
    } catch {
      // keep empty
    } finally {
      setLoading(false)
    }
  }

  onMount(() => {
    void loadData()
  })
  createEffect(() => {
    void state.profileVersion
    void loadData()
  })

  const handleSort = (field: SortField) => {
    if (sortField() === field) {
      setSortAsc(!sortAsc())
    } else {
      setSortField(field)
      setSortAsc(field === 'name')
    }
  }

  const sorted = createMemo(() => {
    const list = [...counterparties()]
    list.sort((a, b) => {
      const aVal = a[sortField()]
      const bVal = b[sortField()]
      const cmp =
        typeof aVal === 'string'
          ? aVal.localeCompare(bVal as string)
          : (aVal as number) - (bVal as number)
      return sortAsc() ? cmp : -cmp
    })
    return list
  })

  const sortIndicator = (field: SortField) => {
    if (sortField() !== field) return ''
    return sortAsc() ? ' ↑' : ' ↓'
  }

  const totalOwed = createMemo(() => {
    let sum = 0
    for (const c of counterparties()) {
      if (c.net < 0) sum += Math.abs(c.net)
    }
    return sum
  })

  const totalOwing = createMemo(() => {
    let sum = 0
    for (const c of counterparties()) {
      if (c.net > 0) sum += c.net
    }
    return sum
  })

  const netPosition = createMemo(() => {
    let sum = 0
    for (const c of counterparties()) sum += c.net
    return sum
  })

  return (
    <div class={`${styles.page} page page-counterparties page-enter`}>
      <div class={styles.pageHeader}>
        <div>
          <h2>Counterparties</h2>
          <p>Aggregated view of who you pay and who pays you</p>
        </div>
      </div>

      {loading() ? (
        <div class={styles.loadingState}>Loading counterparties...</div>
      ) : counterparties().length === 0 ? (
        <div class={styles.emptyState}>
          <p>No counterparty data yet</p>
          <p>Transactions with beneficiary or payor fields will appear here.</p>
        </div>
      ) : (
        <>
          <div class={styles.summaryRow}>
            <div class={styles.summaryCard}>
              <div class={styles.summaryLabel}>We Owe</div>
              <div class={`${styles.summaryValue} ${styles.negative}`}>
                {formatCurrency(totalOwed())}
              </div>
            </div>
            <div class={styles.summaryCard}>
              <div class={styles.summaryLabel}>Owed to Us</div>
              <div class={`${styles.summaryValue} ${styles.positive}`}>
                {formatCurrency(totalOwing())}
              </div>
            </div>
            <div class={styles.summaryCard}>
              <div class={styles.summaryLabel}>Net Position</div>
              <div
                class={`${styles.summaryValue} ${netPosition() >= 0 ? styles.positive : styles.negative}`}
              >
                {formatCurrency(netPosition())}
              </div>
            </div>
          </div>

          <div class={styles.tableWrap}>
            <table class={styles.table}>
              <thead>
                <tr>
                  <th
                    onClick={() => {
                      handleSort('name')
                    }}
                  >
                    Counterparty{sortIndicator('name')}
                  </th>
                  <th
                    onClick={() => {
                      handleSort('incoming')
                    }}
                  >
                    Received{sortIndicator('incoming')}
                  </th>
                  <th
                    onClick={() => {
                      handleSort('outgoing')
                    }}
                  >
                    Paid{sortIndicator('outgoing')}
                  </th>
                  <th
                    onClick={() => {
                      handleSort('net')
                    }}
                  >
                    Net{sortIndicator('net')}
                  </th>
                  <th
                    onClick={() => {
                      handleSort('transaction_count')
                    }}
                  >
                    Txs{sortIndicator('transaction_count')}
                  </th>
                </tr>
              </thead>
              <tbody>
                <For each={sorted()}>
                  {(c) => (
                    <tr>
                      <td>
                        <span class={styles.counterpartyName}>{c.name}</span>
                      </td>
                      <td>
                        <span class={`${styles.amount} ${styles.incoming}`}>
                          {formatCurrency(c.incoming)}
                        </span>
                      </td>
                      <td>
                        <span class={`${styles.amount} ${styles.outgoing}`}>
                          {formatCurrency(c.outgoing)}
                        </span>
                      </td>
                      <td>
                        <span
                          class={
                            c.net > 0
                              ? styles.netPositive
                              : c.net < 0
                                ? styles.netNegative
                                : styles.netNeutral
                          }
                        >
                          {formatCurrency(c.net)}
                        </span>
                      </td>
                      <td>
                        <span class={styles.count}>{c.transaction_count}</span>
                      </td>
                    </tr>
                  )}
                </For>
              </tbody>
            </table>
          </div>
        </>
      )}
    </div>
  )
}

/**
 * Dashboard Component
 */

import { createEffect, createSignal, For, onMount, Show } from 'solid-js'
import { ChartErrorBoundary } from '../components/ChartErrorBoundary'
import ChartWrapper from '../components/ChartWrapper'
import BudgetAlertsCard from '../components/Dashboard/BudgetAlertsCard'
import { PeriodNavigator } from '../components/Dashboard/PeriodNavigator'
import RecurringInsightsCard from '../components/Dashboard/RecurringInsightsCard'
import SavingsRateCard from '../components/Dashboard/SavingsRateCard'
import { DashboardSettings } from '../components/DashboardSettings'
import { PeriodPills } from '../components/PeriodPills'
import { api, formatCurrency, formatDate, toast } from '../core/api'
import { useAppState } from '../core/appStore'
import styles from './DashboardPage.module.css'
import type * as Models from '../types/models'

const DEFAULT_WIDGET_ORDER = [
  'metrics',
  'category-chart',
  'recent-transactions',
  'upcoming-bills',
  'savings-rate',
  'budget-alerts',
  'recurring-insights',
  'income-vs-expenses',
]

const DEFAULT_VISIBLE = [
  'metrics',
  'category-chart',
  'recent-transactions',
  'upcoming-bills',
  'savings-rate',
  'budget-alerts',
]

function loadWidgetPrefs() {
  const saved = localStorage.getItem('dashboard_widgets')
  if (saved) {
    try {
      const parsed = JSON.parse(saved)
      const visible =
        parsed.visibleWidgets && Array.isArray(parsed.visibleWidgets)
          ? parsed.visibleWidgets
          : DEFAULT_VISIBLE
      const order =
        parsed.widgetOrder && Array.isArray(parsed.widgetOrder) && parsed.widgetOrder.length > 0
          ? parsed.widgetOrder
          : DEFAULT_WIDGET_ORDER
      return { visible, order }
    } catch {
      /* ignore */
    }
  }
  return { visible: DEFAULT_VISIBLE, order: DEFAULT_WIDGET_ORDER }
}

export default function Dashboard() {
  const state = useAppState()
  const [month, setMonth] = createSignal(5)
  const [year, setYear] = createSignal(2026)
  const [metrics, setMetrics] = createSignal<Models.DashboardMetrics | null>(null)
  const [monthlyData, setMonthlyData] = createSignal<Models.DashboardChartData | null>(null)
  const [loading, setLoading] = createSignal(true)
  const [pillPeriod, setPillPeriod] = createSignal('month')
  const [allTime, setAllTime] = createSignal(false)
  const [dataMinYear, setDataMinYear] = createSignal<number | undefined>(undefined)
  const [dataMaxYear, setDataMaxYear] = createSignal<number | undefined>(undefined)
  const [dataYears, setDataYears] = createSignal<number[] | undefined>(undefined)
  const [showSettingsModal, setShowSettingsModal] = createSignal(false)

  const prefs = loadWidgetPrefs()
  const [visibleWidgets, setVisibleWidgets] = createSignal<string[]>(prefs.visible)
  const [widgetOrder, setWidgetOrder] = createSignal<string[]>(prefs.order)

  const [savingsGoal, setSavingsGoal] = createSignal(
    (() => {
      const stored = localStorage.getItem('savingsGoal')
      return stored ? parseFloat(stored) : 20
    })()
  )

  const handleSavingsGoalChange = (num: number) => {
    if (!isNaN(num) && num >= 0) {
      setSavingsGoal(num)
      localStorage.setItem('savingsGoal', String(num))
    }
  }

  onMount(() => {
    void loadMonthlyData()
    void loadYearRange()
  })

  createEffect(() => {
    void state.profileVersion
    void loadMonthlyData()
    void loadYearRange()
  })

  createEffect(() => {
    month()
    year()
    if (!allTime()) {
      void loadDashboard()
    }
  })

  const loadDashboard = async (dateFrom?: string, dateTo?: string) => {
    setLoading(true)
    try {
      const data = await api.getDashboard(month(), year(), dateFrom, dateTo, allTime())
      setMetrics(data)
    } catch {
      toast('Failed to load dashboard', 'error')
    } finally {
      setLoading(false)
    }
  }

  const loadYearRange = async () => {
    try {
      const { minYear, maxYear, years } = await api.getTransactionYears()
      setDataMinYear(minYear)
      setDataMaxYear(maxYear)
      setDataYears(years.length > 0 ? years : undefined)
    } catch {
      /* keep defaults */
    }
  }

  const loadMonthlyData = async (dateFrom?: string, dateTo?: string) => {
    try {
      const [_chartsData, netWorthData] = await Promise.all([
        api.getDashboardCharts(12),
        api.getNetWorth(),
      ])
      let timeline = netWorthData.timeline
      if (dateFrom && dateTo) {
        timeline = timeline.filter((t) => {
          const [y, m] = t.month.split('-')
          const tDate = `${y}-${m.padStart(2, '0')}-01`
          const fromKey = `${dateFrom.slice(0, 7)}-01`
          const toKey = `${dateTo.slice(0, 7)}-31`
          return tDate >= fromKey && tDate <= toKey
        })
      }
      const labels = timeline.map((t) => {
        const [y, m] = t.month.split('-')
        const date = new Date(parseInt(y), parseInt(m) - 1)
        return date.toLocaleDateString('en-US', { month: 'short', year: 'numeric' })
      })
      const netWorth = timeline.map((t) => t.balance)
      const income = timeline.map((t) => (t.netChange > 0 ? t.netChange : 0))
      const expenses = timeline.map((t) => (t.netChange < 0 ? Math.abs(t.netChange) : 0))
      setMonthlyData({ labels, income, expenses, netWorth })
    } catch {
      /* optional */
    }
  }

  const handlePillChange = async (pillId: string) => {
    setPillPeriod(pillId)
    setAllTime(pillId === 'all')
    const now = new Date()
    const fmt = (d: Date) => d.toISOString().slice(0, 10)

    let dateFrom = ''
    let dateTo = ''
    let m = now.getMonth() + 1
    const y = now.getFullYear()

    switch (pillId) {
      case 'today':
        dateFrom = fmt(now)
        dateTo = fmt(now)
        break
      case 'week': {
        const dayOfWeek = now.getDay()
        const mondayOffset = dayOfWeek === 0 ? -6 : 1 - dayOfWeek
        const monday = new Date(now.getFullYear(), now.getMonth(), now.getDate() + mondayOffset)
        const sunday = new Date(monday.getFullYear(), monday.getMonth(), monday.getDate() + 6)
        dateFrom = fmt(monday)
        dateTo = fmt(sunday)
        break
      }
      case 'month':
        dateFrom = fmt(new Date(y, m - 1, 1))
        dateTo = fmt(new Date(y, m, 0))
        break
      case 'quarter': {
        const qStartMonth = Math.floor((m - 1) / 3) * 3
        dateFrom = fmt(new Date(y, qStartMonth, 1))
        dateTo = fmt(new Date(y, qStartMonth + 3, 0))
        m = qStartMonth + 1
        break
      }
      case 'year':
        dateFrom = fmt(new Date(y, 0, 1))
        dateTo = fmt(new Date(y, 11, 31))
        break
      case 'last7':
        dateFrom = fmt(new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000))
        dateTo = fmt(now)
        break
      case 'last30':
        dateFrom = fmt(new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000))
        dateTo = fmt(now)
        break
      case 'last90':
        dateFrom = fmt(new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000))
        dateTo = fmt(now)
        break
      case 'all':
        dateFrom = ''
        dateTo = ''
        m = now.getMonth() + 1
        break
    }

    setMonth(m)
    setYear(y)
    await Promise.all([
      loadDashboard(dateFrom, dateTo),
      loadMonthlyData(dateFrom || undefined, dateTo || undefined),
    ])
  }

  const showSettings = () => setShowSettingsModal(true)

  const handleSettingsSave = () => {
    const prefs = loadWidgetPrefs()
    setVisibleWidgets(prefs.visible)
    setWidgetOrder(prefs.order)
    setShowSettingsModal(false)
  }

  const isWidgetVisible = (id: string) => visibleWidgets().includes(id)

  const renderWidget = (id: string) => {
    switch (id) {
      case 'budget-alerts':
        return (
          <div class={styles.widgetCard}>
            <div class={styles.widgetHeader}>
              <div class={styles.widgetTitle}>Budget Alerts</div>
              <a href="#budgets" class={styles.widgetLink}>View All</a>
            </div>
            <BudgetAlertsCard />
          </div>
        )
      case 'savings-rate':
        return (
          <div class={styles.widgetCard}>
            <div class={styles.widgetHeader}>
              <div class={styles.widgetTitle}>Savings Rate</div>
              <a href="#budgets" class={styles.widgetLink}>Details</a>
            </div>
            <SavingsRateCard
              savingsRate={
                metrics()!.totalIncome > 0
                  ? ((metrics()!.totalIncome - metrics()!.totalExpenses) /
                      metrics()!.totalIncome) *
                    100
                  : 0
              }
              monthlySavings={metrics()!.totalIncome - metrics()!.totalExpenses}
              goal={savingsGoal()}
              onGoalChange={handleSavingsGoalChange}
            />
          </div>
        )
      case 'category-chart':
        return (
          <div class={styles.card}>
            <div class={styles.cardHeader}>
              <div class={styles.cardTitle}>Spending by Category</div>
            </div>
            <div class={styles.chartContainerTall}>
              {metrics()!.expenseByCategory && metrics()!.expenseByCategory.length > 0 ? (
                <ChartErrorBoundary title="Spending by Category chart">
                  <ChartWrapper
                    type="doughnut"
                    data={{
                      labels: metrics()!.expenseByCategory.map(
                        (item: any) => item.category_name || 'Uncategorized'
                      ),
                      datasets: [
                        {
                          data: metrics()!.expenseByCategory.map((item: any) => item.total),
                          backgroundColor: [
                            '#dc2626', '#f97316', '#eab308', '#22c55e', '#06b6d4',
                            '#3b82f6', '#8b5cf6', '#ec4899', '#6b7280', '#14b8a6',
                          ],
                        },
                      ],
                    }}
                    options={{
                      plugins: {
                        legend: {
                          position: 'right',
                          align: 'start',
                          labels: {
                            padding: 8,
                            font: { size: 11 },
                            usePointStyle: true,
                            boxWidth: 8,
                          },
                        },
                      },
                    }}
                    height={400}
                    showExport
                    filename="spending-by-category"
                  />
                </ChartErrorBoundary>
              ) : (
                <div class={styles.emptyState}>No expense data to display</div>
              )}
            </div>
          </div>
        )
      case 'recent-transactions':
        return (
          <Show when={(metrics()!.recentTransactions?.length ?? 0) > 0}>
            <div class={styles.card}>
              <div class={styles.cardHeader}>
                <div class={styles.cardTitle}>Recent Transactions</div>
                <a href="#transactions" class={styles.btnLink}>View All →</a>
              </div>
              <div class={styles.transactionList}>
                <For each={metrics()!.recentTransactions.slice(0, 5)}>
                  {(tx) => (
                    <div class={styles.transactionItem}>
                      <div class={styles.transactionIcon} style={{ background: getIconColor(tx.type) }}>
                        {getIcon(tx.type)}
                      </div>
                      <div class={styles.transactionDetails}>
                        <div class={styles.transactionName}>{tx.description}</div>
                        <div class={styles.transactionMeta}>
                          {formatDate(tx.date)} •{' '}
                          {tx.category_name || (tx.category_id ? `#${tx.category_id}` : 'No category')}
                        </div>
                      </div>
                      <div
                        class={`${styles.transactionAmount} ${tx.type === 'expense' ? styles.expense : styles.income}`}
                      >
                        {tx.type === 'expense' ? '-' : '+'}
                        {formatCurrency(tx.amount)}
                      </div>
                    </div>
                  )}
                </For>
              </div>
            </div>
          </Show>
        )
      case 'upcoming-bills':
        return (
          <Show when={(metrics()!.upcomingBills?.length ?? 0) > 0}>
            <div class={styles.card}>
              <div class={styles.cardHeader}>
