function getIcon(type: string) {
  if (type === 'income') {
    return (
      <svg width="16" height="16" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M7 11l5-5m0 0l5 5m-5-5v12" />
      </svg>
    )
  }
  return (
    <svg width="16" height="16" fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M17 13l-5 5m0 0l-5-5m5 5V6" />
    </svg>
  )
}

function getIconColor(type: string): string {
  return type === 'expense' ? 'var(--danger)' : 'var(--income)'
}

function daysUntil(dateStr: string): string {
  const target = new Date(dateStr)
  const today = new Date()
  const diff = target.getTime() - today.getTime()
  const days = Math.ceil(diff / (1000 * 60 * 60 * 24))
  if (days < 0) return `${Math.abs(days)} days overdue`
  if (days === 0) return 'Due today'
  if (days === 1) return 'Due tomorrow'
  return `Due in ${days} days`
}

/**
 * Emergency Fund Tracker Component - EARS Specification
 *
 * GIVEN: A user is on the Emergency Fund page
 * WHEN: The page loads
 * THEN: The header displays "Emergency Fund" and shows monthly expenses and total fund
 *
 * GIVEN: A user has emergency fund data
 * WHEN: The page loads with data
 * THEN: The coverage chart shows how many months of expenses the fund can cover
 *
 * GIVEN: A user expands details
 * WHEN: They click to show details
 * THEN: A breakdown by month displays coverage percentages and status
 */

/**
 * Emergency Fund Tracker Component
 * Calculates monthly expenses and compares against savings account balances
 */
import { createSignal, For, onMount } from 'solid-js'
import Chart from '../components/Chart'
import ExportChartButton from '../components/ExportChartButton'
import { apiGet, formatCurrency, showToast } from '../core/api'
import { theme } from '../core/theme'
import sharedStyles from './CalculatorShared.module.css'
import styles from './EmergencyFundCalculator.module.css'

export default function EmergencyFundCalculator() {
  const chartColors = () => theme.getChartColors()
  const [monthlyExpenses, setMonthlyExpenses] = createSignal(0)
  const [totalEmergencyFund, setTotalEmergencyFund] = createSignal(0)
  const [monthsWithData, setMonthsWithData] = createSignal(0)
  const [coverage, setCoverage] = createSignal<any[]>([])
  const [loading, setLoading] = createSignal(false)
  const [showDetails, setShowDetails] = createSignal(false)

  onMount(() => {
    loadEmergencyFund()
  })

  const loadEmergencyFund = async () => {
    setLoading(true)
    try {
      const data: any = await apiGet('/api/calculator/emergency-fund')
      setMonthlyExpenses(data.avgMonthlyExpenses || 0)
      setTotalEmergencyFund(data.totalEmergencyFund || 0)
      setMonthsWithData(data.monthsWithData || 0)
      setCoverage(data.coverage || [])
    } catch (e: any) {
      showToast(e.message || 'Failed to load emergency fund data', 'error')
    } finally {
      setLoading(false)
    }
  }

  // _coverageData - placeholder (functionality can be extended)

  const [chartRef, setChartRef] = createSignal<any>(undefined)

  return (
    <div class={sharedStyles.page}>
      <div class={sharedStyles.pageHeader}>
        <h1>Emergency Fund Tracker</h1>
        <p>Calculate coverage based on monthly expenses</p>
      </div>

      {loading() ? (
        <div class={styles.loading}>Loading...</div>
      ) : (
        <>
          {/* Summary Cards */}
          <div class={styles.summaryGrid}>
            <div class={styles.summaryCard}>
              <div class={styles.summaryTitle}>Based on</div>
              <div class={styles.summaryValue}>{monthsWithData()} months</div>
              <div class={styles.summarySubtitle}>of transaction history</div>
            </div>
            <div class={styles.summaryCard}>
              <div class={styles.summaryTitle}>Average Monthly Expenses</div>
              <div class={styles.summaryValue}>{formatCurrency(monthlyExpenses(), 'EUR')}</div>
            </div>
            <div class={styles.summaryCard}>
              <div class={styles.summaryTitle}>Total Emergency Fund</div>
              <div class={styles.summaryValue}>{formatCurrency(totalEmergencyFund(), 'EUR')}</div>
            </div>
          </div>

          {/* Coverage Visualization */}
          <div class={styles.chartSection}>
            <Chart
              id="emergencyFundChart"
              type="bar"
              data={{
                labels: coverage().map((c) => c.label),
                datasets: [
                  {
                    label: 'Coverage',
                    data: coverage().map((c) => c.coveragePct),
                    backgroundColor: coverage().map((c) => {
                      if (c.status === 'complete') return 'rgba(16, 185, 129, 0.8)'
                      if (c.status === 'partial') return 'rgba(245, 158, 11, 0.8)'
                      return 'rgba(239, 68, 68, 0.8)'
                    }),
                    borderColor: coverage().map((c) => {
                      if (c.status === 'complete') return 'rgb(16, 185, 129)'
                      if (c.status === 'partial') return 'rgb(245, 158, 11)'
                      return 'rgb(239, 68, 68)'
                    }),
                    borderWidth: 2,
                  },
                ],
              }}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                scales: {
                  y: {
                    beginAtZero: true,
                    max: 100,
                    ticks: { color: chartColors().text },
                    grid: { color: chartColors().border },
                    title: { display: true, text: 'Coverage %', color: chartColors().text },
                  },
                  x: {
                    ticks: { color: chartColors().text },
                    grid: { color: chartColors().border },
                  },
                },
                plugins: {
                  legend: { display: false },
                },
              }}
              height={300}
              width="100%"
              onReady={(chart: any) => {
                setChartRef(chart)
              }}
            />
            <ExportChartButton
              chart={chartRef()}
              filename="emergency-fund-chart"
              variant="inline"
            />
          </div>

          {/* Coverage Details */}
          <div class={styles.detailsSection}>
            <div class={styles.detailsHeader}>
              <h3>Coverage Levels</h3>
              <button class={styles.toggleBtn} onClick={() => setShowDetails(!showDetails())}>
                {showDetails() ? 'Hide' : 'Show'} Details
              </button>
            </div>

            {showDetails() && (
              <div class={styles.coverageGrid}>
                <For each={coverage()}>
                  {(c) => (
                    <div class={`${styles.coverageItem} ${styles[c.status] || ''}`}>
                      <div class={styles.coverageTitle}>{c.label} Fund</div>
                      <div class={styles.coverageBars}>
                        <div class={styles.progressBar}>
                          <div
                            class={styles.progressFill}
                            style={{ width: `${c.coveragePct}%` }}
                          ></div>
                        </div>
                        <div class={styles.progressStats}>
                          <span>{formatCurrency(c.current, 'EUR')}</span>
                          <span>of {formatCurrency(c.required, 'EUR')}</span>
                        </div>
                      </div>
                      <div class={styles.coverageStatus}>{c.status}</div>
                    </div>
                  )}
                </For>
              </div>
            )}
          </div>
        </>
      )}
    </div>
  )
}

/**
 * Goals Component - EARS Specification
 *
 * GIVEN: A user is viewing the Goals page
 * WHEN: The page loads
 * THEN: The header displays "Goals" and shows all savings goals with progress bars
 *
 * GIVEN: A user wants to create a new savings goal
 * WHEN: They click the "Create Goal" button
 * THEN: A goal creation modal opens with fields for name, target amount, and target date
 *
 * GIVEN: A user has a savings goal
 * WHEN: They view the goal card
 * THEN: The progress bar shows current amount toward the target with a percentage
 *
 * GIVEN: A user adds a contribution to a goal
 * WHEN: They enter a contribution amount and save
 * THEN: The goal's current amount increases and progress percentage updates
 *
 * GIVEN: A user wants to edit a goal
 * WHEN: They click the edit button on a goal
 * THEN: The goal details populate the edit form with existing values
 *
 * GIVEN: A user wants to delete a goal
 * WHEN: They select a goal and confirm deletion
 * THEN: The goal is removed from the list
 */

/**
 * Goals Component
 * Handles savings goals with progress tracking
 */
import { createEffect, createMemo, createSignal, For, onMount } from 'solid-js'
import Chart from '../components/Chart'
import ConfirmButton from '../components/ConfirmButton'
import { formatCurrency } from '../core/api'
import { apiDelete, apiGet, apiPost, apiPut, showToast } from '../core/api'
import { useAppState } from '../core/appStore'
import { theme } from '../core/theme'
import styles from './GoalsPage.module.css'

interface Goal {
  id: number
  name: string
  target_amount: number
  current_amount: number
  monthly_contribution: number
  target_date: string
  profile_id: number
  created_at: string
  category_id?: number | null
  category_name?: string
}

interface CategoryOption {
  id: number
  name: string
  color: string
  type: string
}

export default function Goals() {
  const state = useAppState()
  const [goals, setGoals] = createSignal<Goal[]>([])
  const [categories, setCategories] = createSignal<CategoryOption[]>([])
  const [loading, setLoading] = createSignal(true)
  const chartColors = () => theme.getChartColors()
  const [showAddModal, setShowAddModal] = createSignal(false)
  const [showCategoryModal, setShowCategoryModal] = createSignal(false)
  const [categoryForm, setCategoryForm] = createSignal({
    name: '',
    type: 'expense',
    color: '#6366f1',
  })
  const [editingGoal, setEditingGoal] = createSignal<Goal | null>(null)
  const [formData, setFormData] = createSignal({
    name: '',
    target_amount: '',
    target_date: '',
    monthly_contribution: '',
    category_id: '',
  })

  // Load goals
  const loadGoals = async () => {
    setLoading(true)
    try {
      const data = await apiGet<any[]>('/api/savings-goals')
      // Also get category names for each goal
      const cats = await apiGet<any[]>('/api/categories')
      const catMap = new Map<number, string>(cats.map((c: any) => [c.id, c.name]))
      setGoals(
        data.map((s) => ({
          id: s.id,
          name: s.name,
          target_amount: s.target_amount || 0,
          current_amount: s.current_amount || 0,
          monthly_contribution: s.monthly_contribution || 0,
          target_date: s.deadline || s.target_date || new Date().toISOString().split('T')[0],
          profile_id: s.profile_id,
          created_at: s.created_at,
          category_id: s.category_id || null,
          category_name: s.category_id ? catMap.get(s.category_id) : undefined,
        }))
      )
    } catch (err) {
      console.error('Failed to load goals:', err)
      showToast('Failed to load goals', 'error')
    } finally {
      setLoading(false)
    }
  }

  // Load categories for selector
  const loadCategories = async () => {
    try {
      const cats = await apiGet<any[]>('/api/categories')
      setCategories(cats)
    } catch {
      // categories remain empty
    }
  }

  // Handle form submit (create or update)
  const handleSubmit = async (e: Event) => {
    e.preventDefault()
    const data: Record<string, unknown> = {
      name: formData().name,
      target_amount: parseFloat(formData().target_amount),
      target_date: formData().target_date,
      monthly_contribution: formData().monthly_contribution
        ? parseFloat(formData().monthly_contribution)
        : null,
    }
    const catId = formData().category_id ? parseInt(formData().category_id) : null
    if (catId) data.category_id = catId

    try {
      if (editingGoal()) {
        await apiPut(`/api/savings-goals/${editingGoal()!.id}`, data)
        showToast('Goal updated successfully', 'success')
      } else {
        await apiPost('/api/savings-goals', data)
        showToast('Goal created successfully', 'success')
      }
      setShowAddModal(false)
      setEditingGoal(null)
      setFormData({
        name: '',
        target_amount: '',
        target_date: '',
        monthly_contribution: '',
        category_id: '',
      })
      loadGoals()
    } catch (err) {
      console.error('Failed to save goal:', err)
      showToast('Failed to save goal', 'error')
    }
  }

  // Delete goal
  const deleteGoal = async (id: number) => {
    try {
      await apiDelete(`/api/savings-goals/${id}`)
      showToast('Goal deleted successfully', 'success')
      loadGoals()
    } catch (err) {
      console.error('Failed to delete goal:', err)
      showToast('Failed to delete goal', 'error')
    }
  }

  // Add category from within goal modal
  const addCategory = async (e: Event) => {
    e.preventDefault()
    try {
      await apiPost('/api/categories', {
        name: categoryForm().name,
        type: categoryForm().type,
        color: categoryForm().color,
      })
      setShowCategoryModal(false)
      setCategoryForm({ name: '', type: 'expense', color: '#6366f1' })
      loadCategories()
    } catch (err) {
      console.error('Failed to create category:', err)
      showToast('Failed to create category', 'error')
    }
  }

  // Contribute to manually tracked goal
  const [contributingGoalId, setContributingGoalId] = createSignal<number | null>(null)
  const [contributeAmount, setContributeAmount] = createSignal('')

  const startContribute = (goalId: number) => {
    setContributingGoalId(goalId)
    setContributeAmount('')
  }

  const cancelContribute = () => {
    setContributingGoalId(null)
    setContributeAmount('')
  }

  const submitContribute = async (goalId: number) => {
    const parsed = parseFloat(contributeAmount())
    if (isNaN(parsed) || parsed <= 0) {
      showToast('Please enter a valid positive amount', 'error')
      return
    }
    try {
      await apiPost(`/api/savings-goals/${goalId}/contribute`, { amount: parsed })
      showToast('Contribution added', 'success')
      setContributingGoalId(null)
      setContributeAmount('')
      loadGoals()
    } catch (err) {
      console.error('Failed to contribute:', err)
      showToast('Failed to add contribution', 'error')
    }
  }

  // Open edit modal
  const editGoal = (goal: Goal) => {
    setEditingGoal(goal)
    setFormData({
      name: goal.name,
      target_amount: goal.target_amount.toString(),
      target_date: goal.target_date,
      monthly_contribution: goal.monthly_contribution ? goal.monthly_contribution.toString() : '',
      category_id: goal.category_id ? goal.category_id.toString() : '',
    })
    setShowAddModal(true)
  }

  // Progress percentage
  const getProgress = (goal: Goal): number => {
    if (!goal.target_amount || goal.target_amount <= 0) return 0
    return Math.min(100, Math.round((goal.current_amount / goal.target_amount) * 100))
  }

  // Days until target date
  const daysUntil = (dateStr: string): string => {
    const target = new Date(dateStr)
    const today = new Date()
    const diff = Math.ceil((target.getTime() - today.getTime()) / (1000 * 60 * 60 * 24))
    if (diff < 0) return `${Math.abs(diff)} days overdue`
    if (diff === 0) return 'Due today'
    if (diff === 1) return 'Due tomorrow'
    return `Due in ${diff} days`
  }

  // Format date
  const formatDate = (dateStr: string): string => {
    return new Date(dateStr).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    })
  }

  onMount(() => {
    loadGoals()
    loadCategories()
  })

  createEffect(() => {
    void state.profileVersion
    loadGoals()
    loadCategories()
  })

  // Memoized chart data
  const projectionGoals = createMemo(() => goals().filter((g) => g.monthly_contribution > 0))
  const projectionMaxMonths = createMemo(() =>
    Math.max(
      ...projectionGoals().map((g) =>
        Math.ceil((g.target_amount - g.current_amount) / (g.monthly_contribution || 1))
      ),
      1
    )
  )
  const projectionLabels = createMemo(() => {
    const now = new Date()
    return Array.from({ length: projectionMaxMonths() + 1 }, (_, i) => {
      const d = new Date(now.getFullYear(), now.getMonth() + i, 1)
      return d.toLocaleDateString('en-US', { month: 'short', year: 'numeric' })
    })
  })

  return (
    <div class={`page page-goals page-enter ${styles.goalsPage}`}>
      <div class={styles.pageHeader}>
        <div class={styles.headerTop}>
          <h1 data-test-id="goals-header">Savings Goals</h1>
          <button
            data-test-id="add-goal-btn"
            class={styles.btnPrimary}
            onclick={() => setShowAddModal(true)}
          >
            <svg width="16" height="16" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
            </svg>
            New Goal
          </button>
        </div>
        <p data-test-id="goals-subtitle" class={styles.pageSubtitle}>
          Track your savings progress towards financial goals
        </p>
      </div>

      {loading() ? (
        <div class={styles.emptyState}>Loading goals...</div>
      ) : goals().length === 0 ? (
        <div class={styles.emptyState}>
          <p>No goals yet</p>
          <p>Create your first savings goal to start tracking.</p>
          <button class={styles.btnPrimary} onclick={() => setShowAddModal(true)}>
            Create Goal
          </button>
        </div>
      ) : (
        <div data-test-id="goals-grid" class={styles.goalsGrid}>
          <For each={goals()}>
            {(goal) => {
              const progress = getProgress(goal)
              return (
                <div data-test-id="goal-card" class={styles.goalCard}>
                  <div class={styles.goalHeader}>
                    <div data-test-id="goal-icon" class={styles.goalIcon}>
                      <svg
                        width="18"
                        height="18"
                        fill="none"
                        stroke="currentColor"
                        stroke-width="2"
                        viewBox="0 0 24 24"
                      >
                        <path d="M12 2C6.477 2 2 6.477 2 12s4.477 10 10 10 10-4.477 10-10S17.523 2 12 2zm0 4a6 6 0 100 12 6 6 0 000-12zm0 3a3 3 0 100 6 3 3 0 000-6z" />
                      </svg>
                    </div>
                    <div class={styles.goalInfo}>
                      <h3 data-test-id="goal-name" class={styles.goalName}>
                        {goal.name}
                      </h3>
                      <p data-test-id="goal-date" class={styles.goalDate}>
                        {formatDate(goal.target_date)} • {daysUntil(goal.target_date)}
                        {goal.category_name && (
                          <span class={styles.goalCategory}> • {goal.category_name}</span>
                        )}
                      </p>
                    </div>
                    <div data-test-id="goal-actions" class={styles.goalActions}>
                      <button
                        data-test-id="goal-edit-btn"
                        class={styles.btnSm}
                        onclick={() => {
                          editGoal(goal)
                        }}
                      >
                        <svg
                          width="16"
                          height="16"
                          fill="none"
                          stroke="currentColor"
                          viewBox="0 0 24 24"
                        >
                          <path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                        </svg>
                      </button>
                      {!goal.category_id && contributingGoalId() !== goal.id && (
                        <button
                          data-test-id="goal-contribute-btn"
                          class={styles.btnSm}
                          title="Add contribution"
                          onclick={() => {
                            startContribute(goal.id)
                          }}
                        >
                          <svg
                            width="16"
                            height="16"
                            fill="none"
                            stroke="currentColor"
                            stroke-width="2"
                            viewBox="0 0 24 24"
                          >
                            <path d="M12 5v14M5 12h14" />
                          </svg>
                        </button>
                      )}
                      <ConfirmButton
                        class={styles.btnSm}
                        onConfirm={() => deleteGoal(goal.id)}
                        label={
                          <svg
                            width="16"
                            height="16"
                            fill="none"
                            stroke="currentColor"
                            viewBox="0 0 24 24"
                          >
                            <path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                          </svg>
                        }
                      />
                    </div>
                  </div>
                  {contributingGoalId() === goal.id && (
                    <div class={styles.contributeForm}>
                      <input
                        type="number"
                        step="0.01"
                        min="0.01"
                        class={styles.formControl}
                        placeholder="Amount..."
                        value={contributeAmount()}
                        oninput={(e) => setContributeAmount(e.target.value)}
                        onkeydown={(e) => {
                          if (e.key === 'Enter') submitContribute(goal.id)
                          if (e.key === 'Escape') cancelContribute()
                        }}
                        autofocus
                      />
                      <button
                        class={`${styles.btnPrimary} ${styles.btnSm}`}
                        onclick={() => submitContribute(goal.id)}
                      >
                        Add
                      </button>
                      <button
                        class={`${styles.btnSecondary} ${styles.btnSm}`}
                        onclick={cancelContribute}
                      >
                        Cancel
                      </button>
                    </div>
                  )}
                  <div class={styles.goalProgress}>
                    <div data-test-id="goal-progress-bar" class={styles.progressBar}>
                      <div class={styles.progressFill} style={{ width: `${progress}%` }} />
                    </div>
                    <div class={styles.progressStats}>
                      <span data-test-id="goal-progress-percent" class={styles.progressPercent}>
                        {progress}%
                      </span>
                      <span data-test-id="goal-progress-current" class={styles.progressCurrent}>
                        {formatCurrency(goal.current_amount)} of{' '}
                        {formatCurrency(goal.target_amount)}
                      </span>
                    </div>
                  </div>
                </div>
              )
            }}
          </For>
        </div>
      )}

      {/* Goals Progress Chart */}
      {goals().length > 0 && (
        <div class={styles.goalsChartSection}>
          <h3>Goals Progress</h3>
          <div class={styles.chartWrapper}>
            <Chart
              id="goals-progress-chart"
              type="doughnut"
              data={{
                labels: goals().map((g) => g.name),
                datasets: [
                  {
                    data: goals().map((g) => g.current_amount),
                    backgroundColor: goals().map((g) => {
                      const progress = g.target_amount > 0 ? g.current_amount / g.target_amount : 0
                      if (progress < 0.3) return '#dc2626'
                      if (progress < 0.6) return '#eab308'
                      if (progress < 0.9) return '#22c55e'
                      return '#8b5cf6'
                    }),
                    borderWidth: 0,
                  },
                ],
              }}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                  legend: {
                    position: 'right',
                    labels: {
                      usePointStyle: true,
                      padding: 15,
                      font: { size: 12 },
                      color: chartColors().text,
                    },
                  },
                  tooltip: {
                    callbacks: {
                      label: (context: any) => {
                        const goal = goals()[context.dataIndex]
                        const progress =
                          goal.target_amount > 0
                            ? Math.round((goal.current_amount / goal.target_amount) * 100)
                            : 0
                        return `${goal.name}: ${formatCurrency(goal.current_amount)} of ${formatCurrency(goal.target_amount)} (${progress}%)`
                      },
                    },
                  },
                },
              }}
              height={250}
              width="100%"
            />
          </div>
        </div>
      )}

      {/* Goal Projection Timeline */}
      {projectionGoals().length > 0 && (
        <div class={styles.goalsChartSection}>
          <h3>Goal Projections</h3>
          <div class={styles.chartWrapper}>
            <Chart
              id="goals-projection-chart"
              type="line"
              data={{
                labels: projectionLabels(),
                datasets: projectionGoals().map((g, idx) => {
                  const colors = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4']
                  const color = colors[idx % colors.length]
                  const monthly = g.monthly_contribution || 0
                  const remaining = g.target_amount - g.current_amount
                  const monthsNeeded = Math.ceil(remaining / monthly)
                  const data: (number | null)[] = [g.current_amount]
                  for (let m = 1; m <= monthsNeeded; m++) {
                    data.push(Math.min(g.current_amount + monthly * m, g.target_amount))
                  }
                  // Compute achievement date label
                  const now = new Date()
                  const achieveDate = new Date(now.getFullYear(), now.getMonth() + monthsNeeded, 1)
                  const achieveLabel = achieveDate.toLocaleDateString('en-US', {
                    month: 'short',
                    year: 'numeric',
                  })
                  return {
                    label: `${g.name} — target ${achieveLabel}`,
                    data,
                    borderColor: color,
                    backgroundColor: `${color}20`,
                    fill: true,
                    tension: 0.3,
                    borderWidth: 2,
                    pointRadius: data.map((_, i) => (i === monthsNeeded ? 4 : 0)),
                    pointBackgroundColor: data.map((_, i) =>
                      i === monthsNeeded ? color : 'transparent'
                    ),
                    pointBorderColor: data.map((_, i) =>
                      i === monthsNeeded ? '#fff' : 'transparent'
                    ),
                    pointBorderWidth: 2,
                  }
                }),
              }}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                interaction: {
                  intersect: false,
                  mode: 'index',
                },
                scales: {
                  y: {
                    ticks: {
                      callback: (v: number | string) =>
                        formatCurrency(typeof v === 'number' ? v : Number(v), 'EUR'),
                      color: chartColors().text,
                    },
                    grid: { color: chartColors().border },
                    title: {
                      display: true,
                      text: 'Balance',
                      color: chartColors().text,
                    },
                  },
                  x: {
                    ticks: { color: chartColors().text, maxTicksLimit: 12 },
                    grid: { color: chartColors().border },
                    title: {
                      display: true,
                      text: 'Projected timeline',
                      color: chartColors().text,
                    },
                  },
                },
                plugins: {
                  legend: {
                    position: 'top',
                    labels: { color: chartColors().text, usePointStyle: true },
                  },
                  tooltip: {
                    callbacks: {
                      label: (ctx: any) => {
                        const dataset = ctx.dataset
                        const val = dataset.data[ctx.dataIndex]
                        const isLast = ctx.dataIndex === dataset.data.length - 1
                        const isPlateau =
                          !isLast &&
                          val === dataset.data[ctx.dataIndex + 1] &&
                          val === dataset.data[Math.min(ctx.dataIndex + 2, dataset.data.length - 1)]
                        let label = `${dataset.label?.split(' — ')[0] || dataset.label}: ${formatCurrency(val)}`
                        if (isLast) label += ' (goal reached)'
                        else if (isPlateau) label += ' (goal reached)'
                        return label
                      },
                    },
                  },
                },
              }}
              height={300}
              width="100%"
            />
          </div>
        </div>
      )}

      {/* Add/Edit Modal */}
      {showAddModal() && (
        <div
          class={styles.modalOverlay}
          role="dialog"
          aria-modal="true"
          onclick={(e) => {
            if (e.target === e.currentTarget) setShowAddModal(false)
          }}
        >
          <div
            class={styles.modal}
            onclick={(e) => {
              e.stopPropagation()
            }}
          >
            <div class={styles.modalHeader}>
              <h3 class={styles.modalTitle}>{editingGoal() ? 'Edit Goal' : 'New Goal'}</h3>
              <button
                class={styles.modalClose}
                onclick={() => {
                  setShowAddModal(false)
                  setEditingGoal(null)
                  setFormData({
                    name: '',
                    target_amount: '',
                    target_date: '',
                    monthly_contribution: '',
                    category_id: '',
                  })
                }}
              >
                <svg width="24" height="24" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
            <form class={styles.modalBody} onsubmit={handleSubmit}>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Goal Name</label>
                <input
                  type="text"
                  class={styles.formControl}
                  placeholder="e.g., Emergency Fund, Vacation"
                  value={formData().name}
                  oninput={(e) => setFormData({ ...formData(), name: e.target.value })}
                  autofocus
                  required
                />
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Target Amount</label>
                <input
                  type="number"
                  step="0.01"
                  class={styles.formControl}
                  placeholder="5000.00"
                  value={formData().target_amount}
                  oninput={(e) => setFormData({ ...formData(), target_amount: e.target.value })}
                  required
                />
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Target Date</label>
                <input
                  type="date"
                  class={styles.formControl}
                  value={formData().target_date}
                  oninput={(e) => setFormData({ ...formData(), target_date: e.target.value })}
                  required
                />
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Monthly Contribution</label>
                <input
                  type="number"
                  step="0.01"
                  class={styles.formControl}
                  placeholder="e.g., 500.00"
                  value={formData().monthly_contribution}
                  oninput={(e) =>
                    setFormData({ ...formData(), monthly_contribution: e.target.value })
                  }
                />
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Linked Category (optional)</label>
                <select
                  class={styles.formControl}
                  value={formData().category_id}
                  onchange={(e) => setFormData({ ...formData(), category_id: e.target.value })}
                >
                  <option value="">None — manual tracking</option>
                  <For each={categories()}>
                    {(cat) => (
                      <option value={cat.id}>
                        {cat.name} ({cat.type})
                      </option>
                    )}
                  </For>
                </select>
                <button
                  type="button"
                  class={styles.btnLink}
                  style={{ 'margin-top': '8px' }}
                  onClick={() => setShowCategoryModal(true)}
                >
                  + Add Category
                </button>
                <p
                  style={{
                    'font-size': '11px',
                    color: 'var(--text-secondary)',
                    'margin-top': '4px',
                  }}
                >
                  Transactions to this category will count toward goal progress
                </p>
              </div>
              <div class={styles.modalFooter}>
                <button
                  type="button"
                  class={styles.btnSecondary}
                  onclick={() => {
                    setShowAddModal(false)
                    setEditingGoal(null)
                    setFormData({
                      name: '',
                      target_amount: '',
                      target_date: '',
                      monthly_contribution: '',
                      category_id: '',
                    })
                  }}
                >
                  Cancel
                </button>
                <button type="submit" class={styles.btnPrimary}>
                  {editingGoal() ? 'Update' : 'Create'} Goal
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Add Category Modal (from goal creation) */}
      {showCategoryModal() && (
        <div
          class={styles.modalOverlay}
          role="dialog"
          aria-modal="true"
          onclick={(e) => {
            if (e.target === e.currentTarget) setShowCategoryModal(false)
          }}
        >
          <div
            class={styles.modal}
            onclick={(e) => {
              e.stopPropagation()
            }}
          >
            <div class={styles.modalHeader}>
              <h3 class={styles.modalTitle}>Add Category</h3>
              <button class={styles.modalClose} onclick={() => setShowCategoryModal(false)}>
                <svg width="24" height="24" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
            <form class={styles.modalBody} onsubmit={addCategory}>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Category Name</label>
                <input
                  type="text"
                  class={styles.formControl}
                  placeholder="e.g., Vacation Fund"
                  value={categoryForm().name}
                  oninput={(e) => setCategoryForm({ ...categoryForm(), name: e.target.value })}
                  autofocus
                  required
                />
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Type</label>
                <select
                  class={styles.formControl}
                  value={categoryForm().type}
                  oninput={(e) =>
                    setCategoryForm({
                      ...categoryForm(),
                      type: e.target.value as 'expense' | 'income',
                    })
                  }
                >
                  <option value="expense">Expense</option>
                  <option value="income">Income</option>
                </select>
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Color</label>
                <input
                  type="color"
                  class={styles.colorInput}
                  value={categoryForm().color}
                  oninput={(e) => setCategoryForm({ ...categoryForm(), color: e.target.value })}
                />
              </div>
              <div class={styles.modalFooter}>
                <button
                  type="button"
                  class={styles.btnSecondary}
                  onclick={() => setShowCategoryModal(false)}
                >
                  Cancel
                </button>
                <button type="submit" class={styles.btnPrimary}>
                  Add Category
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

/**
 * Housing Component - EARS Specification
 *
 * GIVEN: A user is viewing the Housing page
 * WHEN: The page loads
 * THEN: The header displays "Housing" and shows monthly housing costs with icons
 *
 * GIVEN: A user wants to add a housing expense
 * WHEN: They click the "Add Expense" button
 * THEN: An "Add Expense" modal opens with fields for expense type, amount, and due date
 *
 * GIVEN: A user has set up autopay
 * WHEN: They toggle the autopay switch
 * THEN: The expense is marked with an autopay badge
 *
 * GIVEN: A user has multiple housing expenses
 * WHEN: The page displays the expenses list
 * THEN: It shows total monthly cost, number of active expenses, and autopay count
 *
 * GIVEN: A user wants to delete a housing expense
 * WHEN: They select an expense and confirm deletion
 * THEN: The expense is removed from the list
 */

/**
 * Housing Component
 * Manages housing-related expenses and property information
 */
import { createEffect, createMemo, createSignal, For, onMount } from 'solid-js'
import Badge from '../components/Badge'
import ConfirmButton from '../components/ConfirmButton'
import { formatCurrency } from '../core/api'
import { apiDelete, apiGet, apiPost, showToast } from '../core/api'
import { useAppState } from '../core/appStore'
import styles from './HousingPage.module.css'

interface Housing {
  id: number
  type: 'rent' | 'mortgage' | 'hoa' | 'property_tax' | 'insurance' | 'other'
  property_name?: string
  name?: string
  monthly_amount: number | string
  due_day: number
  due_month: number
  due_date?: string
  start_date?: string
  autopay: boolean | number
  notes?: string
  profile_id: number
}

function getPropertyName(h: Housing): string {
  return h.property_name || h.name || 'Unknown'
}

function getMonthlyAmount(h: Housing): number {
  return Math.abs(parseFloat(String(h.monthly_amount || 0)))
}

export default function HousingForm() {
  const state = useAppState()
  const [housings, setHousings] = createSignal<Housing[]>([])
  const [loading, setLoading] = createSignal(true)
  const [showAddModal, setShowAddModal] = createSignal(false)
  const [formData, setFormData] = createSignal({
    type: 'rent',
    property_name: '',
    monthly_amount: '',
    due_day: 1,
    due_month: new Date().getMonth() + 1,
    autopay: false,
    notes: '',
  })

  // Subscriptions tracker
  interface SubBill {
    id: number
    name: string
    amount: number
    due_date: string
    frequency: string
    is_active: number
    category_name?: string
    category_color?: string
    notes?: string
  }
  const [subscriptions, setSubscriptions] = createSignal<SubBill[]>([])
  const activeSubs = createMemo(() => subscriptions().filter((s) => s.is_active !== 0))
  const totalSubsCost = createMemo(() => activeSubs().reduce((sum, s) => sum + s.amount, 0))

  const loadSubscriptions = async () => {
    try {
      const data = await apiGet<SubBill[]>('/api/bills?type=subscription')
      setSubscriptions(Array.isArray(data) ? data : [])
    } catch {
      // subscriptions remain as-is
    }
  }

  // Load housing expenses
  const loadHousings = async () => {
    setLoading(true)
    try {
      const result = await apiGet<{ housings: Housing[] }>('/api/housing')
      setHousings(result.housings || [])
    } catch (err) {
      console.error('Failed to load housing expenses:', err)
      showToast('Failed to load housing expenses', 'error')
    } finally {
      setLoading(false)
    }
  }

  // Handle form submit
  const handleSubmit = async (e: Event) => {
    e.preventDefault()
    const data = {
      type: formData().type,
      property_name: formData().property_name,
      monthly_amount: parseFloat(formData().monthly_amount),
      due_day: formData().due_day,
      due_month: formData().due_month,
      autopay: formData().autopay,
      notes: formData().notes,
    }

    try {
      await apiPost('/api/housing', data)
      showToast('Housing expense saved', 'success')
      setShowAddModal(false)
      setFormData({
        type: 'rent',
        property_name: '',
        monthly_amount: '',
        due_day: 1,
        due_month: new Date().getMonth() + 1,
        autopay: false,
        notes: '',
      })
      loadHousings()
    } catch (err) {
      console.error('Failed to save housing expense:', err)
      showToast('Failed to save housing expense', 'error')
    }
  }

  // Delete housing expense
  const deleteHousing = async (id: number) => {
    try {
      await apiDelete(`/api/housing/${id}`)
      showToast('Housing expense deleted', 'success')
      loadHousings()
    } catch (err) {
      console.error('Failed to delete housing expense:', err)
      showToast('Failed to delete housing expense', 'error')
    }
  }

  // Calculate total monthly housing cost
  const totalMonthlyCost = createMemo(() => {
    return housings().reduce((sum, h) => sum + getMonthlyAmount(h), 0)
  })

  // Get type icon SVG
  const getTypeIcon = (type: string) => {
    const paths: Record<string, string> = {
      rent: 'M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6',
      mortgage:
        'M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z',
      hoa: 'M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4',
      property_tax:
        'M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z',
      insurance: 'M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z',
      other:
        'M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2',
    }
    const d = paths[type] || paths.other
    return (
      <svg
        width="18"
        height="18"
        fill="none"
        stroke="currentColor"
        stroke-width="2"
        viewBox="0 0 24 24"
      >
        <path d={d} />
      </svg>
    )
  }

  // Get type label
  const getTypeLabel = (type: string): string => {
    const labels: Record<string, string> = {
      rent: 'Rent',
      mortgage: 'Mortgage',
      hoa: 'HOA Fees',
      property_tax: 'Property Tax',
      insurance: 'Insurance',
      other: 'Other',
    }
    return labels[type] || 'Other'
  }

  // Format currency
  const formatAmount = (amount: number): string => {
    return formatCurrency(amount)
  }

  onMount(() => {
    loadHousings()
    loadSubscriptions()
  })
  createEffect(() => {
    void state.profileVersion
    void loadHousings()
    void loadSubscriptions()
  })

  return (
    <div class={`page page-housing page-enter ${styles.housingPage}`}>
      <div class={styles.pageHeader}>
        <div class={styles.headerTop}>
          <h1 data-test-id="housing-header">Housing</h1>
          <button
            data-test-id="add-housing-btn"
            class={styles.btnPrimary}
            onClick={() => setShowAddModal(true)}
          >
            <svg width="16" height="16" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
            </svg>
            Add Expense
          </button>
        </div>
        <p data-test-id="housing-subtitle" class={styles.pageSubtitle}>
          Track all your housing-related expenses
        </p>
      </div>

      {/* Summary Cards */}
      <div class={styles.housingSummary}>
        <div class={`${styles.summaryCard} ${styles.highlighted}`}>
          <div class={styles.summaryLabel}>Monthly Total</div>
          <div class={styles.summaryValue}>{formatAmount(totalMonthlyCost())}</div>
        </div>
        <div class={styles.summaryCard}>
          <div class={styles.summaryLabel}>Active Expenses</div>
          <div class={styles.summaryValue}>{housings().length}</div>
        </div>
        <div class={styles.summaryCard}>
          <div class={styles.summaryLabel}>Autopay Enabled</div>
          <div class={styles.summaryValue}>
            {housings().filter((h) => h.autopay === true || h.autopay === 1).length}
          </div>
        </div>
      </div>

      {/* Subscription Tracker */}
      {activeSubs().length > 0 && (
        <div class={styles.subscriptionSection}>
          <div class={styles.sectionHeader}>
            <h3 class={styles.sectionTitle}>
              <svg
                width="18"
                height="18"
                fill="none"
                stroke="currentColor"
                stroke-width="2"
                viewBox="0 0 24 24"
              >
                <path d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
              </svg>
              Subscription Tracker
            </h3>
            <span class={styles.subTotal}>{formatCurrency(totalSubsCost())}/mo</span>
          </div>
          <div class={styles.subscriptionList}>
            <For each={activeSubs()}>
              {(sub) => (
                <div class={styles.subItem}>
                  <div class={styles.subItemInfo}>
                    <span
                      class={styles.subDot}
                      style={{ background: sub.category_color || 'var(--primary)' }}
                    />
                    <div>
                      <div class={styles.subItemName}>{sub.name}</div>
                      <div class={styles.subItemMeta}>
                        {sub.frequency === 'monthly'
                          ? 'Monthly'
                          : sub.frequency === 'weekly'
                            ? 'Weekly'
                            : 'Biweekly'}
                        {sub.due_date &&
                          ` · Due ${new Date(sub.due_date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`}
                      </div>
                    </div>
                  </div>
                  <div class={styles.subItemAmount}>{formatCurrency(sub.amount)}</div>
                </div>
              )}
            </For>
          </div>
        </div>
      )}

      {loading() ? (
        <div class={styles.emptyState}>Loading housing expenses...</div>
      ) : housings().length === 0 ? (
        <div class={styles.emptyState}>
          <p>No housing expenses yet</p>
          <p>Add your first housing expense to start tracking your housing costs.</p>
          <button class={styles.btnPrimary} onClick={() => setShowAddModal(true)}>
            Add Expense
          </button>
        </div>
      ) : (
        <div class={styles.housingList}>
          <For each={housings()}>
            {(housing) => (
              <div class={styles.housingCard}>
                <div class={styles.housingHeader}>
                  <div class={styles.housingIcon}>{getTypeIcon(housing.type)}</div>
                  <div class={styles.housingInfo}>
                    <h3 class={styles.housingName}>{getPropertyName(housing)}</h3>
                    <p class={styles.housingType}>{getTypeLabel(housing.type)}</p>
                  </div>
                  <div class={styles.housingActions}>
                    {housing.autopay === true || housing.autopay === 1 ? (
                      <Badge status="success">Autopay</Badge>
                    ) : (
                      <Badge status="default">Manual</Badge>
                    )}
                    <ConfirmButton
                      class={`${styles.btnSm} ${styles.btnGhost}`}
                      onConfirm={() => deleteHousing(housing.id)}
                      label={
                        <svg
                          width="16"
                          height="16"
                          fill="none"
                          stroke="currentColor"
                          viewBox="0 0 24 24"
                        >
                          <path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                        </svg>
                      }
                    />
                  </div>
                </div>
                <div class={styles.housingAmount}>
                  <div class={styles.amountLabel}>Monthly Cost</div>
                  <div class={styles.amountValue}>{formatAmount(getMonthlyAmount(housing))}</div>
                </div>
                <div class={styles.housingDetails}>
                  <div class={styles.detailItem}>
                    <span class={styles.detailLabel}>Due</span>
                    <span class={styles.detailValue}>
                      {housing.due_date
                        ? housing.due_date
                        : `${housing.due_month} / ${housing.due_day}`}
                    </span>
                  </div>
                  {housing.notes && (
                    <div class={styles.detailItem}>
                      <span class={styles.detailLabel}>Notes</span>
                      <span class={styles.detailValue}>{housing.notes}</span>
                    </div>
                  )}
                </div>
              </div>
            )}
          </For>
        </div>
      )}

      {/* Add Housing Modal */}
      {showAddModal() && (
        <div
          class={styles.modalOverlay}
          role="dialog"
          aria-modal="true"
          onclick={(e) => {
            if (e.target === e.currentTarget) setShowAddModal(false)
          }}
        >
          <div
            class={styles.modal}
            onclick={(e) => {
              e.stopPropagation()
            }}
          >
            <div class={styles.modalHeader}>
              <h3 class={styles.modalTitle}>Add Housing Expense</h3>
              <button class={styles.modalClose} onClick={() => setShowAddModal(false)}>
                <svg width="24" height="24" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
            <form class={styles.modalBody} onSubmit={handleSubmit}>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Expense Type</label>
                <select
                  class={styles.formControl}
                  value={formData().type}
                  oninput={(e) =>
                    setFormData({ ...formData(), type: e.target.value as Housing['type'] })
                  }
                >
                  <option value="rent">Rent</option>
                  <option value="mortgage">Mortgage</option>
                  <option value="hoa">HOA Fees</option>
                  <option value="property_tax">Property Tax</option>
                  <option value="insurance">Insurance</option>
                  <option value="other">Other</option>
                </select>
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Property / Description</label>
                <input
                  type="text"
                  class={styles.formControl}
                  placeholder="e.g., Main Apartment, Monthly Payment"
                  value={formData().property_name}
                  oninput={(e) => setFormData({ ...formData(), property_name: e.target.value })}
                  required
                />
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Monthly Amount</label>
                <input
                  type="number"
                  step="0.01"
                  class={styles.formControl}
                  placeholder="1200.00"
                  value={formData().monthly_amount}
                  oninput={(e) => setFormData({ ...formData(), monthly_amount: e.target.value })}
                  required
                />
              </div>
              <div class={styles.formRow}>
                <div class={styles.formGroup}>
                  <label class={styles.formLabel}>Due Month</label>
                  <select
                    class={styles.formControl}
                    value={formData().due_month}
                    oninput={(e) =>
                      setFormData({ ...formData(), due_month: parseInt(e.target.value) })
                    }
                  >
                    {Array.from({ length: 12 }, (_, i) => (
                      <option value={i + 1}>
                        {new Date(0, i).toLocaleString('default', { month: 'long' })}
                      </option>
                    ))}
                  </select>
                </div>
                <div class={styles.formGroup}>
                  <label class={styles.formLabel}>Due Day</label>
                  <input
                    type="number"
                    min="1"
                    max="31"
                    class={styles.formControl}
                    placeholder="1"
                    value={formData().due_day}
                    oninput={(e) =>
                      setFormData({ ...formData(), due_day: parseInt(e.target.value) || 1 })
                    }
                  />
                </div>
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>
                  <span>
                    <svg
                      width="16"
                      height="16"
                      fill="none"
                      stroke="currentColor"
                      stroke-width="2"
                      viewBox="0 0 24 24"
                    >
                      <path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                    </svg>{' '}
                    Autopay
                  </span>
                  <span style="font-size: 14px; color: var(--text-secondary)">
                    Automatically pay this expense
                  </span>
                </label>
                <label class={styles.toggleSwitch}>
                  <input
                    type="checkbox"
                    checked={formData().autopay}
                    oninput={(e) => setFormData({ ...formData(), autopay: e.target.checked })}
                  />
                  <span class={styles.toggleSlider}></span>
                </label>
              </div>
              <div class={styles.formGroup}>
                <label class={styles.formLabel}>Notes (optional)</label>
                <textarea
                  class={styles.formControl}
                  placeholder="Additional details..."
                  value={formData().notes}
                  oninput={(e) => setFormData({ ...formData(), notes: e.target.value })}
                  rows={2}
                />
              </div>
              <div class={styles.modalFooter}>
                <button
                  type="button"
                  class={styles.btnSecondary}
                  onClick={() => setShowAddModal(false)}
                >
                  Cancel
                </button>
                <button type="submit" class={styles.btnPrimary}>
                  Add Expense
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

/**
 * Import Component - EARS Specification
 *
 * GIVEN: A user is on the Import page
 * WHEN: The page loads
 * THEN: File Upload and Google Sheets sections are displayed stacked vertically
 *
 * GIVEN: A user wants to import from a CSV/Excel file
 * WHEN: They drag-and-drop or browse for a file
 * THEN: The file content is processed and column mapping UI appears
 *
 * GIVEN: A user uploads a file with headers matching expected fields
 * WHEN: They proceed to mapping
 * THEN: Column select dropdowns auto-populate based on header matches
 *
 * GIVEN: A user maps columns
 * WHEN: They select which columns represent date, description, and amount
 * THEN: The preview table displays rows with mapped data
 *
 * GIVEN: A user uploads a file with duplicate rows
 * WHEN: They preview the data
 * THEN: Duplicate rows are flagged with a visual indicator
 *
 * GIVEN: A user maps category columns
 * WHEN: They select categories and select expense/income
 * THEN: Category type labels (expense/income) are shown next to each category
 *
 * GIVEN: A user wants to import data
 * WHEN: They click "Import all", "Import only new", or "Import selected"
 * THEN: Data is submitted to the backend and success message displays
 */

/**
 * Import Component
 * Handles CSV/Excel file and Google Sheets import with full 12-field column mapping, duplicate detection, and category type review
 */

import { createSignal, For, onMount, Show } from 'solid-js'
import { apiFetch } from '../core/apiFetch'
import { classifyCategory } from '../core/categoryClassifier'
import styles from './Import.module.css'

// Column field names for mapping
const FIELD_NAMES = [
  { key: 'date', label: 'Date', required: true },
  { key: 'description', label: 'Description', required: true },
  { key: 'amount', label: 'Amount', required: true },
  { key: 'category', label: 'Category', required: false },
  { key: 'currency', label: 'Currency', required: false },
  { key: 'beneficiary', label: 'Beneficiary', required: false },
  { key: 'payor', label: 'Payor', required: false },
  { key: 'means_of_payment', label: 'Means of Payment', required: false },
  { key: 'exchange_rate', label: 'Exchange Rate', required: false },
  { key: 'notes', label: 'Notes', required: false },
  { key: 'type', label: 'Type', required: false },
  { key: 'amount_local', label: 'Amount Local', required: false },
] as const

// Header name variants for auto-detection
const HEADER_VARIANTS: Record<string, string[]> = {
  date: ['date', 'datum', 'trans date', 'transaction date'],
  description: ['description', 'desc', 'memo', 'note', 'narration', 'details'],
  amount: ['amount', 'sum', 'total', 'value', 'suma'],
  category: ['category', 'cat', 'kategoria'],
  currency: ['currency', 'waluta', 'curr'],
  beneficiary: ['beneficiary', 'beneficjent', 'recipient', 'payee'],
  payor: ['payor', 'payer', 'płatnik', 'from'],
  means_of_payment: ['payment', 'method', 'means', 'payment method'],
  exchange_rate: ['rate', 'exchange rate', 'kurs'],
  notes: ['notes', 'note', 'remark', 'comments'],
  type: ['type', 'typ', 'tx type', 'transaction type'],
  amount_local: [
    'amount local',
    'local amount',
    'amount pln',
    'amount in local currency',
    'local currency',
    'local curr',
    'amount (local)',
    'local value',
    'domestic amount',
  ],
} as const

interface UploadResult {
  fileId: string
  filename: string
  sheetName: string
  sheetNames: string[]
  headers: string[]
  rows: string[][]
  totalRows: number
  duplicateCount?: number
  duplicateIndices?: number[]
}

interface SheetResult {
  headers: string[]
  rows: string[][]
  sheetNames: string[]
  selectedSheet: string
  duplicateCount?: number
  duplicateIndices?: number[]
}

type Step = 'upload' | 'mapping' | 'preview' | 'importing' | 'done'

export default function Import() {
  // Import method tab
  type ImportTab = 'google-sheets' | 'file-upload' | 'paste-csv'
  const [activeImportTab, setActiveImportTab] = createSignal<ImportTab>('google-sheets')

  const profileHeaders = () => {
    const pid = localStorage.getItem('currentProfileId') || '1'
    return { 'X-Profile-Id': pid }
  }

  // Step state
  const [activeStep, setActiveStep] = createSignal<Step>('upload')

  // File upload state
  const [uploadResult, setUploadResult] = createSignal<UploadResult | null>(null)
  const [selectedSheet, setSelectedSheet] = createSignal<string>('')
  const [fileId, setFileId] = createSignal<string>('')

  // Google Sheets state
  const [sheetUrl, setSheetUrl] = createSignal<string>('')
  const [sheetResult, setSheetResult] = createSignal<SheetResult | null>(null)
  const [sheetNames, setSheetNames] = createSignal<string[]>([])

  // Paste CSV state
  const [pastedText, setPastedText] = createSignal('')
  const [pasteDelimiter, setPasteDelimiter] = createSignal<'auto' | 'comma' | 'tab'>('auto')

  const parsePastedData = (text: string) => {
    if (!text.trim()) return
    setLoading(true)
    setError(null)
    try {
      const delim = pasteDelimiter() === 'tab' ? '\t' : pasteDelimiter() === 'comma' ? ',' : ''
      const rows: string[][] = []
      const lines = text.trim().split('\n')
      for (const line of lines) {
        const cols: string[] = []
        let cur = ''
        let inQuotes = false
        for (const ch of line) {
          if (ch === '"') {
            inQuotes = !inQuotes
          } else if (
            (delim && ch === delim) ||
            (!delim && (ch === ',' || ch === '\t') && !inQuotes)
          ) {
            cols.push(cur.trim().replace(/^"|"$/g, ''))
            cur = ''
          } else cur += ch
        }
        cols.push(cur.trim().replace(/^"|"$/g, ''))
        rows.push(cols)
      }
      if (rows.length < 2) {
        setError('Need at least a header row and one data row')
        setLoading(false)
        return
      }
      const headers = rows[0]
      const dataRows = rows.slice(1).filter((r) => r.some((c) => c))
      setUploadResult({
        headers,
        rows: dataRows,
        filename: 'pasted-data.csv',
        fileId: `paste-${Date.now()}`,
        sheetName: 'Pasted',
        sheetNames: ['Pasted'],
        totalRows: dataRows.length,
        duplicateCount: 0,
        duplicateIndices: [],
      })
      setActiveStep('upload')
    } catch {
      setError('Failed to parse pasted data')
      setLoading(false)
    }
  }

  // Column mapping
  const [columnMapping, setColumnMapping] = createSignal<Record<string, number>>({})
  const [categoryTypes, setCategoryTypes] = createSignal<
    Record<string, 'income' | 'expense' | 'account'>
  >({})
  const [accountTypes, setAccountTypes] = createSignal<Record<string, string>>({})
  const [accountBalances, setAccountBalances] = createSignal<Record<string, string>>({})
  const [accountBalanceDates, setAccountBalanceDates] = createSignal<Record<string, string>>({})
  const [universalStartDate, setUniversalStartDate] = createSignal('')

  const applyUniversalStartDate = (date: string) => {
    setUniversalStartDate(date)
    if (!date) return
    const types = categoryTypes()
    const dates = { ...accountBalanceDates() }
    for (const cat of detectCategories()) {
      if (types[cat] === 'account') {
        dates[cat] = date
      }
    }
    setAccountBalanceDates(dates)
  }

  // Preview state
  const [_rows, setRows] = createSignal<string[][]>([])
  const [_headers, setHeaders] = createSignal<string[]>([])
  const [selectedRows, setSelectedRows] = createSignal<Set<number>>(new Set())
  const [currentPage, setCurrentPage] = createSignal(1)
  const [rowsPerPage, setRowsPerPage] = createSignal(50)
  const [duplicateIndices, _setDuplicateIndices] = createSignal<number[]>([])

  // Loading/error
  const [loading, setLoading] = createSignal(false)
  const [error, setError] = createSignal<string | null>(null)
  const [resultMessage, setResultMessage] = createSignal<{
    type: 'success' | 'error'
    text: string
  } | null>(null)

  const currentHeaders = () => {
    if (uploadResult()) return uploadResult()!.headers
    if (sheetResult()) return sheetResult()!.headers
    return []
  }

  const currentRows = () => {
    if (uploadResult()) return uploadResult()!.rows
    if (sheetResult()) return sheetResult()!.rows
    return []
  }

  const hasDuplicateCount = () => {
    if (uploadResult()) return uploadResult()!.duplicateCount
    if (sheetResult()) return sheetResult()!.duplicateCount
    return 0
  }

  // Calculate auto-detection mapping
  const autoDetectMapping = (headers: string[]) => {
    const mapping: Record<string, number> = {}
    FIELD_NAMES.forEach((field) => {
      const variants = HEADER_VARIANTS[field.key]
      const lowerHeaders = headers.map((h) => h.toLowerCase())
      const idx = lowerHeaders.findIndex((h) => variants.some((v) => h.includes(v.toLowerCase())))
      if (idx !== -1) {
        mapping[field.key] = idx
      }
    })
    return mapping
  }

  // Detect unique categories
  const detectCategories = () => {
    const categories = new Set<string>()
    currentRows().forEach((row) => {
      const catIdx = columnMapping()['category']
      if (catIdx !== undefined && row[catIdx]) {
        const catName = row[catIdx].trim()
        if (catName) categories.add(catName)
      }
    })
    return Array.from(categories)
  }

  // Step navigation
  const goToMapping = () => {
    const headers = currentHeaders()
    if (headers.length === 0) return
    setActiveStep('mapping')
    const mapping = autoDetectMapping(headers)
    setColumnMapping(mapping)

