    if (mapping['category'] !== undefined) {
      const categories = detectCategories()
      const types: Record<string, 'income' | 'expense' | 'account'> = {}
      categories.forEach((cat) => {
        types[cat] = classifyCategory(cat)
      })
      setCategoryTypes(types)
    }
