                      <span class={styles.legendValue}>{formatAmount(a.value)}</span>
                    </div>
                  )}
                </For>
              </div>
            </Show>
          </div>
        </div>
      )}

      {/* Add/Edit Modal */}
      <Show when={showAddModal()}>
        <div
          class={styles.modalOverlay}
          onclick={(e) => {
            if (e.target === e.currentTarget) setShowAddModal(false)
          }}
