/**
 * Rent vs Buy Calculator Component - EARS Specification
 *
 * GIVEN: A user is on the Rent vs Buy Calculator page
 * WHEN: The page loads
 * THEN: The header displays "Rent vs Buy" and input fields for both scenarios appear
 *
 * GIVEN: A user enters rent and buy costs
 * WHEN: They input rent, home price, loan terms, and maintenance costs
 * THEN: The calculator computes 30-year cumulative costs for both options
 *
 * GIVEN: A user views results
 * WHEN: They click calculate
 * THEN: Charts display cumulative costs and the break-even year is highlighted
 *
 * GIVEN: A user saves calculator settings
 * WHEN: They complete calculations
 * THEN: Settings are saved to localStorage for next visit
 */

/**
 * Rent vs Buy Calculator Component
 * Compares 30-year costs of renting vs buying a home
 */
import { createMemo, createSignal, onCleanup, onMount } from 'solid-js'
import Chart from '../components/Chart'
import ExportChartButton from '../components/ExportChartButton'
import { formatCurrency } from '../core/api'
import { theme } from '../core/theme'
import sharedStyles from './CalculatorShared.module.css'
import styles from './RentBuyCalculator.module.css'
import type * as Models from '../types/models'

interface Result {
  year: number
  rentCumulative: number
  buyCumulative: number
  rentInvestmentValue: number
  buyEquity: number
  rentNetCost: number
  buyNetCost: number
}

interface Props {
  currency?: Models.Currency
}

export default function RentBuyCalculator(props: Props) {
  const currency = props.currency || 'EUR'
  const [loading, setLoading] = createSignal(false)
  const chartColors = () => theme.getChartColors()
  const [results, setResults] = createSignal<Result[]>([])
  const [breakEvenYear, setBreakEvenYear] = createSignal<number | null>(null)

  // Form state
  const [formData, setFormData] = createSignal({
    rentMonthly: '1200',
    rentIncrease: '3',
    investReturn: '7',
    homePrice: '300000',
    downPayment: '60000',
    loanTerm: '30',
    interestRate: '4',
    propertyTax: '3000',
    insurance: '1200',
    maintenance: '1',
    hoa: '200',
    horizon: '30',
  })

  const [showResults, setShowResults] = createSignal(false)
  const [chartRef, setChartRef] = createSignal<any>(undefined)

  // Load saved calculator settings
  onMount(() => {
    const saved = localStorage.getItem('rentBuyCalculatorSettings')
    if (saved) {
      try {
        const parsed = JSON.parse(saved)
        // Convert stored numbers to strings for the string-based form
        const strForm: Record<string, string> = {}
        for (const key of Object.keys(parsed)) {
          strForm[key] = String(parsed[key] ?? formData()[key as keyof typeof formData])
        }
        setFormData({ ...formData(), ...strForm })
      } catch (_e) {
        console.error('Failed to load calculator settings')
      }
    }
    // Calculate immediately with loaded/default values
    calculate()
  })

  onCleanup(() => {
    if (debounceTimer) clearTimeout(debounceTimer)
  })

  // Debounced calculation
  let debounceTimer: number | null = null

  const scheduleUpdate = () => {
    if (debounceTimer) clearTimeout(debounceTimer)
    debounceTimer = window.setTimeout(() => {
      calculate()
    }, 400)
  }

  function handleInput(field: keyof typeof formData, value: string) {
    setFormData({ ...formData(), [field]: value })
    scheduleUpdate()
  }

  const calculate = () => {
    setLoading(true)
    const raw = formData()
    // Helper for locale-aware number parsing (supports both . and , as decimal separator)
    const n = (s: string) => parseFloat(s.replace(',', '.')) || 0
    // Save numeric values to localStorage
    const numForm: Record<string, number> = {}
    for (const key of Object.keys(raw)) {
      numForm[key] = n(raw[key as keyof typeof raw])
    }
    localStorage.setItem('rentBuyCalculatorSettings', JSON.stringify(numForm))

    try {
      const rentMonthly = n(raw.rentMonthly)
      const rentIncrease = n(raw.rentIncrease) / 100
      const investReturn = n(raw.investReturn || '7') / 100

      const homePrice = n(raw.homePrice)
      const downPayment = n(raw.downPayment)
      const loanTerm = parseInt(raw.loanTerm) || 0
      const interestRate = n(raw.interestRate) / 100
      const propertyTax = n(raw.propertyTax)
      const insurance = n(raw.insurance)
      const maintenancePct = n(raw.maintenance) / 100
      const hoa = n(raw.hoa)

      const years = parseInt(raw.horizon) || 30
      const monthlyRate = interestRate / 12
      const totalMonths = loanTerm * 12

      // Calculate monthly mortgage payment
      let monthlyPayment = 0
      if (monthlyRate > 0 && totalMonths > 0) {
        monthlyPayment =
          ((homePrice - downPayment) * (monthlyRate * Math.pow(1 + monthlyRate, totalMonths))) /
          (Math.pow(1 + monthlyRate, totalMonths) - 1)
      } else if (totalMonths > 0) {
        monthlyPayment = (homePrice - downPayment) / totalMonths
      }

      // Track cumulative values
      let cumulativeRent = 0
      let cumulativeBuyCost = 0
      let investmentBalance = downPayment
      let cumulativePrincipal = 0
      let _cumulativeInterest = 0
      let principalBalance = homePrice - downPayment

      const resultData: Result[] = []

      for (let year = 1; year <= years; year++) {
        const yearRent = rentMonthly * 12 * Math.pow(1 + rentIncrease, year - 1)

        // Calculate mortgage details for this year
        let yearPrincipal = 0
        let yearInterest = 0
        const yearTax = propertyTax
        const yearInsurance = insurance
        const yearMaintenance = homePrice * maintenancePct
        const yearHOA = hoa * 12

        // Calculate mortgage principal/interest for each month of this year
        for (let month = 1; month <= 12; month++) {
          if (principalBalance > 0) {
            const interestPayment = principalBalance * monthlyRate
            const principalPayment = Math.min(monthlyPayment - interestPayment, principalBalance)
            yearInterest += interestPayment
            yearPrincipal += principalPayment
            principalBalance -= principalPayment
          }
        }

        // Add to cumulative
        cumulativeRent += yearRent
        cumulativeBuyCost +=
          monthlyPayment * 12 + yearTax + yearInsurance + yearMaintenance + yearHOA
        cumulativePrincipal += yearPrincipal
        _cumulativeInterest += yearInterest

        // Investment growth
        investmentBalance *= 1 + investReturn

        resultData.push({
          year,
          rentCumulative: cumulativeRent,
          buyCumulative: cumulativeBuyCost,
          rentInvestmentValue: investmentBalance,
          buyEquity: cumulativePrincipal,
          rentNetCost: cumulativeRent,
          buyNetCost: cumulativeBuyCost - cumulativePrincipal,
        })
      }

      // Find break-even year
      let beYear: number | null = null
      for (let i = 0; i < resultData.length; i++) {
        const r = resultData[i]
        if (r.buyNetCost <= r.rentNetCost) {
          beYear = r.year
          break
        }
      }

      setResults(resultData)
      setBreakEvenYear(beYear)
      setShowResults(true)
    } catch (e) {
      console.error('Calculation failed:', e)
    } finally {
      setLoading(false)
    }
  }

  const getSummary = () => {
    const data = results()
    if (!data.length) return null
    const last = data[data.length - 1]
    return {
      rentCumulative: last.rentCumulative,
      rentInvestmentValue: last.rentInvestmentValue,
      rentNetCost: last.rentNetCost,
      buyCumulative: last.buyCumulative,
      buyEquity: last.buyEquity,
      buyNetCost: last.buyNetCost,
      winner: last.buyNetCost < last.rentNetCost ? 'buy' : 'rent',
      savings: Math.abs(last.buyNetCost - last.rentNetCost),
      breakEven: breakEvenYear(),
    }
  }

  const summary = createMemo(() => getSummary())

  return (
    <div class={sharedStyles.page}>
      <div class={sharedStyles.pageHeader}>
        <h1>Rent vs Buy Calculator</h1>
        <p>Compare long-term costs between renting and buying</p>
      </div>

      <div class={styles.calcContainer}>
        {/* Rent Inputs */}
        <div class={styles.calcSection}>
          <h3 class={styles.calcTitle}>Rent Scenario</h3>
          <div class={styles.formGrid}>
            <div class={styles.formGroup}>
              <label>Monthly Rent</label>
              <input
                type="text"
                inputmode="decimal"
                pattern="[0-9]*[.,]?[0-9]*"
                data-test-id="rent-monthly-input"
                value={formData().rentMonthly}
                oninput={(e) => {
                  handleInput('rentMonthly' as keyof typeof formData, e.target.value)
                }}
              />
            </div>
            <div class={styles.formGroup}>
              <label>Annual Rent Increase (%)</label>
              <input
                type="text"
                inputmode="decimal"
                pattern="[0-9]*[.,]?[0-9]*"
                data-test-id="rent-increase-input"
                value={formData().rentIncrease}
                oninput={(e) => {
                  handleInput('rentIncrease' as keyof typeof formData, e.target.value)
                }}
              />
            </div>
            <div class={styles.formGroup}>
              <label>Investment Return (%)</label>
              <input
                type="text"
                inputmode="decimal"
                pattern="[0-9]*[.,]?[0-9]*"
                data-test-id="invest-return-input"
                value={formData().investReturn}
                oninput={(e) => {
                  handleInput('investReturn' as keyof typeof formData, e.target.value)
                }}
              />
            </div>
            <div class={styles.formGroup}>
              <label>Time Horizon (years)</label>
              <input
                type="text"
                inputmode="decimal"
                pattern="[0-9]*"
                data-test-id="horizon-input"
                value={formData().horizon}
                oninput={(e) => {
                  handleInput('horizon' as keyof typeof formData, e.target.value)
                }}
              />
            </div>
          </div>
        </div>

        {/* Buy Inputs */}
        <div class={styles.calcSection}>
          <h3 class={styles.calcTitle}>Buy Scenario</h3>
          <div class={styles.formGrid}>
            <div class={styles.formGroup}>
              <label>Home Price</label>
              <input
                type="text"
                inputmode="decimal"
                pattern="[0-9]*[.,]?[0-9]*"
                data-test-id="home-price-input"
                value={formData().homePrice}
                oninput={(e) => {
                  handleInput('homePrice' as keyof typeof formData, e.target.value)
                }}
              />
            </div>
            <div class={styles.formGroup}>
              <label>Down Payment</label>
              <input
                type="text"
                inputmode="decimal"
                pattern="[0-9]*[.,]?[0-9]*"
                data-test-id="down-payment-input"
                value={formData().downPayment}
                oninput={(e) => {
                  handleInput('downPayment' as keyof typeof formData, e.target.value)
                }}
              />
            </div>
            <div class={styles.formGroup}>
              <label>Loan Term (years)</label>
              <input
                type="text"
                inputmode="decimal"
                pattern="[0-9]*[.,]?[0-9]*"
                data-test-id="loan-term-input"
                value={formData().loanTerm}
                oninput={(e) => {
                  handleInput('loanTerm' as keyof typeof formData, e.target.value)
                }}
              />
            </div>
            <div class={styles.formGroup}>
              <label>Interest Rate (%)</label>
              <input
                type="text"
                inputmode="decimal"
                pattern="[0-9]*[.,]?[0-9]*"
                data-test-id="interest-rate-input"
                value={formData().interestRate}
                oninput={(e) => {
                  handleInput('interestRate' as keyof typeof formData, e.target.value)
                }}
              />
            </div>
            <div class={styles.formGroup}>
              <label>Annual Property Tax</label>
              <input
                type="text"
                inputmode="decimal"
                pattern="[0-9]*[.,]?[0-9]*"
                data-test-id="property-tax-input"
                value={formData().propertyTax}
                oninput={(e) => {
                  handleInput('propertyTax' as keyof typeof formData, e.target.value)
                }}
              />
            </div>
            <div class={styles.formGroup}>
              <label>Annual Insurance</label>
              <input
                type="text"
                inputmode="decimal"
                pattern="[0-9]*[.,]?[0-9]*"
                data-test-id="insurance-input"
                value={formData().insurance}
                oninput={(e) => {
                  handleInput('insurance' as keyof typeof formData, e.target.value)
                }}
              />
            </div>
            <div class={styles.formGroup}>
              <label>Maintenance (%)</label>
              <input
                type="text"
                inputmode="decimal"
                pattern="[0-9]*[.,]?[0-9]*"
                data-test-id="maintenance-input"
                value={formData().maintenance}
                oninput={(e) => {
                  handleInput('maintenance' as keyof typeof formData, e.target.value)
                }}
              />
            </div>
            <div class={styles.formGroup}>
              <label>Annual HOA Fees</label>
              <input
                type="text"
                inputmode="decimal"
                pattern="[0-9]*[.,]?[0-9]*"
                data-test-id="hoa-input"
                value={formData().hoa}
                oninput={(e) => {
                  handleInput('hoa' as keyof typeof formData, e.target.value)
                }}
              />
            </div>
          </div>
        </div>
      </div>

      {loading() ? (
        <div class={styles.loading}>Calculating...</div>
      ) : showResults() && summary() ? (
        (() => {
          const s = summary()!
          return (
            <>
              {/* Summary Cards */}
              <div class={styles.summaryGrid}>
                <div class={styles.summaryCard} data-test-id="rent-scenario-card">
                  <div class={styles.summaryTitle}>Rent Scenario ({formData().horizon} years)</div>
                  <div class={styles.summaryRow} data-test-id="total-rent-paid">
                    <span>Total Rent Paid</span>
                    <span class={styles.summaryValue}>
                      {formatCurrency(s.rentCumulative, currency)}
                    </span>
                  </div>
                  <div class={styles.summaryRow}>
                    <span>Investment Value</span>
                    <span class={styles.summaryValue}>
                      {formatCurrency(s.rentInvestmentValue, currency)}
                    </span>
                  </div>
                  <div
                    class={`${styles.summaryRow} ${styles.highlight}`}
                    data-test-id="rent-net-cost"
                  >
                    <span>Net Cost</span>
                    <span class={styles.summaryValue}>
                      {formatCurrency(s.rentNetCost, currency)}
                    </span>
                  </div>
                </div>
                <div class={styles.summaryCard} data-test-id="buy-scenario-card">
                  <div class={styles.summaryTitle}>Buy Scenario ({formData().horizon} years)</div>
                  <div class={styles.summaryRow} data-test-id="total-mortgage-costs">
                    <span>Total Mortgage + Costs</span>
                    <span class={styles.summaryValue}>
                      {formatCurrency(s.buyCumulative, currency)}
                    </span>
                  </div>
                  <div class={styles.summaryRow}>
                    <span>Home Equity</span>
                    <span class={styles.summaryValue}>{formatCurrency(s.buyEquity, currency)}</span>
                  </div>
                  <div
                    class={`${styles.summaryRow} ${styles.highlight}`}
                    data-test-id="buy-net-cost"
                  >
                    <span>Net Cost</span>
                    <span class={styles.summaryValue}>
                      {formatCurrency(s.buyNetCost, currency)}
                    </span>
                  </div>
                </div>
                <div
                  class={`${styles.summaryCard} ${styles.verdict}`}
                  data-test-id="comparison-card"
                >
                  <div class={styles.summaryTitle}>Comparison</div>
                  <div class={styles.summaryRow}>
                    <span>Winner</span>
                    <span
                      class={`${styles.summaryValue} ${s.winner === 'buy' ? styles.success : styles.warning}`}
                      data-test-id="winner-value"
                    >
                      {s.winner === 'buy' ? 'Buying' : 'Renting'}
                    </span>
                  </div>
                  <div class={styles.summaryRow}>
                    <span>Savings</span>
                    <span class={styles.summaryValue} data-test-id="savings-value">
                      {formatCurrency(Math.abs(s.savings), currency)}
                    </span>
                  </div>
                  <div class={`${styles.summaryRow} highlight`}>
                    <span>Break-even</span>
                    <span class={styles.summaryValue} data-test-id="break-even-value">
                      {s.breakEven ? `Year ${s.breakEven}` : 'Not reached'}
                    </span>
                  </div>
                </div>
              </div>

              {/* Break-even message */}
              {s.breakEven && (
                <div
                  class={`${styles.breakeven} ${s.winner === 'buy' ? '' : styles.neutral}`}
                  data-test-id="break-even-message"
                >
                  <div class={styles.breakevenIcon}>
                    <svg
                      width="24"
                      height="24"
                      fill="none"
                      stroke="currentColor"
                      viewBox="0 0 24 24"
                    >
                      <path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                  </div>
                  <div class={styles.breakevenText}>
                    <strong>After {s.breakEven} years, buying becomes cheaper than renting.</strong>
                    <p>
                      At this point, your home equity exceeds the cumulative cost advantage of
                      renting plus investment returns.
                    </p>
                  </div>
                </div>
              )}

              {/* Chart */}
              <div class={styles.chartSection} data-test-id="rent-buy-chart">
                <ExportChartButton
                  chart={chartRef()}
                  filename="rent-buy-comparison"
                  variant="inline"
                />
                <Chart
                  id="rentBuyChart"
                  type="line"
                  data={{
                    labels: results().map((r) => `Year ${r.year}`),
                    datasets: [
                      {
                        label: 'Renting Net Cost',
                        data: results().map((r) => r.rentNetCost),
                        borderColor: '#f59e0b',
                        backgroundColor: 'rgba(245, 158, 11, 0.1)',
                        fill: true,
                        tension: 0.3,
                        borderWidth: 2,
                      },
                      {
                        label: 'Buying Net Cost',
                        data: results().map((r) => r.buyNetCost),
                        borderColor: '#3b82f6',
                        backgroundColor: 'rgba(59, 130, 246, 0.1)',
                        fill: true,
                        tension: 0.3,
                        borderWidth: 2,
                      },
                    ],
                  }}
                  options={{
                    responsive: true,
                    maintainAspectRatio: false,
                    scales: {
                      y: {
                        ticks: {
                          callback: (v: number | string) =>
                            formatCurrency(typeof v === 'number' ? v : Number(v), currency as any),
                          color: chartColors().text,
                        },
                        grid: {
                          color: chartColors().border,
                        },
                        title: {
                          display: true,
                          text: 'Net Cost (lower is better)',
                          color: chartColors().text,
                        },
                      },
                      x: {
                        ticks: { color: chartColors().text, maxTicksLimit: 10 },
                        grid: { color: chartColors().border },
                      },
                    },
                    plugins: {
                      legend: { position: 'top', labels: { color: chartColors().text } },
                    },
                  }}
                  height={300}
                  width="100%"
                  onReady={(chart: any) => {
                    setChartRef(chart)
                  }}
                />
              </div>
            </>
          )
        })()
      ) : (
        <div class={styles.cta}>
          <p>Enter your values above to see the comparison</p>
        </div>
      )}
    </div>
  )
}

/**
 * Retirement Component - EARS Specification
 *
 * GIVEN: A user is viewing the Retirement page
 * WHEN: The page loads
 * THEN: The header displays "Retirement" and shows retirement goals with progress
 *
 * GIVEN: A user wants to create a retirement goal
 * WHEN: They click the "Create Goal" button
 * THEN: A goal creation modal opens with fields for goal name, target amount, and dates
 *
 * GIVEN: A user has a retirement goal
 * WHEN: They view the goal card
 * THEN: The progress bar shows current amount toward the target with a percentage
 *
 * GIVEN: A user views the projection
 * WHEN: They have valid retirement goal data
 * THEN: The projection shows projected retirement income and total accumulated wealth
 *
 * GIVEN: A user wants to edit a goal
 * WHEN: They click the edit button on a goal
 * THEN: The goal details populate the edit form with existing values
 *
 * GIVEN: A user wants to delete a goal
 * WHEN: They select a goal and confirm deletion
 * THEN: The goal is removed from the list
 */

/**
 * Retirement Component
 * Tracks retirement savings, calculates projected growth, and sets retirement goals
 */
import { createSignal, For, onMount } from 'solid-js'
import Badge from '../components/Badge'
import Chart from '../components/Chart'
import ConfirmButton from '../components/ConfirmButton'
import { formatCurrency } from '../core/api'
import { apiDelete, apiGet, apiPost, apiPut, showToast } from '../core/api'
import { theme } from '../core/theme'
import styles from './RetirementPage.module.css'

interface RetirementGoal {
  id: number
  name: string
  target_amount: number
  current_amount: number
  target_date: string
  monthly_contribution: number
  expected_return_rate: number
  current_age: number
  retirement_age: number
  profile_id: number
}

interface RetirementProjection {
  current_age: number
  retirement_age: number
  annual_contribution: number
  expected_return: number
  years_to_retire: number
  projected_total: number
  projected_income: number
  monthly_income_in_retirement: number
}

interface ProjectedBalance {
  age: number
  balance: number
  cumulative: number
  annual_contribution: number
}

export default function Retirement() {
  const [goals, setGoals] = createSignal<RetirementGoal[]>([])
  const [projection, setProjection] = createSignal<RetirementProjection | null>(null)
  const [projectedBalances, setProjectedBalances] = createSignal<ProjectedBalance[]>([])
  const [loading, setLoading] = createSignal(true)
  const chartColors = () => theme.getChartColors()
  const [showAddModal, setShowAddModal] = createSignal(false)
  const [editingGoal, setEditingGoal] = createSignal<RetirementGoal | null>(null)
  const [formData, setFormData] = createSignal({
    name: '',
    target_amount: '',
    current_amount: '',
    target_date: '',
    monthly_contribution: '',
    expected_return_rate: '',
    current_age: '',
    retirement_age: '',
  })

  // Load retirement goals
  const loadGoals = async () => {
    setLoading(true)
    try {
      const data = await apiGet<{ settings: any; goals: RetirementGoal[] }>('/api/retirement-goals')
      setGoals(
        (data.goals || []).map((g: any) => ({
          id: g.id,
          name: g.name || '',
          target_amount: g.target_amount || 0,
          current_amount: g.current_amount || 0,
          target_date: g.deadline || g.target_date || '',
          monthly_contribution: g.monthly_contribution || 0,
          expected_return_rate: g.expected_return_rate || 7,
          current_age: g.current_age || 30,
          retirement_age: g.retirement_age || 65,
          profile_id: g.profile_id || 0,
        }))
      )
    } catch (err) {
      console.error('Failed to load retirement goals', err)
      showToast('Failed to load retirement goals', 'error')
    } finally {
      setLoading(false)
    }
  }

  // Load projection
  const loadProjection = async () => {
    try {
      const res = await apiGet<RetirementProjection & { current_amount: number }>(
        '/api/retirement/projection'
      )
      setProjection(res)

      // Calculate detailed projection
      if (res) {
        const balances: ProjectedBalance[] = []
        let cumulative = res.current_amount
        const age = res.current_age

        for (let y = 0; y <= res.years_to_retire; y++) {
          const year = age + y
          cumulative += res.annual_contribution * Math.pow(1 + res.expected_return / 100, y)
          balances.push({
            age: year,
            balance: cumulative,
            cumulative: cumulative,
            annual_contribution: res.annual_contribution,
          })
        }
        setProjectedBalances(balances)
      }
    } catch (err) {
      console.error('Failed to load projection', err)
      showToast('Failed to load retirement projection', 'error')
    }
  }

  // Handle form submit
  const handleSubmit = async (e: Event) => {
    e.preventDefault()
    const data = {
      name: formData().name,
      target_amount: parseFloat(formData().target_amount),
      current_amount: parseFloat(formData().current_amount),
      target_date: formData().target_date,
      monthly_contribution: parseFloat(formData().monthly_contribution),
      expected_return_rate: parseFloat(formData().expected_return_rate),
      current_age: parseInt(formData().current_age),
      retirement_age: parseInt(formData().retirement_age),
    }

    try {
      if (editingGoal()) {
        await apiPut(`/api/retirement-goals/${editingGoal()!.id}`, data)
      } else {
        await apiPost('/api/retirement-goals', data)
      }
      showToast(
        editingGoal() ? 'Goal updated successfully' : 'Goal created successfully',
        'success'
      )
      setShowAddModal(false)
      setEditingGoal(null)
      setFormData({
        name: '',
        target_amount: '',
        current_amount: '',
        target_date: '',
        monthly_contribution: '',
        expected_return_rate: '',
        current_age: '',
        retirement_age: '',
      })
      loadGoals()
      loadProjection()
    } catch (err) {
      console.error('Failed to save retirement goal', err)
      showToast('Failed to save retirement goal', 'error')
    }
  }

  // Delete goal
  const deleteGoal = async (id: number) => {
    try {
      await apiDelete(`/api/retirement-goals/${id}`)
      showToast('Goal deleted successfully', 'success')
      loadGoals()
      loadProjection()
    } catch (err) {
      console.error('Failed to delete retirement goal', err)
      showToast('Failed to delete retirement goal', 'error')
    }
  }

  // Open edit modal
  const editGoal = (goal: RetirementGoal) => {
    setEditingGoal(goal)
    setFormData({
      name: goal.name,
      target_amount: goal.target_amount.toString(),
      current_amount: goal.current_amount.toString(),
      target_date: goal.target_date.slice(0, 10),
      monthly_contribution: goal.monthly_contribution.toString(),
      expected_return_rate: goal.expected_return_rate.toString(),
      current_age: goal.current_age.toString(),
      retirement_age: goal.retirement_age.toString(),
    })
    setShowAddModal(true)
  }

  // Calculate years until retirement
  const yearsUntil = (): number => {
    if (!projection()) return 0
    return projection()!.years_to_retire
  }

  // Calculate months until retirement
  const monthsUntil = (): number => {
    return yearsUntil() * 12
  }

  // Get total contributed
  const totalContributed = (): number => {
    const years = yearsUntil()
    if (!projection()) return 0
    return years * projection()!.annual_contribution
  }

  // Get remaining to save
  const remainingToSave = (): number => {
    if (!projection()) return 0
    return (projection() as any).projected_total - (projection() as any).current_amount
  }

  // Calculate growth
  const calculateGrowth = (): number => {
    if (!projection()) return 0
    return (
      (projection() as any).projected_total -
      (projection() as any).current_amount -
      totalContributed()
    )
  }

  // Get progress percentage
  const getProgress = (goal: RetirementGoal): number => {
    if (goal.target_amount === 0) return 0
    return Math.min(100, Math.round((goal.current_amount / goal.target_amount) * 100))
  }

  // Format date
  const formatDate = (dateStr: string): string => {
    return new Date(dateStr).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    })
  }

  // Format age
  const formatAge = (age: number): string => {
    return `${age} years old`
  }

  // Format currency
  const formatAmount = (amount: number): string => {
    return formatCurrency(amount)
  }

  // Get retirement age badge status
  const getRetirementBadgeStatus = (age: number): 'default' | 'warning' | 'info' | 'success' => {
    if (age < 40) return 'default'
    if (age < 50) return 'warning'
    if (age < 60) return 'info'
    return 'success'
  }

  onMount(() => {
    loadGoals()
    loadProjection()
  })

  return (
    <div class={`page page-retirement page-enter ${styles.retirementPage}`}>
      <div class={styles.pageHeader} data-test-id="retirement-page-header">
        <div class={styles.headerTop}>
          <h1 data-test-id="retirement-header">Retirement Planning</h1>
          <button
            data-test-id="add-retirement-goal-btn"
            class={styles.btnPrimary}
            onClick={() => setShowAddModal(true)}
          >
            <svg width="16" height="16" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
            </svg>
            Add Goal
          </button>
        </div>
        <p data-test-id="retirement-subtitle" class={styles.pageSubtitle}>
          Plan your retirement and track your savings progress
        </p>
      </div>

      {/* Projected Balances Chart */}
      <div class={styles.retirementProjections} data-test-id="retirement-projections">
        <h2 class={styles.sectionTitle}>Projected Balances Over Time</h2>
        {projection() ? (
          <Chart
            id="retirement-projection-chart"
            type="line"
            data={{
              labels: projectedBalances().map((pb) => pb.age.toString()),
              datasets: [
                {
                  label: 'Projected Balance',
                  data: projectedBalances().map((pb) => pb.balance),
                  borderColor: '#22c55e',
                  backgroundColor: 'rgba(34, 197, 94, 0.1)',
                  fill: true,
                  tension: 0.4,
                  pointRadius: 4,
                  pointHoverRadius: 6,
                },
              ],
            }}
            options={{
              responsive: true,
              maintainAspectRatio: false,
              scales: {
                x: {
                  title: {
                    display: true,
                    text: 'Age',
                    color: chartColors().text,
                  },
                  ticks: {
                    stepSize: 5,
                    color: chartColors().text,
                  },
                  grid: { color: chartColors().border },
                },
                y: {
                  beginAtZero: true,
                  ticks: {
                    callback: (value: any) => formatAmount(value),
                    color: chartColors().text,
                  },
                  grid: { color: chartColors().border },
                },
              },
              plugins: {
                legend: {
                  display: true,
                  labels: {
                    usePointStyle: true,
                    padding: 15,
                    font: { size: 12 },
                    color: chartColors().text,
                  },
                },
                tooltip: {
                  mode: 'index',
                  intersect: false,
                  callbacks: {
                    label: (context: any) => {
                      const age = context.label
                      const balance = formatAmount(context.raw)
                      return `${age} years: ${balance}`
                    },
                  },
                },
              },
            }}
            height={250}
            width="100%"
          />
        ) : (
          <div class={styles.emptyState}>Loading projection...</div>
        )}
      </div>

      <div class={styles.retirementContent}>
        {/* Projection Cards */}
        <div class={styles.retirementProjection}>
          {projection() && (
            <>
              <div data-test-id="retirement-projection-row" class={styles.projectionRow}>
                <div class={`${styles.projectionCard} ${styles.primary}`}>
                  <div class={styles.cardLabel}>Projected Total</div>
                  <div class={styles.cardValue}>{formatAmount(projection()!.projected_total)}</div>
                  <div class={styles.cardSub}>At age {projection()!.retirement_age}</div>
                </div>
                <div class={styles.projectionCard}>
                  <div class={styles.cardLabel}>Years to Retire</div>
                  <div class={styles.cardValue}>{yearsUntil()} years</div>
                  <div class={styles.cardSub}>{monthsUntil()} months</div>
                </div>
                <div class={styles.projectionCard}>
                  <div class={styles.cardLabel}>Monthly Contribution</div>
                  <div class={styles.cardValue}>
                    {formatAmount(projection()!.annual_contribution / 12)}
                  </div>
                  <div class={styles.cardSub}>
                    {formatAmount(projection()!.annual_contribution)}/year
                  </div>
                </div>
                <div class={styles.projectionCard}>
                  <div class={styles.cardLabel}>Expected Return</div>
                  <div class={styles.cardValue}>{projection()!.expected_return}%</div>
                  <div class={styles.cardSub}>Annual average</div>
                </div>
              </div>
              <div data-test-id="retirement-projection-details" class={styles.projectionDetails}>
                <div class={styles.detailRow}>
                  <span class={styles.detailLabel}>Current Savings</span>
                  <span class={styles.detailValue}>
                    {formatAmount((projection() as any).current_amount)}
                  </span>
                </div>
                <div class={styles.detailRow}>
                  <span class={styles.detailLabel}>Total Contributions</span>
                  <span class={styles.detailValue}>{formatAmount(totalContributed())}</span>
                </div>
                <div class={styles.detailRow}>
                  <span class={styles.detailLabel}>Investment Growth</span>
                  <span class={`${styles.detailValue} ${styles.positive}`}>
                    {formatAmount(calculateGrowth())}
                  </span>
                </div>
                <div class={styles.detailRow}>
                  <span class={styles.detailLabel}>Remaining to Save</span>
                  <span
                    class={`${styles.detailValue} ${remainingToSave() > 0 ? styles.positive : ''}`}
                  >
                    {formatAmount(remainingToSave())}
                  </span>
                </div>
              </div>
            </>
          )}
        </div>

        {/* Goals Section */}
        <div data-test-id="retirement-goals" class={styles.retirementGoals}>
          <h2 class={styles.sectionTitle}>Retirement Goals</h2>
          {loading() ? (
            <div data-test-id="loading-state" class={styles.emptyState}>
              Loading goals...
            </div>
          ) : goals().length === 0 ? (
            <div class={styles.emptyState}>
              <p>No retirement goals yet</p>
              <p>Add your first retirement goal to start planning.</p>
              <button class={styles.btnPrimary} onClick={() => setShowAddModal(true)}>
                Add Goal
              </button>
            </div>
          ) : (
            <div data-test-id="retirement-goals-grid" class={styles.goalsGrid}>
              <For each={goals()}>
                {(goal) => {
                  const progress = getProgress(goal)
                  return (
                    <div data-test-id="retirement-goal-card" class={styles.goalCard}>
                      <div class={styles.goalHeader}>
                        <div data-test-id="retirement-goal-icon" class={styles.goalIcon}>
                          <svg
                            width="18"
                            height="18"
                            fill="none"
                            stroke="currentColor"
                            stroke-width="2"
                            viewBox="0 0 24 24"
                          >
                            <path d="M12 2C6.477 2 2 6.477 2 12s4.477 10 10 10 10-4.477 10-10S17.523 2 12 2zm0 4a6 6 0 100 12 6 6 0 000-12zm0 3a3 3 0 100 6 3 3 0 000-6z" />
                          </svg>
                        </div>
                        <div class={styles.goalInfo}>
                          <h3 data-test-id="retirement-goal-name" class={styles.goalName}>
                            {goal.name}
                          </h3>
                          <Badge status={getRetirementBadgeStatus(goal.retirement_age)}>
                            Retire at {formatAge(goal.retirement_age)}
                          </Badge>
                        </div>
                        <div class={styles.goalActions}>
                          <button
                            data-test-id="retirement-goal-edit-btn"
                            class={`${styles.btnSm} ${styles.btnGhost}`}
                            onClick={() => {
                              editGoal(goal)
                            }}
                          >
                            <svg
                              width="16"
                              height="16"
                              fill="none"
                              stroke="currentColor"
                              viewBox="0 0 24 24"
                            >
                              <path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                            </svg>
                          </button>
                          <ConfirmButton
                            class={`${styles.btnSm} ${styles.btnGhost}`}
                            onConfirm={() => deleteGoal(goal.id)}
                            label={
                              <svg
                                width="16"
                                height="16"
                                fill="none"
                                stroke="currentColor"
                                viewBox="0 0 24 24"
                              >
                                <path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                              </svg>
                            }
                          />
                        </div>
                      </div>
                      <div data-test-id="retirement-goal-balance" class={styles.goalBalance}>
                        <div class={styles.balanceLabel}>Current Amount</div>
                        <div class={styles.balanceValue}>{formatAmount(goal.current_amount)}</div>
                      </div>
                      <div class={styles.goalProgress}>
                        <div data-test-id="retirement-progress-bar" class={styles.progressBar}>
                          <div class={styles.progressFill} style={{ width: `${progress}%` }} />
                        </div>
                        <div class={styles.progressStats}>
                          <span
                            data-test-id="retirement-progress-percent"
                            class={styles.progressPercent}
                          >
                            {progress}%
                          </span>
                          <span
                            data-test-id="retirement-progress-target"
                            class={styles.progressTarget}
                          >
                            {formatAmount(goal.target_amount)} target
                          </span>
                        </div>
                      </div>
                      <div class={styles.goalDetails}>
                        <div data-test-id="retirement-detail-item" class={styles.detailItem}>
                          <span class={styles.detailLabel}>Monthly</span>
                          <span
                            data-test-id="retirement-monthly-contribution"
                            class={styles.detailValue}
                          >
                            {formatAmount(goal.monthly_contribution)}
                          </span>
                        </div>
                        <div data-test-id="retirement-detail-item" class={styles.detailItem}>
                          <span class={styles.detailLabel}>Expected Return</span>
                          <span
                            data-test-id="retirement-expected-return"
                            class={styles.detailValue}
                          >
                            {goal.expected_return_rate}%
                          </span>
                        </div>
                        <div data-test-id="retirement-detail-item" class={styles.detailItem}>
                          <span class={styles.detailLabel}>Target Date</span>
                          <span data-test-id="retirement-target-date" class={styles.detailValue}>
                            {formatDate(goal.target_date)}
                          </span>
                        </div>
                      </div>
                    </div>
                  )
                }}
              </For>
            </div>
          )}
        </div>
      </div>

      {/* Add/Edit Modal */}
      {showAddModal() && (
        <div
          class={styles.modalOverlay}
          role="dialog"
          aria-modal="true"
          onclick={(e) => {
            if (e.target === e.currentTarget) {
              setShowAddModal(false)
              setEditingGoal(null)
              setFormData({
                name: '',
                target_amount: '',
                current_amount: '',
                target_date: '',
                monthly_contribution: '',
                expected_return_rate: '',
                current_age: '',
                retirement_age: '',
              })
            }
          }}
        >
          <div
            class={styles.modal}
            onclick={(e) => {
              e.stopPropagation()
            }}
          >
            <div class={styles.modalHeader}>
              <h3 class={styles.modalTitle}>
                {editingGoal() ? 'Edit Goal' : 'Add Retirement Goal'}
              </h3>
              <button
                class={styles.modalClose}
                onClick={() => {
                  setShowAddModal(false)
                  setEditingGoal(null)
                  setFormData({
                    name: '',
                    target_amount: '',
                    current_amount: '',
                    target_date: '',
                    monthly_contribution: '',
                    expected_return_rate: '',
                    current_age: '',
                    retirement_age: '',
                  })
                }}
              >
                <svg width="24" height="24" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path d="M6 18L18 6M6 6l12 12" />
                </svg>
