/**
 * Chart Export Utilities
 * PNG and SVG export for Chart.js charts
 */
import type * as ChartJS from 'chart.js/auto'

export function exportChartAsPNG(
  chart: ChartJS.Chart,
  filename: string,
  backgroundColor?: string | null
): void {
  const canvas = chart.canvas as HTMLCanvasElement
  if (backgroundColor) {
    // Create a temporary canvas to layer background + chart
    const tempCanvas = document.createElement('canvas')
    tempCanvas.width = canvas.width
    tempCanvas.height = canvas.height
    const ctx = tempCanvas.getContext('2d')!
    ctx.fillStyle = backgroundColor
    ctx.fillRect(0, 0, tempCanvas.width, tempCanvas.height)
    ctx.drawImage(canvas, 0, 0)
    const link = document.createElement('a')
    link.download = `${filename}.png`
    link.href = tempCanvas.toDataURL('image/png')
    link.click()
  } else {
    const link = document.createElement('a')
    link.download = `${filename}.png`
    link.href = canvas.toDataURL('image/png')
    link.click()
  }
}

export function exportChartAsSVG(
  chart: ChartJS.Chart,
  filename: string,
  backgroundColor?: string | null
): void {
  try {
    const canvas = chart.canvas as HTMLCanvasElement
    const width = canvas.width
    const height = canvas.height
    const dataUrl = canvas.toDataURL('image/png')

    const svgContent = `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">
  ${backgroundColor ? `<rect width="100%" height="100%" fill="${backgroundColor}"/>` : ''}
  <image x="0" y="0" width="${width}" height="${height}" xlink:href="${dataUrl}"/>
</svg>`

    const blob = new Blob([svgContent], { type: 'image/svg+xml;charset=utf-8' })
    const url = URL.createObjectURL(blob)
    const link = document.createElement('a')
    link.download = `${filename}.svg`
    link.href = url
    link.click()
    URL.revokeObjectURL(url)
  } catch (error) {
    console.error('Failed to export SVG:', error)
  }
}

export function downloadBlob(blob: Blob, filename: string): void {
  const url = URL.createObjectURL(blob)
  const link = document.createElement('a')
  link.href = url
  link.download = filename
  link.style.display = 'none'
  document.body.appendChild(link)
  link.click()
  document.body.removeChild(link)
  URL.revokeObjectURL(url)
}

/**
 * Chart Export Settings
 * Persistent preferences for chart export (background, format)
 */

export interface ChartExportSettings {
  /** Background color for exported charts: 'transparent' | 'white' | 'dark' | 'theme' */
  background: 'transparent' | 'white' | 'dark' | 'theme'
}

const STORAGE_KEY = 'chartExportSettings'

export const defaultSettings: ChartExportSettings = {
  background: 'transparent',
}

export function loadChartExportSettings(): ChartExportSettings {
  try {
    const saved = localStorage.getItem(STORAGE_KEY)
    if (saved) {
      const parsed = JSON.parse(saved)
      return { ...defaultSettings, ...parsed }
    }
  } catch {
    // ignore
  }
  return { ...defaultSettings }
}

export function saveChartExportSettings(settings: ChartExportSettings): void {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(settings))
}

/** Resolve background setting to an actual CSS color string for canvas fill */
export function resolveBackgroundColor(setting: ChartExportSettings['background']): string | null {
  switch (setting) {
    case 'transparent':
      return null
    case 'white':
      return '#ffffff'
    case 'dark':
      return '#1a1a2e'
    case 'theme': {
      const isDark = document.documentElement.getAttribute('data-theme') === 'dark'
      return isDark ? '#1a1a2e' : '#ffffff'
    }
  }
}

/**
 * Chart Worker — renders Chart.js charts on OffscreenCanvas in a background thread.
 * Keeps the main thread responsive during PDF report generation.
 */
/* eslint-disable no-restricted-globals */
import type { ChartData } from 'chart.js'

interface ChartRequest {
  id: number
  chartType: 'doughnut' | 'bar' | 'line'
  chartData: ChartData
  width: number
  height: number
  dark: boolean
}

interface ChartResponse {
  id: number
  blob: Blob | null
  error?: string
}

self.onmessage = async (e: MessageEvent<ChartRequest>) => {
  const { id, chartType, chartData, width, height, dark } = e.data

  try {
    const canvas = new OffscreenCanvas(width, height)
    const ctx = canvas.getContext('2d')
    if (!ctx) {
      self.postMessage({ id, blob: null, error: 'No 2d context' } satisfies ChartResponse)
      return
    }

    const { default: Chart } = await import('chart.js/auto')

    const textColor = dark ? '#E5E7EB' : '#374151'
    const gridColor = dark ? 'rgba(255,255,255,0.1)' : 'rgba(0,0,0,0.1)'
    const isPie = chartType === 'doughnut'

    const chart = new Chart(ctx as any, {
      type: chartType,
      data: chartData,
      options: {
        responsive: false,
        maintainAspectRatio: false,
        animation: false,
        layout: isPie ? { padding: { left: 0, right: 0, top: 0, bottom: 0 } } : undefined,
        plugins: {
          legend: { display: false },
          tooltip: { enabled: false },
        },
        scales: isPie
          ? {}
          : {
              x: {
                grid: { color: gridColor, drawBorder: false },
                ticks: { color: textColor, font: { size: 10 } },
              },
              y: {
                grid: { color: gridColor, drawBorder: false },
                ticks: {
                  color: textColor,
                  font: { size: 10 },
                  callback: (v: string | number) => v as number,
                },
              },
            },
      } as any,
    })

    const blob = await canvas.convertToBlob({ type: 'image/png' })
    chart.destroy()
    self.postMessage({ id, blob } satisfies ChartResponse)
  } catch (err) {
    self.postMessage({
      id,
      blob: null,
      error: err instanceof Error ? err.message : String(err),
    } satisfies ChartResponse)
  }
}

